window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NV"] = {"code":"NV","name":"Nevada","agency":"Nevada DMV","agencyShort":"DMV","handbook":"https://dmv.nv.gov/pdfforms/dlbookcomm.pdf","links":{},"en":[{"q":"What is the maximum height, including any load, that a vehicle may be operated at on a Nevada highway?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"answer":2,"explanation":"Nevada law sets the maximum vehicle height, including load, at 14 feet measured from the surface on which the vehicle stands (NRS 484D.605).","handbook":"","hbref":""},{"q":"What is the standard maximum legal width of a vehicle, combination of vehicles, or load on a Nevada highway?","options":["96 inches","98 inches","102 inches","108 inches"],"answer":2,"explanation":"The legal maximum width of any vehicle, combination of vehicles, special mobile equipment, or load is 102 inches (8 feet 6 inches) in Nevada (NRS 484D.685).","handbook":"","hbref":""},{"q":"In Nevada, what is the maximum allowable weight on any single axle of a vehicle operated on a public highway?","options":["18,000 pounds","20,000 pounds","22,000 pounds","34,000 pounds"],"answer":1,"explanation":"Nevada limits the weight on any single axle to 20,000 pounds (NRS 484D.635).","handbook":"","hbref":""},{"q":"What is the maximum allowable weight on any tandem axle of a vehicle on a Nevada public highway?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Nevada limits the weight on any tandem axle to 34,000 pounds (NRS 484D.635).","handbook":"","hbref":""},{"q":"On Nevada's portion of the Interstate System and other federal-aid highways, what is the maximum gross vehicle weight allowed without a special permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"answer":1,"explanation":"Nevada applies the federal maximum of 80,000 pounds gross weight on the Interstate and federal-aid systems, because reducing it would jeopardize federal highway funds (NRS 484D.660; 23 U.S.C. 127).","handbook":"","hbref":""},{"q":"What is the maximum length of a combination of vehicles in Nevada before a special permit is required?","options":["65 feet","70 feet","75 feet","80 feet"],"answer":1,"explanation":"No combination of vehicles coupled together, including attachments, may exceed 70 feet in Nevada without a special permit from the Department of Transportation (NRS 484D.615).","handbook":"","hbref":""},{"q":"What is the maximum length of a single motortruck (straight truck) on a Nevada highway?","options":["35 feet","40 feet","45 feet","53 feet"],"answer":1,"explanation":"A single motortruck may not exceed 40 feet in length in Nevada (NRS 484D.615).","handbook":"","hbref":""},{"q":"Which Nevada agency issues oversize and overweight (over-dimensional) vehicle permits?","options":["The Nevada Department of Motor Vehicles","The Nevada Department of Transportation","The Nevada Highway Patrol","The county sheriff of each county"],"answer":1,"explanation":"The Nevada Department of Transportation (NDOT) issues over-dimensional/overweight permits, including through its online Overdimensional Permitting System (NRS 484D.625 and 484D.685; NDOT).","handbook":"","hbref":""},{"q":"In a tractor-semitrailer combination on a Nevada highway, what is the maximum length permitted for the semitrailer without a special permit?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"A truck-tractor with a single semitrailer is allowed when the semitrailer does not exceed 53 feet in length (NRS 484D.615).","handbook":"","hbref":""},{"q":"For a truck-tractor pulling two trailing units (twin trailers) in Nevada, what is the maximum length of each trailer without a special permit?","options":["26 feet","28 feet 6 inches","30 feet","33 feet"],"answer":1,"explanation":"A truck-tractor with a semitrailer and trailer is allowed when each of the two trailing units does not exceed 28.5 feet in length (NRS 484D.615).","handbook":"","hbref":""},{"q":"A vehicle is equipped with pneumatic tires. In Nevada, what is the maximum overall width measured from the outside of one outer tire to the outside of the opposite outer tire?","options":["102 inches","104 inches","108 inches","120 inches"],"answer":2,"explanation":"For vehicles on pneumatic tires, the width measured tire-to-tire may reach 108 inches, but the body or load itself still may not exceed 102 inches (NRS 484D.685).","handbook":"","hbref":""},{"q":"Under Nevada law, what is the maximum weight per inch of tire width allowed on a steering axle?","options":["450 pounds per inch","500 pounds per inch","550 pounds per inch","600 pounds per inch"],"answer":3,"explanation":"Nevada limits steering-axle loading to 600 pounds per inch of tire width (and 500 pounds per inch for all other axles) (NRS 484D.635).","handbook":"","hbref":""},{"q":"Under Nevada law, what is the maximum weight per inch of tire width allowed on axles other than the steering axle?","options":["400 pounds per inch","500 pounds per inch","600 pounds per inch","650 pounds per inch"],"answer":1,"explanation":"For all axles other than the steering axle, Nevada limits loading to 500 pounds per inch of tire width (600 pounds per inch is allowed only on the steering axle) (NRS 484D.635).","handbook":"","hbref":""},{"q":"Nevada applies the federal bridge formula to determine the maximum weight on a group of consecutive axles. Two consecutive sets of tandem axles may each carry 34,000 pounds if the distance between the first and last axle of the group is at least how many feet?","options":["30 feet","33 feet","36 feet","40 feet"],"answer":2,"explanation":"Under the federal bridge formula as applied in Nevada, two consecutive sets of tandem axles may each carry 34,000 pounds if the overall distance between the first and last axle is 36 feet or more (NRS 484D.660; 23 U.S.C. 127, Bridge Formula).","handbook":"","hbref":""},{"q":"A carrier wants to move a load 110 inches wide on a Nevada highway. What is required?","options":["Nothing, because it is within the legal width","An oversize permit from the Nevada Department of Transportation","Only amber warning lights on each corner","A waiver from the Nevada Highway Patrol"],"answer":1,"explanation":"A load wider than the 102-inch legal limit is oversize and requires an over-dimensional permit from NDOT before it may be moved (NRS 484D.685; NDOT).","handbook":"","hbref":""},{"q":"What is the purpose of the federal bridge formula that Nevada applies on the Interstate System?","options":["It sets the maximum speed for heavy trucks","It limits weight on a group of axles based on the number of axles and the distance between them","It sets the registration fee for commercial vehicles","It determines the maximum trailer length"],"answer":1,"explanation":"The federal bridge formula caps the gross weight that any group of two or more consecutive axles may carry, based on the number of axles and the spacing between the outer axles of the group, to protect bridges (NRS 484D.660; 23 U.S.C. 127, Bridge Formula).","handbook":"","hbref":""},{"q":"A vehicle hauling loosely piled (unbaled) agricultural products such as hay or straw in bulk is given a width variance in Nevada. What is the maximum width allowed for that load and its retaining racks?","options":["102 inches","108 inches","114 inches","120 inches"],"answer":3,"explanation":"Nevada allows a load of loosely piled agricultural products (not crated, baled, boxed, or sacked) plus any retaining racks to be up to 120 inches wide, a variance from the 102-inch standard (NRS 484D.705).","handbook":"","hbref":""},{"q":"Nevada permits a load of baled hay to exceed the normal 14-foot height limit. What is the maximum height allowed for a load of baled hay?","options":["14 feet 6 inches","15 feet","16 feet","17 feet"],"answer":1,"explanation":"While the general height limit is 14 feet, Nevada allows a load of baled hay to be carried up to 15 feet in height (NRS 484D.605).","handbook":"","hbref":""},{"q":"When NDOT determines that vehicles operating at maximum legal weight are likely to cause substantial stress to a particular highway, bridge, or street, what may NDOT or the local governing body do?","options":["Close the road permanently to all commercial traffic","Reduce the permitted weight limits on that highway, road, or street","Require all trucks to add a third trailer","Increase the statewide single-axle limit to compensate"],"answer":1,"explanation":"NDOT and local governing bodies may reduce weight limits on any highway, road, or street where vehicles at maximum permitted weight are likely to cause substantial structural stress (NRS 484D.660).","handbook":"","hbref":""},{"q":"A motor carrier needs an annual overweight permit for routine hauls in Nevada. According to NDOT guidance, how far in advance is the carrier advised to apply through the over-dimensional permitting system?","options":["At least 24 hours in advance","At least 7 days in advance","At least 30 days in advance","At least 90 days in advance"],"answer":2,"explanation":"NDOT advises permittees to plan at least 30 days in advance of a desired movement or before an existing annual permit lapses; applications are submitted through the NDOT Overdimensional Permitting System (NDOT; NRS 484D.625).","handbook":"","hbref":""},{"q":"In Nevada, which class of commercial driver license (CDL) is required to operate a combination of vehicles with a gross combination weight rating over 26,000 lbs when the towed unit has a GVWR over 10,000 lbs?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Nevada requires a Class A CDL for combination vehicles over 26,000 lbs where the trailer/towed unit exceeds 10,000 lbs GVWR. Source: Nevada DMV CDL-051 'Commercial Driver License Information' and dmv.nv.gov/cdlcertify.htm (License Classes).","handbook":"","hbref":""},{"q":"Which Nevada CDL class covers any single vehicle with a GVWR of 26,001 lbs or more, such as a large bus or straight truck, towing a unit not over 10,000 lbs?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"A Nevada Class B CDL covers single vehicles of 26,001 lbs or more (buses, large trucks) towing a unit under 10,001 lbs. Source: Nevada DMV cdlcertify.htm and CDL-051.","handbook":"","hbref":""},{"q":"Under Nevada rules, a vehicle that does not meet Class A or B size limits but is designed to carry 16 or more passengers (including the driver) or that carries placarded hazardous materials requires which CDL class?","options":["Class A","Class B","Class C","Class P"],"answer":2,"explanation":"Nevada's Class C CDL is for vehicles under the A/B weight limits that transport 16+ passengers (including the driver) or require a hazardous-materials placard. Source: Nevada DMV cdlcertify.htm and CDL-051.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a Nevada CDL for operating a commercial motor vehicle in interstate commerce?","options":["18 years","19 years","21 years","25 years"],"answer":2,"explanation":"Nevada requires applicants to be at least 21 to operate a commercial motor vehicle in interstate commerce. Source: Nevada DMV CDL-051 'Minimum Age'.","handbook":"","hbref":""},{"q":"In Nevada, an applicant between 18 and 20 years of age may be granted a CDL only for what type of operation?","options":["Interstate commerce only","Intrastate commerce only","Federal government routes only","Passenger transport only"],"answer":1,"explanation":"Nevada allows 18-to-20-year-olds a CDL for intrastate commerce only; they cannot transport passengers for hire or haul placarded hazardous materials. Source: Nevada DMV CDL-051 'Minimum Age'.","handbook":"","hbref":""},{"q":"What is the minimum age in Nevada to receive the endorsement required to drive an over-length combination vehicle (70 feet)?","options":["21 years","23 years","25 years","26 years"],"answer":2,"explanation":"Nevada requires drivers to be at least 25 to drive an over-length combination vehicle of 70 feet. Source: Nevada DMV CDL-051 'Minimum Age'; see also NRS 484D.615 (length restrictions).","handbook":"","hbref":""},{"q":"How long is a Nevada Commercial Learner Permit (CLP) valid from its date of issuance?","options":["60 days","90 days","180 days","1 year"],"answer":2,"explanation":"A Nevada CLP is valid for 180 days from issuance (renewal may require retesting). Source: Nevada DMV dmv.nv.gov/clp.htm and CDL-051 'CLP Conditions'.","handbook":"","hbref":""},{"q":"Under Nevada and federal rules, how long must a Commercial Learner Permit be held before the holder may take the CDL skills test?","options":["At least 7 days","At least 14 days","At least 21 days","At least 30 days"],"answer":1,"explanation":"A Nevada CLP must be held at least 14 days prior to skills testing, matching the federal requirement. Source: Nevada DMV clp.htm and CDL-051 'CLP Conditions'.","handbook":"","hbref":""},{"q":"Before issuing a CLP or CDL, how many forms of proof of Nevada residency does the Nevada DMV require an applicant to present?","options":["One form","Two forms","Three forms","No proof required"],"answer":1,"explanation":"Nevada requires two forms of residency proof showing the applicant's name and Nevada residential address. Source: Nevada DMV CDL-051 'Proof of residency'.","handbook":"","hbref":""},{"q":"Which document is acceptable to the Nevada DMV as proof of an applicant's Social Security number for a CDL?","options":["A voter registration card","A Social Security card, W-2, or payroll stub showing the entire number","A Nevada vehicle registration","A signed personal affidavit"],"answer":1,"explanation":"Nevada accepts a Social Security card, W-2, 1099, or payroll stub listing the entire SSN as proof of the Social Security number. Source: Nevada DMV CDL-051 'Proof of Your Social Security Number'.","handbook":"","hbref":""},{"q":"For a U.S.-born CDL applicant, which document does the Nevada DMV accept as additional proof of identity?","options":["A certified birth certificate or U.S. passport","A high school diploma","A library card","A credit card statement"],"answer":0,"explanation":"Nevada accepts a certified birth certificate (or abstract) or a U.S. passport as additional proof of identity for U.S.-born applicants; documents must be originals. Source: Nevada DMV CDL-051 'Additional Proof of Identity'.","handbook":"","hbref":""},{"q":"A CDL applicant born outside the United States must present which of the following to the Nevada DMV to establish lawful presence?","options":["A foreign driver license","A valid unexpired foreign passport with I-94 stamp, Permanent Resident card, or Certificate of Naturalization","A consular business card","A student ID from any country"],"answer":1,"explanation":"Nevada requires foreign-born applicants to show a valid unexpired foreign passport (with I-94 stamp), a Permanent Resident card, or a Certificate of Naturalization. Source: Nevada DMV CDL-051 'Additional Proof of Identity'.","handbook":"","hbref":""},{"q":"Which Nevada CDL endorsement is required to transport hazardous materials in amounts requiring placards?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"answer":2,"explanation":"The H (Hazardous Materials) endorsement is required to haul placarded hazmat in Nevada. Source: Nevada DMV CDL-051 'Endorsements' and dmv.nv.gov/cdl.htm.","handbook":"","hbref":""},{"q":"Besides holding a CDL and valid identification, what must a Nevada applicant complete before the HazMat (H) endorsement can be issued?","options":["A defensive driving course","A fingerprint-based background check","A second road skills test","A 70-foot length endorsement"],"answer":1,"explanation":"Nevada requires the applicant to pass a fingerprint-based (TSA) background check; the Hazmat knowledge test may not be taken until the background check is completed. Source: Nevada DMV CDL-051 'Hazmat Endorsement'.","handbook":"","hbref":""},{"q":"Which Nevada CDL endorsement is required to operate a tank vehicle that hauls liquid or gaseous materials in a permanently mounted bulk tank?","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"answer":1,"explanation":"The N (Tank Vehicle) endorsement is required to operate tank vehicles in Nevada. Source: Nevada DMV CDL-051 'Endorsements'.","handbook":"","hbref":""},{"q":"On a Nevada commercial license, what does the X endorsement designate?","options":["Doubles/triples authority","A combined HazMat and Tanker (Hazmat Tanker) endorsement","A school bus endorsement","An over-length vehicle endorsement"],"answer":1,"explanation":"Nevada lists X as the Hazmat Tanker endorsement (combining the H and N requirements). Source: Nevada DMV CDL-051 'Endorsements'.","handbook":"","hbref":""},{"q":"Which endorsement does Nevada require for a driver to pull double or triple trailers?","options":["P endorsement","S endorsement","T endorsement","N endorsement"],"answer":2,"explanation":"The T (Double/Triple Trailers) endorsement is required to pull doubles or triples in Nevada. Source: Nevada DMV CDL-051 'Endorsements'.","handbook":"","hbref":""},{"q":"A driver who wants to drive a public school bus in Nevada must hold which combination of endorsements?","options":["P and S endorsements","N and T endorsements","H and X endorsements","S endorsement only"],"answer":0,"explanation":"A Nevada school bus driver must hold both the Passenger (P) and School Bus (S) endorsements, each requiring additional knowledge and skills testing. Source: Nevada DMV CDL materials; Nevada School Bus Driver Training Manual (ELDT for P and S).","handbook":"","hbref":""},{"q":"Where must an entry-level Nevada commercial driver complete the required Entry-Level Driver Training (ELDT)?","options":["Any licensed Nevada business","A provider listed on the federal Training Provider Registry","The county sheriff's office","An online course of the driver's choice"],"answer":1,"explanation":"Nevada requires entry-level commercial drivers to complete ELDT from a provider listed on the federal FMCSA Training Provider Registry. Source: Nevada DMV CDL-051 'Entry Level Driver Training (ELDT)'; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"When self-certifying with the Nevada DMV, which category applies to a CDL holder who drives only within Nevada and is subject to state (not federal Part 391) physical qualification standards?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Interstate-Excepted"],"answer":2,"explanation":"Non-Excepted Intrastate applies to drivers operating only within Nevada who are subject to state driver qualification standards. Source: Nevada DMV dmv.nv.gov/cdlcertify.htm (self-certification categories); 49 CFR 383.71.","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle (CMV) in Nevada, a CDL driver is considered legally intoxicated and commits a major offense at what blood alcohol concentration (BAC)?","options":["0.04 percent or higher","0.08 percent or higher","0.02 percent or higher","0.10 percent or higher"],"answer":0,"explanation":"Nevada applies the federal CMV standard: it is a disqualifying major offense to operate a CMV with a BAC of 0.04 percent or more (a non-CDL driver's general limit of 0.08 percent still applies in any vehicle). Source: Nevada Commercial Driver Handbook (disqualifications) and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Nevada's implied-consent law, what happens if a CDL driver refuses to submit to a chemical test of blood, breath, or urine when lawfully requested?","options":["The driver's license is automatically revoked, and the refusal is itself a disqualifying major offense","Nothing happens unless the driver is later convicted of DUI in court","Only a written warning is issued for the first refusal","The driver pays a $250 civil penalty with no license action"],"answer":0,"explanation":"By driving in Nevada a CDL holder gives implied consent to testing; refusal triggers an automatic license revocation by the DMV and counts as a major offense that disqualifies the CDL even if the driver is later acquitted. Source: Nevada implied-consent statutes (NRS Chapter 484C) and Nevada Commercial Driver Handbook.","handbook":"","hbref":""},{"q":"For a first major offense (such as DUI or test refusal) committed while NOT hauling placarded hazardous materials, how long is a Nevada CDL disqualified?","options":["1 year","60 days","3 years","6 months"],"answer":0,"explanation":"A first major offense disqualifies the CDL for a minimum of 1 year. Source: Nevada Commercial Driver Handbook (disqualifications) and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a first major offense (such as DUI) is committed while the driver is operating a CMV carrying placarded hazardous materials, the Nevada CDL disqualification increases to:","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"A first major offense committed while transporting placarded hazardous materials carries a 3-year disqualification rather than the standard 1 year. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"What is the Nevada CDL disqualification period for a SECOND major offense (for example, a second DUI conviction in a CMV)?","options":["Lifetime disqualification","10 years","3 years","5 years"],"answer":0,"explanation":"A second major offense results in a lifetime CDL disqualification (a limited reinstatement after at least 10 years may be available only under specific conditions). Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CDL driver in Nevada is convicted of TWO serious traffic violations in separate incidents within a 3-year period. The CDL is disqualified for:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Two serious traffic violations within 3 years (in separate incidents) disqualify the CDL for 60 days. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A CDL driver in Nevada is convicted of THREE serious traffic violations in separate incidents within a 3-year period. The CDL is disqualified for:","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"Three serious traffic violations within 3 years (in separate incidents) disqualify the CDL for 120 days, served in addition to any prior 60-day disqualification. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which of the following counts as a SERIOUS traffic violation for CDL disqualification purposes in Nevada?","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A non-moving parking violation","Driving with an expired vehicle registration"],"answer":0,"explanation":"Excessive speeding, defined as 15 mph or more above the posted limit, is a listed serious traffic violation. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Which set of offenses are all classified as SERIOUS traffic violations under Nevada CDL rules?","options":["Reckless driving, following too closely, and improper or erratic lane changes","DUI, leaving the scene of an accident, and using a CMV in a felony","Refusing a chemical test, a second DUI, and a fatal hit-and-run","Overweight permit violation, expired medical card, and unpaid tolls"],"answer":0,"explanation":"Reckless driving, following too closely, and improper or erratic lane changes are all serious traffic violations. The other listed offenses are major offenses or are not part of the serious-violation list. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Driving a CMV in Nevada without the proper class of CDL or commercial learner's permit, or without it in your possession, is classified as:","options":["A serious traffic violation","A major offense","An out-of-service order violation","A non-disqualifying paperwork error"],"answer":0,"explanation":"Operating a CMV without the proper CDL/CLP, or without it in possession, is a serious traffic violation that counts toward the 60-day/120-day disqualifications. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"For a FIRST conviction of a railroad-highway grade crossing violation in a CMV, the Nevada CDL is disqualified for at least:","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation disqualifies the CDL for not less than 60 days. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A SECOND railroad-highway grade crossing violation within a 3-year period disqualifies a Nevada CDL for at least:","options":["120 days","60 days","1 year","90 days"],"answer":0,"explanation":"A second grade-crossing violation within any 3-year period disqualifies the CDL for not less than 120 days. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"A THIRD railroad-highway grade crossing violation within a 3-year period disqualifies a Nevada CDL for at least:","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third grade-crossing violation within any 3-year period disqualifies the CDL for not less than 1 year. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"If a driver violates an out-of-service order while transporting placarded hazardous materials or operating a vehicle designed for 16 or more passengers, the FIRST-offense disqualification is:","options":["No less than 180 days and no more than 2 years","No less than 90 days and no more than 1 year","No less than 1 year and no more than 5 years","Exactly 120 days"],"answer":0,"explanation":"A first OOS-order violation while hauling placarded hazmat or carrying 16+ passengers disqualifies the CDL for not less than 180 days and not more than 2 years. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In addition to being disqualified, a driver convicted of violating an out-of-service order in Nevada faces a federal civil penalty of at least:","options":["$1,000","$250","$500","$2,750"],"answer":0,"explanation":"A driver who violates an OOS order is subject to a civil penalty of not less than $1,000 (and up to $2,500), separate from the disqualification. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Nevada law (NRS 484B.165), using a handheld cellphone or texting while driving carries what civil penalty for a FIRST offense?","options":["$50","$100","$250","$500"],"answer":0,"explanation":"Nevada's handheld/texting law (NRS 484B.165) sets a $50 civil penalty for a first offense, $100 for a second, and $250 for a third within 7 years; a first offense is not treated as a moving violation. Source: NRS 484B.165.","handbook":"","hbref":""},{"q":"For a CDL holder, how does using a handheld phone or texting while operating a CMV affect the commercial license under Nevada/federal rules?","options":["It is a serious traffic violation that can lead to a 60- or 120-day disqualification if repeated","It is a major offense causing a 1-year disqualification on the first offense","It only results in a $50 fine with no effect on the CDL","It is an out-of-service violation carrying a 90-day disqualification"],"answer":0,"explanation":"Texting or using a handheld mobile phone while driving a CMV is a serious traffic violation; two within 3 years disqualify the CDL for 60 days and three within 3 years for 120 days. Source: Nevada Commercial Driver Handbook and 49 CFR 383.51 / 392.80-392.82.","handbook":"","hbref":""},{"q":"Nevada caps the fine for a speeding violation under the basic-rule statute (NRS 484B.600) at what amount per mile per hour over the limit?","options":["$20 for each mph over the limit","$25 for each mph over the limit","$10 for each mph over the limit","$50 for each mph over the limit"],"answer":0,"explanation":"Nevada caps the speeding fine at $20 for each mile per hour the driver travels above the posted limit; for a CDL holder, speeding 15+ mph over remains a serious traffic violation regardless of the fine amount. Source: NRS 484B.600 and Nevada Commercial Driver Handbook.","handbook":"","hbref":""},{"q":"Under Nevada's Move Over law, when you approach a stopped emergency vehicle, tow truck, or NDOT vehicle displaying flashing lights on a highway, what must you do?","options":["Slow to a reasonable speed, proceed with caution, and if possible move into a lane not adjacent to the stopped vehicle","Come to a complete stop until the emergency vehicle's lights are turned off","Maintain the posted speed limit but sound your horn while passing","Move onto the right shoulder and wait for an officer to wave you through"],"answer":0,"explanation":"Nevada's Move Over law (NRS 484B.607) requires drivers to decrease speed to a reasonable and proper rate, proceed with caution, be prepared to stop, and if possible move into a lane not immediately adjacent to the stopped vehicle. It applies to authorized emergency vehicles and to vehicles displaying flashing amber or non-flashing blue lights, including NDOT vehicles. Source: NRS 484B.607.","handbook":"","hbref":""},{"q":"On a Nevada divided highway with a physical barrier or dividing section, a school bus stopped in the OTHER roadway is displaying flashing red lights to load children. What must a driver in your direction do?","options":["Stop until the red lights stop flashing, the same as on an undivided road","Need not stop, because the bus is positioned in the other roadway of a divided highway","Slow to 15 mph and pass with caution in the far lane","Stop only if children are visibly crossing the median"],"answer":1,"explanation":"Under NRS 484B.353, the driver of a vehicle upon a divided highway need not stop upon meeting or passing a school bus positioned in the other roadway. Nevada defines a divided highway as one separated by a physical barrier or dividing section, so this exception requires a true divided highway, not merely a center line or turn lane. Source: NRS 484B.353.","handbook":"","hbref":""},{"q":"When a Nevada school bus carrying children, a bus carrying passengers, or a placarded hazardous materials vehicle approaches a railroad grade crossing required to stop, within what distance of the nearest rail must it stop?","options":["Not less than 5 feet nor more than 25 feet from the nearest rail","Not less than 25 feet nor more than 75 feet from the nearest rail","Not less than 15 feet nor more than 50 feet from the nearest rail","Not less than 50 feet nor more than 100 feet from the nearest rail"],"answer":2,"explanation":"NRS 484B.560 requires a bus carrying passengers, a school bus carrying children, or a vehicle carrying placarded hazardous materials to stop within 50 feet but not less than 15 feet from the nearest rail before crossing at grade. Source: NRS 484B.560.","handbook":"","hbref":""},{"q":"In Nevada, a commercial motor vehicle that is NOT required to fully stop at a railroad grade crossing still has a specific duty before crossing. What is it?","options":["Maintain highway speed to clear the crossing as quickly as possible","Stop, set the parking brake, and roll down the window to listen","Sound the horn twice and proceed without slowing","Decrease speed and confirm the tracks are clear of any approaching train"],"answer":3,"explanation":"NRS 484B.560 provides that a commercial motor vehicle (as defined in 49 C.F.R. 383.5) that is not otherwise required to stop must, before crossing at grade, decrease its speed and confirm the tracks are clear of any approaching train or on-track equipment. Source: NRS 484B.560.","handbook":"","hbref":""},{"q":"What is the maximum speed limit that may be posted on any Nevada highway?","options":["65 miles per hour","80 miles per hour","75 miles per hour","85 miles per hour"],"answer":1,"explanation":"Under NRS 484B.613, NDOT may establish speed limits not exceeding 80 miles per hour on state highways, and 80 mph is the highest posted limit found in Nevada (on designated rural Interstate segments). Source: NRS 484B.613; NRS 484B.617.","handbook":"","hbref":""},{"q":"Does Nevada law set a single statewide maximum speed limit for trucks that is lower than the limit for passenger cars?","options":["Yes, trucks are limited to 55 mph everywhere in the state","Yes, trucks are limited to 60 mph on all interstates","No single statewide lower truck limit exists; NDOT may set a lower limit for trucks where it is posted","Yes, trucks must always travel exactly 10 mph below the posted car limit"],"answer":2,"explanation":"Unlike some states, Nevada does not impose a blanket statewide lower truck speed limit. NRS 484B.613 authorizes NDOT to establish a lower speed limit for trucks, oversized vehicles, and buses where studies warrant it, posted by sign; otherwise trucks follow the posted limit. Source: NRS 484B.613.","handbook":"","hbref":""},{"q":"On a Nevada controlled-access highway, when is a driver required to move out of the extreme left lane?","options":["Only when a sign specifically prohibits trucks from the left lane","Whenever any vehicle is within 500 feet behind, regardless of speed","Only during nighttime hours of darkness","When traveling slower than the posted speed limit and being overtaken by a faster vehicle from behind"],"answer":3,"explanation":"NRS 484B.208 requires a driver in the extreme left lane of a controlled-access highway to move out of that lane when traveling below the posted speed limit and being overtaken by a faster vehicle. Exceptions include passing, preparing to turn left, road construction, HOV-lane use, and travel within a city or town. Source: NRS 484B.208.","handbook":"","hbref":""},{"q":"After stopping a commercial vehicle on the shoulder of a two-lane, two-way Nevada highway, within how many minutes must you place your emergency warning devices?","options":["Within 10 minutes","Within 5 minutes","Within 15 minutes","Within 30 minutes"],"answer":0,"explanation":"Federal rule 49 C.F.R. 392.22, which Nevada enforces for CMVs, requires reflective triangles (or other approved devices) to be placed within 10 minutes of stopping on the traveled portion or shoulder of a highway. Source: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook.","handbook":"","hbref":""},{"q":"On a two-lane, two-way Nevada road, where do you place your three emergency warning triangles for a stopped CMV (not near a hill or curve)?","options":["10 feet, 50 feet, and 100 feet, all behind the vehicle","25 feet, 75 feet, and 150 feet behind the vehicle","10 feet behind the vehicle, 100 feet behind, and 100 feet ahead of the vehicle","50 feet ahead, 50 feet behind, and one on the roof of the vehicle"],"answer":2,"explanation":"Per 49 C.F.R. 392.22, on a two-lane, two-way road you place one triangle about 10 feet from the vehicle toward approaching traffic, one about 100 feet to the rear, and one about 100 feet to the front, so traffic is warned from both directions. Source: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook.","handbook":"","hbref":""},{"q":"What is the maximum legal width of a commercial vehicle or its load on a Nevada highway before an oversize permit is required?","options":["96 inches (8 feet)","114 inches (9 feet 6 inches)","120 inches (10 feet)","102 inches (8 feet 6 inches)"],"answer":3,"explanation":"NRS 484D.685 sets the maximum legal width of a vehicle, combination, or load at 102 inches (8 feet 6 inches), excluding certain safety devices. Anything wider requires an oversize permit. Source: NRS 484D.685.","handbook":"","hbref":""},{"q":"What is the maximum legal height, including load, for a vehicle on a Nevada highway?","options":["14 feet","13 feet 6 inches","15 feet","16 feet"],"answer":0,"explanation":"NRS 484D.605 prohibits operating a vehicle on a Nevada highway if its height, including any load, exceeds 14 feet. (A narrow exception allows baled hay up to 15 feet.) Source: NRS 484D.605.","handbook":"","hbref":""},{"q":"On a Nevada divided highway or one-way street, where is the FARTHEST emergency warning triangle placed behind a stopped CMV?","options":["About 100 feet toward approaching traffic","About 200 feet toward approaching traffic","About 50 feet toward approaching traffic","About 500 feet toward approaching traffic"],"answer":1,"explanation":"Under 49 C.F.R. 392.22, on a one-way or divided highway the triangles go at about 10, 100, and 200 feet toward the approaching traffic behind the vehicle. Source: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook.","handbook":"","hbref":""},{"q":"Which vehicle is required by Nevada law to STOP at every railroad grade crossing (absent an exception)?","options":["An empty flatbed with no placards","A delivery van under 10,000 pounds","A passenger car towing a small trailer","A school bus carrying children"],"answer":3,"explanation":"NRS 484B.560 requires buses carrying passengers, school buses carrying children, and vehicles carrying placarded hazardous materials to stop at all railroad grade crossings. A non-placarded empty flatbed, light van, or car is not in the mandatory-stop category. Source: NRS 484B.560.","handbook":"","hbref":""},{"q":"When a Nevada bus or placarded vehicle is stopped at a railroad crossing and prepares to cross, what gear rule applies?","options":["Cross in a gear that requires no shifting while on the crossing","Downshift to the lowest gear in the middle of the crossing","Shift to neutral and coast across the tracks","Use the highest gear available to clear the tracks fastest"],"answer":0,"explanation":"NRS 484B.560 directs that after stopping, the driver must cross only in a gear that will not require changing gears while traversing the crossing, and must not shift gears on the tracks. Source: NRS 484B.560.","handbook":"","hbref":""},{"q":"Which situation is an EXCEPTION that relieves a Nevada bus or placarded vehicle from the mandatory railroad-crossing stop?","options":["The driver is running behind schedule","A police officer or flagman is directing traffic at the crossing","The crossing has automatic gates that are up","Visibility down the track exceeds 400 feet"],"answer":1,"explanation":"NRS 484B.560 lists exceptions including crossings controlled by a police officer or flagman, abandoned or exempt-marked tracks, and certain industrial switching in a business district. A clear view or being late is not an exception. Source: NRS 484B.560.","handbook":"","hbref":""},{"q":"What is the maximum legal gross vehicle weight on a Nevada highway before an overweight permit is required?","options":["73,280 pounds","90,000 pounds","80,000 pounds","100,000 pounds"],"answer":2,"explanation":"Nevada follows the federal limit: maximum gross weight is 80,000 pounds, with 20,000 pounds on a single axle and 34,000 pounds on a tandem axle, subject to the bridge formula. Heavier loads need an NDOT overweight permit. Source: NRS Chapter 484D (size/weight); NDOT Over Dimensional permits.","handbook":"","hbref":""},{"q":"A driver violates Nevada's Move Over law for the first time on a normal (non-work-zone) highway. How is the offense generally classified?","options":["A misdemeanor carrying a fine (about $395) and demerit points","A non-moving infraction with no points and no fine","A felony requiring mandatory license revocation","A warning only, with no penalty for a first offense"],"answer":0,"explanation":"A violation of NRS 484B.607 is a misdemeanor; a first offense typically carries a fine in the range of about $395 (and up to roughly $790 in a work zone) plus demerit points. Source: NRS 484B.607.","handbook":"","hbref":""},{"q":"For a truck-tractor drawing a single semitrailer in Nevada, what is the maximum legal length of the semitrailer (no special permit)?","options":["48 feet","57 feet","60 feet","53 feet"],"answer":3,"explanation":"NRS 484D.615 allows a truck-tractor and semitrailer combination in which the semitrailer does not exceed 53 feet, as an exception to the general 70-foot overall combination limit. Source: NRS 484D.615.","handbook":"","hbref":""},{"q":"While stopped at a railroad crossing in a Nevada school bus, in addition to stopping at the proper distance, what must the driver do before proceeding?","options":["Only watch the crossing signal lights and gates","Listen and look in both directions along the track for an approaching train","Have a passenger step out to flag the bus across","Rely on the train horn alone to signal that it is safe"],"answer":1,"explanation":"NRS 484B.560 requires the driver, while stopped, to listen and look in both directions along the track for any approaching train and for signals indicating a train's approach before crossing. Drivers are taught not to rely solely on signals. Source: NRS 484B.560; Nevada Commercial Driver Handbook.","handbook":"","hbref":""},{"q":"When does an oversize-load vehicle traveling under an NDOT permit generally have to stop moving in Nevada?","options":["Only between noon and 1:00 p.m. each day","Whenever the posted speed limit exceeds 65 mph","During hours of darkness, unless the permit or special instructions authorize night travel","Only within incorporated city limits at any hour"],"answer":2,"explanation":"Nevada NDOT over-dimensional permit conditions generally prohibit travel during hours of darkness and may restrict weekend and holiday movement unless the permit or special instructions specifically authorize it. Source: NDOT Over Dimensional Vehicle permit provisions.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver Licenses (CDLs) in Nevada?","options":["The Nevada Department of Motor Vehicles (DMV)","The Federal Motor Carrier Safety Administration (FMCSA)","The Nevada Department of Transportation (NDOT)","The Nevada Highway Patrol"],"answer":0,"explanation":"In Nevada the Department of Motor Vehicles (DMV) issues CDLs and CLPs; FMCSA sets federal standards but does not issue the license. Source: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm).","handbook":"","hbref":""},{"q":"How long is a Nevada Commercial Learner Permit (CLP) valid?","options":["180 days","30 days","60 days","1 year"],"answer":0,"explanation":"Nevada issues CLPs that are valid for 180 days. Source: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm).","handbook":"","hbref":""},{"q":"In Nevada, what is the minimum amount of time you must hold a CLP before you may take any CDL skills test?","options":["14 days","7 days","30 days","60 days"],"answer":0,"explanation":"Nevada requires that you hold a CLP for at least 14 days prior to any skills test, consistent with the federal CLP rule. Source: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm).","handbook":"","hbref":""},{"q":"The Nevada CDL skills test is made up of three parts. Which set correctly lists them?","options":["Vehicle (pre-trip) inspection, basic vehicle control, and on-road driving","General knowledge, air brakes, and combination vehicles","Written exam, vision screening, and on-road driving","Pre-trip inspection, hazardous materials, and night driving"],"answer":0,"explanation":"Nevada's three-part skills test consists of the vehicle (pre-trip) inspection, basic control skills, and the on-road driving test. Source: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm).","handbook":"","hbref":""},{"q":"Before a first-time CDL applicant in Nevada may take the skills test, what training must be completed?","options":["Entry-Level Driver Training (ELDT) from a provider listed in the Federal Training Provider Registry","A defensive-driving course approved by the courts","An online-only general knowledge course","A first-aid and CPR certification course"],"answer":0,"explanation":"Federal ELDT rules apply in Nevada: applicants must complete training from a provider on the Federal Training Provider Registry before taking the skills test. Source: Nevada DMV (dmv.nv.gov/cdl.htm); 49 CFR Part 380.","handbook":"","hbref":""},{"q":"How many self-certification categories must a Nevada commercial driver choose from when applying for a CLP or CDL?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: interstate non-excepted, interstate excepted, intrastate non-excepted, and intrastate excepted. Source: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm).","handbook":"","hbref":""},{"q":"Which self-certification category generally requires the driver to submit a DOT medical examiner's certificate?","options":["Interstate non-excepted","Interstate excepted","Intrastate excepted","Excepted government employee"],"answer":0,"explanation":"Non-excepted interstate drivers are subject to 49 CFR Part 391 physical-qualification rules and must hold/submit a Medical Examiner's Certificate; excepted categories are not required to. Source: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm).","handbook":"","hbref":""},{"q":"Which medical examiner's certificate form does the Nevada DMV accept for CDL medical certification?","options":["The MCSA-5876 Medical Examiner's Certificate","The DOT Form HS-2","The Nevada CDL-9 health waiver","Any letter signed by a physician"],"answer":0,"explanation":"The Nevada DMV accepts only the MCSA-5876 Medical Examiner's Certificate. Source: Nevada DMV CDL medical certification pages (dmv.nv.gov/cdlmedical.htm).","handbook":"","hbref":""},{"q":"As of Nevada's modernized process, how does a non-excepted driver's medical certificate normally reach the DMV?","options":["The certified medical examiner uploads it electronically to the FMCSA National Registry, which transmits it to the DMV","The driver mails a notarized paper copy to Carson City","The driver's employer faxes it to the local DMV office","The driver scans it and emails it to the DMV directly"],"answer":0,"explanation":"Effective June 16, 2025, Nevada moved to a paperless system: the examiner uploads the MEC electronically to FMCSA, which transmits it to the DMV, so drivers no longer turn in paper cards. Source: Nevada DMV news release 25013 (dmv.nv.gov).","handbook":"","hbref":""},{"q":"Who is permitted to perform the DOT physical that supports a Nevada non-excepted CDL self-certification?","options":["A provider listed on the National Registry of Certified Medical Examiners","Any licensed nurse practitioner in the state","The applicant's regular family doctor, regardless of registry status","A Nevada DMV technician at the testing site"],"answer":0,"explanation":"The exam must be performed by a provider listed on the National Registry of Certified Medical Examiners; the DMV will not accept results from unlisted providers. Source: Nevada DMV CDL medical pages (dmv.nv.gov/cdlmedical.htm).","handbook":"","hbref":""},{"q":"How long is a standard Nevada CDL valid before it must be renewed (for a driver under 65)?","options":["8 years","4 years","5 years","10 years"],"answer":0,"explanation":"A Nevada CDL expires on the eighth anniversary of issuance or renewal for drivers under 65. Source: Nevada Administrative Code NAC 483.832.","handbook":"","hbref":""},{"q":"For a Nevada CDL holder who is 65 years of age or older, how long is the CDL valid?","options":["4 years","8 years","2 years","6 years"],"answer":0,"explanation":"A CDL issued to a licensee who is 65 or older expires on the fourth anniversary of the licensee's birthday, rather than the standard 8 years. Source: Nevada Administrative Code NAC 483.832.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Nevada CDL for intrastate (within-Nevada) driving?","options":["18 years old","16 years old","19 years old","21 years old"],"answer":0,"explanation":"You must be at least 18 to obtain a Nevada CDL for intrastate operation. Source: Nevada DMV Commercial Learner Permits/CDL pages (dmv.nv.gov/clp.htm, dmv.nv.gov/cdl.htm).","handbook":"","hbref":""},{"q":"What is the minimum age required to drive in interstate commerce or to hold passenger or hazmat endorsements in Nevada?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Interstate commerce and passenger/hazmat endorsements require a minimum age of 21 in Nevada. Source: Nevada DMV CLP page (dmv.nv.gov/clp.htm).","handbook":"","hbref":""},{"q":"Which knowledge test must a Nevada applicant pass only if the vehicle they will drive is equipped with air brakes?","options":["The air brakes knowledge test","The general knowledge test","The combination vehicles test","The hazardous materials test"],"answer":0,"explanation":"The air brakes knowledge test applies when the vehicle is equipped with air brakes; failing or skipping it results in an air-brake restriction. Source: Nevada DMV CDL Licensing (dmv.nv.gov/cdl.htm).","handbook":"","hbref":""},{"q":"A Nevada applicant who certifies as 'excepted intrastate' is generally NOT required to do which of the following?","options":["Submit a DOT medical examiner's certificate","Pass the general knowledge test","Hold a CLP before testing","Provide proof of identity and residency"],"answer":0,"explanation":"Excepted drivers (e.g., certain government, firefighting, or home-to-school transport) are not required to provide a Medical Examiner's Certificate, though employers may still require an exam. Source: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm).","handbook":"","hbref":""},{"q":"Before a Nevada CLP can be issued, which requirement must the applicant first satisfy?","options":["Pass all required knowledge tests for the license class and endorsements","Complete the on-road skills test","Hold the permit for 14 days","Pass the basic vehicle control test"],"answer":0,"explanation":"To receive a CLP, the applicant must pass all required knowledge tests for the license class and endorsements; the skills tests come later. Source: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm).","handbook":"","hbref":""},{"q":"At what age does a Nevada combination-vehicle CDL restriction apply for combinations exceeding 70 feet in length?","options":["Drivers must be at least 25 years old","Drivers must be at least 18 years old","Drivers must be at least 21 years old","There is no age restriction tied to length"],"answer":0,"explanation":"Nevada requires a minimum age of 25 to operate vehicle combinations exceeding 70 feet. Source: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm).","handbook":"","hbref":""},{"q":"If a non-excepted Nevada CDL holder lets their medical certification lapse without a new electronic MEC on file, what is the likely consequence?","options":["The CDL is downgraded to non-commercial status until a valid MEC is received","The CDL is permanently revoked with no path to restoration","Nothing happens until the 8-year renewal date","The driver is automatically reclassified as excepted"],"answer":0,"explanation":"Without a current MEC on file, Nevada auto-downgrades the CDL to non-commercial status until a valid electronic MEC is received. Source: Nevada DMV news release 25013 (dmv.nv.gov).","handbook":"","hbref":""},{"q":"Which statement best reflects how Nevada CDL application fees should be treated by an applicant?","options":["Fees are set by the DMV and can change, so applicants should confirm current amounts with the DMV before applying","Fees are fixed permanently by federal law and never change","CDL testing and licensing are always free of charge in Nevada","Fees are paid directly to the FMCSA National Registry"],"answer":0,"explanation":"Nevada CDL-related fees are administered by the DMV and are subject to change; applicants should verify current amounts directly with the DMV rather than rely on a fixed figure. Source: Nevada DMV CDL pages (dmv.nv.gov/cdl.htm).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная высота транспортного средства, включая груз, при движении по автомагистрали Невады?","options":["13 футов","13 футов 6 дюймов","14 футов","15 футов"],"explanation":"Закон Невады устанавливает максимальную высоту транспортного средства, включая груз, в 14 футов, измеряемую от поверхности, на которой стоит транспортное средство (NRS 484D.605)."},"1":{"q":"Какова стандартная максимальная разрешённая ширина транспортного средства, состава транспортных средств или груза на автомагистрали Невады?","options":["96 дюймов","98 дюймов","102 дюйма","108 дюймов"],"explanation":"Максимальная разрешённая ширина любого транспортного средства, состава транспортных средств, специальной самоходной техники или груза в Неваде составляет 102 дюйма (8 футов 6 дюймов) (NRS 484D.685)."},"2":{"q":"Какова максимальная разрешённая нагрузка на любую одиночную ось транспортного средства, движущегося по дорогам общего пользования в Неваде?","options":["18 000 фунтов","20 000 фунтов","22 000 фунтов","34 000 фунтов"],"explanation":"Невада ограничивает нагрузку на любую одиночную ось до 20 000 фунтов (NRS 484D.635)."},"3":{"q":"Какова максимальная разрешённая нагрузка на любую сдвоенную ось транспортного средства на дорогах общего пользования в Неваде?","options":["32 000 фунтов","34 000 фунтов","36 000 фунтов","40 000 фунтов"],"explanation":"Невада ограничивает нагрузку на любую сдвоенную ось до 34 000 фунтов (NRS 484D.635)."},"4":{"q":"На участках системы межштатных автомагистралей Невады и других дорогах федерального финансирования какова максимальная полная масса транспортного средства, разрешённая без специального разрешения?","options":["73 280 фунтов","80 000 фунтов","88 000 фунтов","105 500 фунтов"],"explanation":"Невада применяет федеральный максимум в 80 000 фунтов полной массы на межштатных и федерально финансируемых дорогах, поскольку его снижение поставило бы под угрозу федеральное финансирование автомагистралей (NRS 484D.660; 23 U.S.C. 127)."},"5":{"q":"Какова максимальная длина состава транспортных средств в Неваде, прежде чем потребуется специальное разрешение?","options":["65 футов","70 футов","75 футов","80 футов"],"explanation":"Ни один состав соединённых вместе транспортных средств, включая навесное оборудование, не может превышать 70 футов в Неваде без специального разрешения от Департамента транспорта (NRS 484D.615)."},"6":{"q":"Какова максимальная длина одиночного грузового автомобиля (прямого грузовика) на автомагистрали Невады?","options":["35 футов","40 футов","45 футов","53 фута"],"explanation":"Одиночный грузовой автомобиль не может превышать 40 футов в длину в Неваде (NRS 484D.615)."},"7":{"q":"Какое ведомство Невады выдаёт разрешения на негабаритные и тяжеловесные (сверхгабаритные) транспортные средства?","options":["Департамент транспортных средств Невады (Nevada Department of Motor Vehicles)","Департамент транспорта Невады (Nevada Department of Transportation)","Дорожный патруль Невады (Nevada Highway Patrol)","Шериф каждого округа"],"explanation":"Департамент транспорта Невады (NDOT) выдаёт разрешения на сверхгабаритные/тяжеловесные перевозки, в том числе через свою онлайн-систему оформления разрешений на негабаритные перевозки (NRS 484D.625 и 484D.685; NDOT)."},"8":{"q":"В составе «тягач — полуприцеп» на автомагистрали Невады какова максимальная разрешённая длина полуприцепа без специального разрешения?","options":["48 футов","53 фута","57 футов","60 футов"],"explanation":"Седельный тягач с одним полуприцепом допускается, когда полуприцеп не превышает 53 фута в длину (NRS 484D.615)."},"9":{"q":"Для седельного тягача, буксирующего два прицепных звена (сдвоенные прицепы) в Неваде, какова максимальная длина каждого прицепа без специального разрешения?","options":["26 футов","28 футов 6 дюймов","30 футов","33 фута"],"explanation":"Седельный тягач с полуприцепом и прицепом допускается, когда каждое из двух прицепных звеньев не превышает 28,5 фута в длину (NRS 484D.615)."},"10":{"q":"Транспортное средство оснащено пневматическими шинами. Какова в Неваде максимальная общая ширина, измеряемая от внешней стороны одной крайней шины до внешней стороны противоположной крайней шины?","options":["102 дюйма","104 дюйма","108 дюймов","120 дюймов"],"explanation":"Для транспортных средств на пневматических шинах ширина, измеряемая от шины до шины, может достигать 108 дюймов, но сам кузов или груз по-прежнему не может превышать 102 дюйма (NRS 484D.685)."},"11":{"q":"Согласно закону Невады, какова максимальная разрешённая нагрузка на дюйм ширины шины на управляемой оси?","options":["450 фунтов на дюйм","500 фунтов на дюйм","550 фунтов на дюйм","600 фунтов на дюйм"],"explanation":"Невада ограничивает нагрузку на управляемую ось до 600 фунтов на дюйм ширины шины (и 500 фунтов на дюйм для всех остальных осей) (NRS 484D.635)."},"12":{"q":"Согласно закону Невады, какова максимальная разрешённая нагрузка на дюйм ширины шины на осях, кроме управляемой?","options":["400 фунтов на дюйм","500 фунтов на дюйм","600 фунтов на дюйм","650 фунтов на дюйм"],"explanation":"Для всех осей, кроме управляемой, Невада ограничивает нагрузку до 500 фунтов на дюйм ширины шины (600 фунтов на дюйм допускается только на управляемой оси) (NRS 484D.635)."},"13":{"q":"Невада применяет федеральную мостовую формулу для определения максимальной нагрузки на группу последовательных осей. Два последовательных комплекта сдвоенных осей могут нести по 34 000 фунтов каждый, если расстояние между первой и последней осью группы составляет не менее скольких футов?","options":["30 футов","33 фута","36 футов","40 футов"],"explanation":"Согласно федеральной мостовой формуле в применении в Неваде, два последовательных комплекта сдвоенных осей могут нести по 34 000 фунтов каждый, если общее расстояние между первой и последней осью составляет 36 футов или более (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)."},"14":{"q":"Перевозчик хочет переместить груз шириной 110 дюймов по автомагистрали Невады. Что для этого требуется?","options":["Ничего, поскольку это в пределах разрешённой ширины","Разрешение на негабаритный груз от Департамента транспорта Невады","Только жёлтые предупреждающие огни на каждом углу","Освобождение (отказ от требований) от Дорожного патруля Невады"],"explanation":"Груз шире разрешённого предела в 102 дюйма является негабаритным и требует разрешения на сверхгабаритную перевозку от NDOT, прежде чем его можно будет переместить (NRS 484D.685; NDOT)."},"15":{"q":"Какова цель федеральной мостовой формулы, которую Невада применяет на системе межштатных автомагистралей?","options":["Она устанавливает максимальную скорость для тяжёлых грузовиков","Она ограничивает нагрузку на группу осей в зависимости от количества осей и расстояния между ними","Она устанавливает регистрационный сбор для коммерческих транспортных средств","Она определяет максимальную длину прицепа"],"explanation":"Федеральная мостовая формула ограничивает полную массу, которую может нести любая группа из двух или более последовательных осей, исходя из количества осей и расстояния между крайними осями группы, чтобы защитить мосты (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)."},"16":{"q":"Транспортному средству, перевозящему навалом рыхло уложенную (нетюкованную) сельскохозяйственную продукцию, такую как сено или солома, в Неваде предоставляется послабление по ширине. Какова максимальная разрешённая ширина для такого груза и его удерживающих стоек?","options":["102 дюйма","108 дюймов","114 дюймов","120 дюймов"],"explanation":"Невада допускает, чтобы груз из рыхло уложенной сельскохозяйственной продукции (не упакованной в ящики, не тюкованной, не в коробках и не в мешках) вместе с любыми удерживающими стойками был шириной до 120 дюймов, что является послаблением от стандарта в 102 дюйма (NRS 484D.705)."},"17":{"q":"Невада допускает, чтобы груз тюкованного сена превышал обычный предел высоты в 14 футов. Какова максимальная разрешённая высота для груза тюкованного сена?","options":["14 футов 6 дюймов","15 футов","16 футов","17 футов"],"explanation":"Хотя общий предел высоты составляет 14 футов, Невада допускает перевозку груза тюкованного сена на высоту до 15 футов (NRS 484D.605)."},"18":{"q":"Когда NDOT устанавливает, что транспортные средства, движущиеся с максимально разрешённой массой, вероятно вызовут существенную нагрузку на конкретную автомагистраль, мост или улицу, что может сделать NDOT или местный орган управления?","options":["Навсегда закрыть дорогу для всего коммерческого транспорта","Снизить разрешённые пределы массы на этой автомагистрали, дороге или улице","Потребовать от всех грузовиков добавить третий прицеп","Увеличить общештатный предел нагрузки на одиночную ось в качестве компенсации"],"explanation":"NDOT и местные органы управления могут снижать пределы массы на любой автомагистрали, дороге или улице, где транспортные средства с максимально разрешённой массой вероятно вызовут существенную нагрузку на конструкцию (NRS 484D.660)."},"19":{"q":"Автоперевозчику требуется годовое разрешение на тяжеловесные перевозки для регулярных рейсов в Неваде. Согласно рекомендациям NDOT, за какой срок перевозчику рекомендуется подавать заявку через систему оформления разрешений на негабаритные перевозки?","options":["Не менее чем за 24 часа","Не менее чем за 7 дней","Не менее чем за 30 дней","Не менее чем за 90 дней"],"explanation":"NDOT рекомендует обладателям разрешений планировать не менее чем за 30 дней до желаемой перевозки или до истечения срока действия существующего годового разрешения; заявки подаются через систему оформления разрешений на негабаритные перевозки NDOT (NDOT; NRS 484D.625)."},"20":{"q":"В Неваде какой класс коммерческих водительских прав (CDL) требуется для управления составом транспортных средств с полной массой состава более 26 000 фунтов, когда буксируемое звено имеет полную разрешённую массу (GVWR) более 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Невада требует CDL класса A для составных транспортных средств свыше 26 000 фунтов, где прицеп/буксируемое звено превышает 10 000 фунтов GVWR. Источник: Nevada DMV CDL-051 «Commercial Driver License Information» и dmv.nv.gov/cdlcertify.htm (License Classes)."},"21":{"q":"Какой класс CDL Невады охватывает любое одиночное транспортное средство с GVWR 26 001 фунт или более, например, большой автобус или прямой грузовик, буксирующее звено не более 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"CDL класса B в Неваде охватывает одиночные транспортные средства массой 26 001 фунт или более (автобусы, большие грузовики), буксирующие звено менее 10 001 фунта. Источник: Nevada DMV cdlcertify.htm и CDL-051."},"22":{"q":"Согласно правилам Невады, транспортное средство, которое не соответствует ограничениям по размеру класса A или B, но предназначено для перевозки 16 или более пассажиров (включая водителя) или которое перевозит опасные материалы, требующие табличек, требует какого класса CDL?","options":["Класс A","Класс B","Класс C","Класс P"],"explanation":"CDL класса C в Неваде предназначен для транспортных средств, не достигающих весовых пределов A/B, которые перевозят 16 и более пассажиров (включая водителя) или требуют таблички об опасных материалах. Источник: Nevada DMV cdlcertify.htm и CDL-051."},"23":{"q":"Каков минимальный возраст для получения CDL Невады для управления коммерческим транспортным средством в межштатных перевозках?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Невада требует, чтобы заявители были не моложе 21 года для управления коммерческим транспортным средством в межштатных перевозках. Источник: Nevada DMV CDL-051 «Minimum Age»."},"24":{"q":"В Неваде заявителю в возрасте от 18 до 20 лет CDL может быть выдан только для какого вида перевозок?","options":["Только межштатные перевозки","Только внутриштатные перевозки","Только маршруты федерального правительства","Только перевозка пассажиров"],"explanation":"Невада разрешает лицам в возрасте от 18 до 20 лет получать CDL только для внутриштатных перевозок; они не могут перевозить пассажиров за плату или перевозить опасные материалы, требующие табличек. Источник: Nevada DMV CDL-051 «Minimum Age»."},"25":{"q":"Каков минимальный возраст в Неваде для получения отметки (endorsement), необходимой для управления сверхдлинным составом транспортных средств (70 футов)?","options":["21 год","23 года","25 лет","26 лет"],"explanation":"Невада требует, чтобы водители были не моложе 25 лет для управления сверхдлинным составом транспортных средств длиной 70 футов. Источник: Nevada DMV CDL-051 «Minimum Age»; см. также NRS 484D.615 (ограничения по длине)."},"26":{"q":"Сколько времени действует коммерческое ученическое разрешение Невады (CLP) с даты его выдачи?","options":["60 дней","90 дней","180 дней","1 год"],"explanation":"CLP Невады действует 180 дней с момента выдачи (продление может потребовать повторной сдачи экзаменов). Источник: Nevada DMV dmv.nv.gov/clp.htm и CDL-051 «CLP Conditions»."},"27":{"q":"Согласно правилам Невады и федеральным правилам, сколько времени необходимо владеть коммерческим ученическим разрешением (CLP), прежде чем его обладатель сможет сдать экзамен на навыки CDL?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 21 дня","Не менее 30 дней"],"explanation":"CLP Невады необходимо владеть не менее 14 дней до сдачи экзамена на навыки, что соответствует федеральному требованию. Источник: Nevada DMV clp.htm и CDL-051 «CLP Conditions»."},"28":{"q":"Перед выдачей CLP или CDL сколько форм подтверждения проживания в Неваде требует Nevada DMV предъявить заявителю?","options":["Одну форму","Две формы","Три формы","Подтверждение не требуется"],"explanation":"Невада требует две формы подтверждения проживания, показывающие имя заявителя и его жилой адрес в Неваде. Источник: Nevada DMV CDL-051 «Proof of residency»."},"29":{"q":"Какой документ принимается Nevada DMV в качестве подтверждения номера социального страхования заявителя для CDL?","options":["Карточка регистрации избирателя","Карточка социального страхования, форма W-2 или расчётный листок с указанием полного номера","Регистрация транспортного средства в Неваде","Подписанное личное заявление под присягой"],"explanation":"Невада принимает карточку социального страхования, форму W-2, 1099 или расчётный листок с указанием полного номера SSN в качестве подтверждения номера социального страхования. Источник: Nevada DMV CDL-051 «Proof of Your Social Security Number»."},"30":{"q":"Для заявителя на CDL, родившегося в США, какой документ Nevada DMV принимает в качестве дополнительного подтверждения личности?","options":["Заверенное свидетельство о рождении или паспорт США","Аттестат об окончании средней школы","Читательский билет","Выписку по кредитной карте"],"explanation":"Невада принимает заверенное свидетельство о рождении (или выписку из него) либо паспорт США в качестве дополнительного подтверждения личности для заявителей, родившихся в США; документы должны быть оригиналами. Источник: Nevada DMV CDL-051 «Additional Proof of Identity»."},"31":{"q":"Заявитель на CDL, родившийся за пределами Соединённых Штатов, должен предъявить Nevada DMV что из следующего, чтобы подтвердить законность пребывания?","options":["Иностранные водительские права","Действующий непросроченный иностранный паспорт со штампом I-94, карту постоянного жителя (Permanent Resident card) или свидетельство о натурализации (Certificate of Naturalization)","Консульскую визитную карточку","Студенческий билет любой страны"],"explanation":"Невада требует, чтобы заявители, родившиеся за рубежом, предъявили действующий непросроченный иностранный паспорт (со штампом I-94), карту постоянного жителя или свидетельство о натурализации. Источник: Nevada DMV CDL-051 «Additional Proof of Identity»."},"32":{"q":"Какая отметка (endorsement) CDL Невады требуется для перевозки опасных материалов в количествах, требующих табличек?","options":["Отметка N","Отметка T","Отметка H","Отметка P"],"explanation":"Отметка H (опасные материалы, HazMat) требуется для перевозки опасных материалов, требующих табличек, в Неваде. Источник: Nevada DMV CDL-051 «Endorsements» и dmv.nv.gov/cdl.htm."},"33":{"q":"Помимо наличия CDL и действительного удостоверения личности, что должен пройти заявитель в Неваде, прежде чем может быть выдана отметка HazMat (H)?","options":["Курс безопасного вождения","Проверку биографических данных на основе отпечатков пальцев","Второй экзамен на навыки вождения по дорогам","Отметку для транспортного средства длиной 70 футов"],"explanation":"Невада требует, чтобы заявитель прошёл проверку биографических данных на основе отпечатков пальцев (TSA); экзамен на знания по HazMat нельзя сдавать до завершения проверки биографических данных. Источник: Nevada DMV CDL-051 «Hazmat Endorsement»."},"34":{"q":"Какая отметка (endorsement) CDL Невады требуется для управления цистерной, перевозящей жидкие или газообразные материалы в стационарно установленной наливной цистерне?","options":["Отметка T","Отметка N","Отметка S","Отметка X"],"explanation":"Отметка N (цистерна, Tank Vehicle) требуется для управления транспортными средствами-цистернами в Неваде. Источник: Nevada DMV CDL-051 «Endorsements»."},"35":{"q":"Что обозначает отметка X в коммерческих правах Невады?","options":["Право на сдвоенные/строенные прицепы","Совмещённую отметку HazMat и цистерны (Hazmat Tanker)","Отметку для школьного автобуса","Отметку для сверхдлинного транспортного средства"],"explanation":"Невада указывает X как отметку Hazmat Tanker (объединяющую требования H и N). Источник: Nevada DMV CDL-051 «Endorsements»."},"36":{"q":"Какую отметку требует Невада для того, чтобы водитель мог буксировать сдвоенные или строенные прицепы?","options":["Отметка P","Отметка S","Отметка T","Отметка N"],"explanation":"Отметка T (сдвоенные/строенные прицепы) требуется для буксировки сдвоенных или строенных прицепов в Неваде. Источник: Nevada DMV CDL-051 «Endorsements»."},"37":{"q":"Водитель, который хочет управлять государственным школьным автобусом в Неваде, должен иметь какое сочетание отметок?","options":["Отметки P и S","Отметки N и T","Отметки H и X","Только отметку S"],"explanation":"Водитель школьного автобуса в Неваде должен иметь как отметку для пассажиров (P), так и отметку для школьного автобуса (S), каждая из которых требует дополнительной сдачи экзаменов на знания и навыки. Источник: материалы Nevada DMV по CDL; Nevada School Bus Driver Training Manual (ELDT для P и S)."},"38":{"q":"Где начинающий коммерческий водитель в Неваде должен пройти обязательное обучение водителей начального уровня (ELDT)?","options":["В любой лицензированной компании Невады","У поставщика, указанного в федеральном реестре поставщиков обучения (Training Provider Registry)","В офисе шерифа округа","На онлайн-курсе по выбору водителя"],"explanation":"Невада требует, чтобы коммерческие водители начального уровня проходили ELDT у поставщика, указанного в федеральном реестре поставщиков обучения FMCSA (Training Provider Registry). Источник: Nevada DMV CDL-051 «Entry Level Driver Training (ELDT)»; 49 CFR Part 380."},"39":{"q":"При самостоятельной сертификации в Nevada DMV какая категория применяется к обладателю CDL, который ездит только в пределах Невады и на которого распространяются стандарты физической пригодности штата (а не федеральные согласно Part 391)?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Interstate-Excepted"],"explanation":"Категория Non-Excepted Intrastate применяется к водителям, работающим только в пределах Невады, на которых распространяются квалификационные стандарты водителей штата. Источник: Nevada DMV dmv.nv.gov/cdlcertify.htm (категории самостоятельной сертификации); 49 CFR 383.71."},"40":{"q":"При управлении коммерческим транспортным средством (CMV) в Неваде водитель CDL считается находящимся в состоянии алкогольного опьянения и совершает серьёзное правонарушение (major offense) при какой концентрации алкоголя в крови (BAC)?","options":["0,04 процента или выше","0,08 процента или выше","0,02 процента или выше","0,10 процента или выше"],"explanation":"Невада применяет федеральный стандарт для CMV: управление CMV с BAC 0,04 процента или более является дисквалифицирующим серьёзным правонарушением (общий предел 0,08 процента для водителей без CDL по-прежнему применяется в любом транспортном средстве). Источник: Nevada Commercial Driver Handbook (дисквалификации) и 49 CFR 383.51."},"41":{"q":"Согласно закону Невады о подразумеваемом согласии, что произойдёт, если водитель CDL откажется пройти химический анализ крови, дыхания или мочи по законному требованию?","options":["Водительские права автоматически аннулируются, а сам отказ является дисквалифицирующим серьёзным правонарушением","Ничего не произойдёт, если только водитель позже не будет осуждён за DUI в суде","За первый отказ выдаётся только письменное предупреждение","Водитель платит гражданский штраф в размере 250 долларов без каких-либо действий в отношении прав"],"explanation":"Управляя транспортным средством в Неваде, обладатель CDL даёт подразумеваемое согласие на прохождение анализов; отказ влечёт автоматическое аннулирование прав со стороны DMV и считается серьёзным правонарушением, которое дисквалифицирует CDL, даже если водитель позже будет оправдан. Источник: статуты Невады о подразумеваемом согласии (NRS Chapter 484C) и Nevada Commercial Driver Handbook."},"42":{"q":"За первое серьёзное правонарушение (такое как DUI или отказ от анализа), совершённое НЕ при перевозке опасных материалов, требующих табличек, на какой срок дисквалифицируется CDL Невады?","options":["1 год","60 дней","3 года","6 месяцев"],"explanation":"Первое серьёзное правонарушение дисквалифицирует CDL минимум на 1 год. Источник: Nevada Commercial Driver Handbook (дисквалификации) и 49 CFR 383.51."},"43":{"q":"Если первое серьёзное правонарушение (такое как DUI) совершено в то время, когда водитель управляет CMV, перевозящим опасные материалы, требующие табличек, дисквалификация CDL Невады увеличивается до:","options":["3 лет","1 года","5 лет","пожизненной"],"explanation":"Первое серьёзное правонарушение, совершённое при перевозке опасных материалов, требующих табличек, влечёт дисквалификацию на 3 года вместо стандартного 1 года. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"44":{"q":"Каков срок дисквалификации CDL Невады за ВТОРОЕ серьёзное правонарушение (например, второе осуждение за DUI на CMV)?","options":["Пожизненная дисквалификация","10 лет","3 года","5 лет"],"explanation":"Второе серьёзное правонарушение влечёт пожизненную дисквалификацию CDL (ограниченное восстановление по истечении не менее 10 лет может быть доступно только при определённых условиях). Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"45":{"q":"Водитель CDL в Неваде осуждён за ДВА серьёзных нарушения ПДД в отдельных случаях в течение 3-летнего периода. CDL дисквалифицируется на:","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения ПДД в течение 3 лет (в отдельных случаях) дисквалифицируют CDL на 60 дней. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"46":{"q":"Водитель CDL в Неваде осуждён за ТРИ серьёзных нарушения ПДД в отдельных случаях в течение 3-летнего периода. CDL дисквалифицируется на:","options":["120 дней","60 дней","1 год","90 дней"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет (в отдельных случаях) дисквалифицируют CDL на 120 дней, в дополнение к любой предшествующей 60-дневной дисквалификации. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"47":{"q":"Что из следующего считается СЕРЬЁЗНЫМ нарушением ПДД для целей дисквалификации CDL в Неваде?","options":["Превышение скорости на 15 миль/ч или более над установленным пределом","Превышение скорости на 5 миль/ч над установленным пределом","Нарушение правил стоянки без движения транспортного средства","Вождение с просроченной регистрацией транспортного средства"],"explanation":"Чрезмерное превышение скорости, определяемое как 15 миль/ч или более над установленным пределом, является перечисленным серьёзным нарушением ПДД. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"48":{"q":"Какой набор правонарушений полностью классифицируется как СЕРЬЁЗНЫЕ нарушения ПДД согласно правилам CDL Невады?","options":["Безрассудное вождение, движение на слишком близком расстоянии и неправильная или беспорядочная смена полос","DUI, оставление места ДТП и использование CMV при совершении тяжкого преступления","Отказ от химического анализа, второе DUI и наезд со смертельным исходом со скрытием с места ДТП","Нарушение разрешения на тяжеловесную перевозку, просроченная медицинская карта и неоплаченные дорожные сборы"],"explanation":"Безрассудное вождение, движение на слишком близком расстоянии и неправильная или беспорядочная смена полос — всё это серьёзные нарушения ПДД. Остальные перечисленные правонарушения являются серьёзными правонарушениями (major offenses) или не входят в список серьёзных нарушений. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"49":{"q":"Управление CMV в Неваде без надлежащего класса CDL или коммерческого ученического разрешения либо без них при себе классифицируется как:","options":["Серьёзное нарушение ПДД","Серьёзное правонарушение (major offense)","Нарушение предписания о выводе из эксплуатации (out-of-service)","Недисквалифицирующая ошибка в документах"],"explanation":"Управление CMV без надлежащего CDL/CLP либо без них при себе является серьёзным нарушением ПДД, которое учитывается при 60-дневной/120-дневной дисквалификации. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"50":{"q":"За ПЕРВОЕ осуждение за нарушение на железнодорожном переезде на CMV CDL Невады дисквалифицируется не менее чем на:","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде дисквалифицирует CDL не менее чем на 60 дней. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"51":{"q":"ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода дисквалифицирует CDL Невады не менее чем на:","options":["120 дней","60 дней","1 год","90 дней"],"explanation":"Второе нарушение на переезде в течение любого 3-летнего периода дисквалифицирует CDL не менее чем на 120 дней. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"52":{"q":"ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода дисквалифицирует CDL Невады не менее чем на:","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье нарушение на переезде в течение любого 3-летнего периода дисквалифицирует CDL не менее чем на 1 год. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"53":{"q":"Если водитель нарушает предписание о выводе из эксплуатации при перевозке опасных материалов, требующих табличек, или при управлении транспортным средством, предназначенным для 16 или более пассажиров, дисквалификация за ПЕРВОЕ нарушение составляет:","options":["Не менее 180 дней и не более 2 лет","Не менее 90 дней и не более 1 года","Не менее 1 года и не более 5 лет","Ровно 120 дней"],"explanation":"Первое нарушение предписания OOS при перевозке опасных материалов, требующих табличек, или при перевозке 16 и более пассажиров дисквалифицирует CDL не менее чем на 180 дней и не более чем на 2 года. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"54":{"q":"Помимо дисквалификации, водитель, осуждённый за нарушение предписания о выводе из эксплуатации в Неваде, подвергается федеральному гражданскому штрафу в размере не менее:","options":["$1,000","$250","$500","$2,750"],"explanation":"Водитель, нарушивший предписание OOS, подвергается гражданскому штрафу в размере не менее $1,000 (и до $2,500), отдельно от дисквалификации. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51."},"55":{"q":"Согласно закону Невады (NRS 484B.165), использование мобильного телефона в руках или отправка текстовых сообщений во время вождения влечёт какой гражданский штраф за ПЕРВОЕ нарушение?","options":["$50","$100","$250","$500"],"explanation":"Закон Невады о телефонах в руках/текстовых сообщениях (NRS 484B.165) устанавливает гражданский штраф в размере $50 за первое нарушение, $100 за второе и $250 за третье в течение 7 лет; первое нарушение не рассматривается как нарушение ПДД с движением. Источник: NRS 484B.165."},"56":{"q":"Для обладателя CDL, как использование телефона в руках или отправка текстовых сообщений во время управления CMV влияет на коммерческие права согласно правилам Невады/федеральным правилам?","options":["Это серьёзное нарушение ПДД, которое при повторении может привести к дисквалификации на 60 или 120 дней","Это серьёзное правонарушение (major offense), влекущее дисквалификацию на 1 год за первое нарушение","Это влечёт только штраф $50 без влияния на CDL","Это нарушение предписания о выводе из эксплуатации, влекущее дисквалификацию на 90 дней"],"explanation":"Отправка текстовых сообщений или использование мобильного телефона в руках во время управления CMV является серьёзным нарушением ПДД; два таких нарушения в течение 3 лет дисквалифицируют CDL на 60 дней, а три в течение 3 лет — на 120 дней. Источник: Nevada Commercial Driver Handbook и 49 CFR 383.51 / 392.80-392.82."},"57":{"q":"Невада ограничивает штраф за превышение скорости согласно статуту об основном правиле (NRS 484B.600) какой суммой за каждую милю в час сверх предела?","options":["$20 за каждую милю/ч сверх предела","$25 за каждую милю/ч сверх предела","$10 за каждую милю/ч сверх предела","$50 за каждую милю/ч сверх предела"],"explanation":"Невада ограничивает штраф за превышение скорости суммой $20 за каждую милю в час, на которую водитель превышает установленный предел; для обладателя CDL превышение скорости на 15+ миль/ч сверх предела остаётся серьёзным нарушением ПДД независимо от суммы штрафа. Источник: NRS 484B.600 и Nevada Commercial Driver Handbook."},"58":{"q":"Согласно закону Невады «Move Over» (об уступлении полосы), когда вы приближаетесь к стоящему на шоссе автомобилю экстренных служб, эвакуатору или транспортному средству NDOT с включёнными проблесковыми маячками, что вы должны сделать?","options":["Снизить скорость до разумной, продолжать движение с осторожностью и, если возможно, перестроиться в полосу, не примыкающую к стоящему автомобилю","Полностью остановиться, пока проблесковые маячки автомобиля экстренной службы не будут выключены","Сохранять установленную ограничением скорость, но подавать звуковой сигнал при проезде","Съехать на правую обочину и ждать, пока офицер не даст знак проезжать"],"explanation":"Закон Невады «Move Over» (NRS 484B.607) требует от водителей снизить скорость до разумной и надлежащей, продолжать движение с осторожностью, быть готовыми остановиться и, если возможно, перестроиться в полосу, не примыкающую непосредственно к стоящему автомобилю. Он применяется к уполномоченным автомобилям экстренных служб и к транспортным средствам с включёнными мигающими жёлтыми или немигающими синими огнями, включая автомобили NDOT. Источник: NRS 484B.607."},"59":{"q":"На разделённом шоссе Невады с физическим барьером или разделительной секцией школьный автобус, остановившийся на ДРУГОЙ проезжей части, включает мигающие красные огни для посадки детей. Что должен сделать водитель, едущий в вашем направлении?","options":["Остановиться, пока красные огни не перестанут мигать, так же как на неразделённой дороге","Останавливаться не обязан, поскольку автобус находится на другой проезжей части разделённого шоссе","Снизить скорость до 15 mph и проехать с осторожностью по дальней полосе","Останавливаться только если видно, что дети пересекают разделительную полосу"],"explanation":"Согласно NRS 484B.353, водитель транспортного средства на разделённом шоссе не обязан останавливаться при встрече или проезде школьного автобуса, находящегося на другой проезжей части. Невада определяет разделённое шоссе как разделённое физическим барьером или разделительной секцией, поэтому это исключение требует настоящего разделённого шоссе, а не просто осевой линии или полосы для поворота. Источник: NRS 484B.353."},"60":{"q":"Когда школьный автобус Невады с детьми, автобус с пассажирами или транспортное средство с табличками об опасных материалах приближается к железнодорожному переезду, на котором обязан остановиться, на каком расстоянии от ближайшего рельса он должен остановиться?","options":["Не менее 5 футов и не более 25 футов от ближайшего рельса","Не менее 25 футов и не более 75 футов от ближайшего рельса","Не менее 15 футов и не более 50 футов от ближайшего рельса","Не менее 50 футов и не более 100 футов от ближайшего рельса"],"explanation":"NRS 484B.560 требует, чтобы автобус с пассажирами, школьный автобус с детьми или транспортное средство с табличками об опасных материалах остановилось в пределах 50 футов, но не ближе 15 футов от ближайшего рельса перед пересечением переезда в одном уровне. Источник: NRS 484B.560."},"61":{"q":"В Неваде коммерческое транспортное средство, которое НЕ обязано полностью останавливаться на железнодорожном переезде, всё же имеет определённую обязанность перед пересечением. Какую?","options":["Поддерживать шоссейную скорость, чтобы проехать переезд как можно быстрее","Остановиться, поставить стояночный тормоз и опустить окно, чтобы прислушаться","Дважды подать звуковой сигнал и продолжить движение, не снижая скорости","Снизить скорость и убедиться, что пути свободны от приближающегося поезда"],"explanation":"NRS 484B.560 предусматривает, что коммерческое транспортное средство (как определено в 49 C.F.R. 383.5), которое иным образом не обязано останавливаться, должно перед пересечением переезда в одном уровне снизить скорость и убедиться, что пути свободны от любого приближающегося поезда или рельсового оборудования. Источник: NRS 484B.560."},"62":{"q":"Какое максимальное ограничение скорости может быть установлено на любом шоссе Невады?","options":["65 миль в час","80 миль в час","75 миль в час","85 миль в час"],"explanation":"Согласно NRS 484B.613, NDOT может устанавливать ограничения скорости, не превышающие 80 миль в час, на шоссе штата, и 80 mph — это самое высокое установленное ограничение в Неваде (на отдельных сельских участках межштатных автомагистралей). Источник: NRS 484B.613; NRS 484B.617."},"63":{"q":"Устанавливает ли закон Невады единое для всего штата максимальное ограничение скорости для грузовиков, которое ниже ограничения для легковых автомобилей?","options":["Да, грузовики ограничены 55 mph по всему штату","Да, грузовики ограничены 60 mph на всех межштатных автомагистралях","Единого для всего штата пониженного ограничения для грузовиков нет; NDOT может установить пониженное ограничение для грузовиков там, где оно обозначено знаком","Да, грузовики всегда должны двигаться ровно на 10 mph ниже установленного ограничения для легковых автомобилей"],"explanation":"В отличие от некоторых штатов, Невада не вводит общего для всего штата пониженного ограничения скорости для грузовиков. NRS 484B.613 уполномочивает NDOT устанавливать пониженное ограничение скорости для грузовиков, негабаритных транспортных средств и автобусов там, где это обосновано исследованиями, с обозначением знаком; в остальных случаях грузовики следуют установленному ограничению. Источник: NRS 484B.613."},"64":{"q":"На шоссе Невады с контролируемым доступом, когда водитель обязан покинуть крайнюю левую полосу?","options":["Только когда знак специально запрещает грузовикам движение по левой полосе","Всякий раз, когда какое-либо транспортное средство находится в пределах 500 футов позади, независимо от скорости","Только в ночное время суток","Когда движется медленнее установленного ограничения скорости и его обгоняет более быстрое транспортное средство сзади"],"explanation":"NRS 484B.208 требует, чтобы водитель в крайней левой полосе шоссе с контролируемым доступом покинул эту полосу, когда движется ниже установленного ограничения скорости и его обгоняет более быстрое транспортное средство. Исключения включают обгон, подготовку к левому повороту, дорожные работы, использование полосы HOV и движение в пределах города или посёлка. Источник: NRS 484B.208."},"65":{"q":"После остановки коммерческого транспортного средства на обочине двухполосного двустороннего шоссе Невады, в течение скольких минут вы должны выставить аварийные предупреждающие устройства?","options":["В течение 10 минут","В течение 5 минут","В течение 15 минут","В течение 30 минут"],"explanation":"Федеральное правило 49 C.F.R. 392.22, которое Невада применяет к коммерческим транспортным средствам, требует, чтобы светоотражающие треугольники (или другие одобренные устройства) были выставлены в течение 10 минут после остановки на проезжей части или обочине шоссе. Источник: 49 C.F.R. 392.22; Руководство коммерческого водителя Невады."},"66":{"q":"На двухполосной двусторонней дороге Невады, где вы размещаете три аварийных предупреждающих треугольника для остановившегося коммерческого транспортного средства (не вблизи холма или поворота)?","options":["10 футов, 50 футов и 100 футов, все позади транспортного средства","25 футов, 75 футов и 150 футов позади транспортного средства","10 футов позади транспортного средства, 100 футов позади и 100 футов впереди транспортного средства","50 футов впереди, 50 футов позади и один на крыше транспортного средства"],"explanation":"Согласно 49 C.F.R. 392.22, на двухполосной двусторонней дороге вы размещаете один треугольник примерно в 10 футах от транспортного средства в сторону приближающегося движения, один примерно в 100 футах сзади и один примерно в 100 футах спереди, чтобы движение предупреждалось с обоих направлений. Источник: 49 C.F.R. 392.22; Руководство коммерческого водителя Невады."},"67":{"q":"Какова максимальная разрешённая ширина коммерческого транспортного средства или его груза на шоссе Невады, прежде чем потребуется разрешение на негабаритный груз?","options":["96 дюймов (8 футов)","114 дюймов (9 футов 6 дюймов)","120 дюймов (10 футов)","102 дюйма (8 футов 6 дюймов)"],"explanation":"NRS 484D.685 устанавливает максимальную разрешённую ширину транспортного средства, автопоезда или груза в 102 дюйма (8 футов 6 дюймов), исключая определённые устройства безопасности. Всё, что шире, требует разрешения на негабаритный груз. Источник: NRS 484D.685."},"68":{"q":"Какова максимальная разрешённая высота, включая груз, для транспортного средства на шоссе Невады?","options":["14 футов","13 футов 6 дюймов","15 футов","16 футов"],"explanation":"NRS 484D.605 запрещает эксплуатацию транспортного средства на шоссе Невады, если его высота, включая любой груз, превышает 14 футов. (Узкое исключение допускает прессованное сено высотой до 15 футов.) Источник: NRS 484D.605."},"69":{"q":"На разделённом шоссе или дороге с односторонним движением в Неваде, где размещается САМЫЙ ДАЛЬНИЙ аварийный предупреждающий треугольник позади остановившегося коммерческого транспортного средства?","options":["Примерно в 100 футах в сторону приближающегося движения","Примерно в 200 футах в сторону приближающегося движения","Примерно в 50 футах в сторону приближающегося движения","Примерно в 500 футах в сторону приближающегося движения"],"explanation":"Согласно 49 C.F.R. 392.22, на дороге с односторонним движением или разделённом шоссе треугольники размещаются примерно в 10, 100 и 200 футах в сторону приближающегося движения позади транспортного средства. Источник: 49 C.F.R. 392.22; Руководство коммерческого водителя Невады."},"70":{"q":"Какое транспортное средство по закону Невады обязано ОСТАНАВЛИВАТЬСЯ на каждом железнодорожном переезде (при отсутствии исключения)?","options":["Пустой бортовой полуприцеп без табличек","Доставочный фургон массой менее 10 000 фунтов","Легковой автомобиль, буксирующий небольшой прицеп","Школьный автобус с детьми"],"explanation":"NRS 484B.560 требует, чтобы автобусы с пассажирами, школьные автобусы с детьми и транспортные средства с табличками об опасных материалах останавливались на всех железнодорожных переездах. Бортовой полуприцеп без табличек, лёгкий фургон или легковой автомобиль не относятся к категории обязательной остановки. Источник: NRS 484B.560."},"71":{"q":"Когда автобус или транспортное средство с табличками в Неваде остановилось на железнодорожном переезде и готовится к пересечению, какое правило по передачам применяется?","options":["Пересекать на передаче, которая не требует переключения во время нахождения на переезде","Переключиться на низшую передачу посреди переезда","Перейти на нейтраль и проехать пути накатом","Использовать самую высокую доступную передачу, чтобы пересечь пути как можно быстрее"],"explanation":"NRS 484B.560 предписывает, что после остановки водитель должен пересекать переезд только на той передаче, которая не потребует переключения во время проезда переезда, и не должен переключать передачи на путях. Источник: NRS 484B.560."},"72":{"q":"Какая ситуация является ИСКЛЮЧЕНИЕМ, освобождающим автобус или транспортное средство с табличками в Неваде от обязательной остановки на железнодорожном переезде?","options":["Водитель отстаёт от графика","Полицейский или регулировщик руководит движением на переезде","На переезде установлены автоматические шлагбаумы, которые подняты","Видимость вдоль путей превышает 400 футов"],"explanation":"NRS 484B.560 перечисляет исключения, включая переезды, регулируемые полицейским или регулировщиком, заброшенные или помеченные как освобождённые пути, а также определённое промышленное маневрирование в деловом районе. Хороший обзор или опоздание не являются исключением. Источник: NRS 484B.560."},"73":{"q":"Какова максимальная разрешённая полная масса транспортного средства на шоссе Невады, прежде чем потребуется разрешение на сверхнормативный вес?","options":["73 280 фунтов","90 000 фунтов","80 000 фунтов","100 000 фунтов"],"explanation":"Невада следует федеральному ограничению: максимальная полная масса составляет 80 000 фунтов, при 20 000 фунтов на одиночной оси и 34 000 фунтов на сдвоенной оси, с учётом мостовой формулы. Более тяжёлые грузы требуют разрешения NDOT на сверхнормативный вес. Источник: NRS Chapter 484D (габариты/вес); разрешения NDOT Over Dimensional."},"74":{"q":"Водитель впервые нарушает закон Невады «Move Over» на обычном шоссе (вне зоны дорожных работ). Как обычно классифицируется это правонарушение?","options":["Как мисдиминор со штрафом (около $395) и штрафными баллами","Как немоторное нарушение без баллов и без штрафа","Как фелония с обязательным аннулированием прав","Только как предупреждение, без наказания за первое нарушение"],"explanation":"Нарушение NRS 484B.607 является мисдиминором; первое нарушение обычно влечёт штраф в размере около $395 (и до примерно $790 в зоне дорожных работ) плюс штрафные баллы. Источник: NRS 484B.607."},"75":{"q":"Для седельного тягача, буксирующего один полуприцеп в Неваде, какова максимальная разрешённая длина полуприцепа (без специального разрешения)?","options":["48 футов","57 футов","60 футов","53 фута"],"explanation":"NRS 484D.615 допускает сочетание седельного тягача и полуприцепа, в котором полуприцеп не превышает 53 футов, в качестве исключения из общего ограничения общей длины автопоезда в 70 футов. Источник: NRS 484D.615."},"76":{"q":"Находясь на остановке у железнодорожного переезда в школьном автобусе Невады, что, помимо остановки на надлежащем расстоянии, водитель должен сделать перед началом движения?","options":["Только следить за сигнальными огнями и шлагбаумами переезда","Прислушаться и посмотреть в обе стороны вдоль путей на предмет приближающегося поезда","Попросить пассажира выйти, чтобы регулировать проезд автобуса","Полагаться только на гудок поезда как сигнал безопасности"],"explanation":"NRS 484B.560 требует, чтобы водитель во время остановки прислушался и посмотрел в обе стороны вдоль путей на предмет любого приближающегося поезда и сигналов, указывающих на приближение поезда, перед пересечением. Водителей учат не полагаться только на сигналы. Источник: NRS 484B.560; Руководство коммерческого водителя Невады."},"77":{"q":"Когда транспортное средство с негабаритным грузом, движущееся по разрешению NDOT, как правило, обязано прекратить движение в Неваде?","options":["Только между 12:00 и 13:00 каждый день","Всякий раз, когда установленное ограничение скорости превышает 65 mph","В тёмное время суток, если только разрешение или специальные инструкции не разрешают ночное движение","Только в пределах городской черты в любое время"],"explanation":"Условия разрешения NDOT на негабаритный груз в Неваде, как правило, запрещают движение в тёмное время суток и могут ограничивать движение в выходные и праздничные дни, если только разрешение или специальные инструкции прямо это не разрешают. Источник: положения о разрешениях NDOT Over Dimensional Vehicle."},"78":{"q":"Какое ведомство выдаёт коммерческие водительские права (CDL) в Неваде?","options":["Департамент транспортных средств Невады (Nevada DMV)","Федеральная администрация безопасности автотранспортных перевозчиков (FMCSA)","Департамент транспорта Невады (NDOT)","Дорожный патруль Невады"],"explanation":"В Неваде Департамент транспортных средств (DMV) выдаёт CDL и CLP; FMCSA устанавливает федеральные стандарты, но не выдаёт права. Источник: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"79":{"q":"Сколько действует коммерческое ученическое разрешение Невады (CLP)?","options":["180 дней","30 дней","60 дней","1 год"],"explanation":"Невада выдаёт CLP, действительные в течение 180 дней. Источник: страница Nevada DMV Commercial Learner Permits (dmv.nv.gov/clp.htm)."},"80":{"q":"В Неваде каков минимальный срок, в течение которого вы должны иметь CLP, прежде чем сможете сдавать какой-либо экзамен по навыкам CDL?","options":["14 дней","7 дней","30 дней","60 дней"],"explanation":"Невада требует, чтобы вы имели CLP не менее 14 дней до любого экзамена по навыкам, что соответствует федеральному правилу о CLP. Источник: страница Nevada DMV Commercial Learner Permits (dmv.nv.gov/clp.htm)."},"81":{"q":"Экзамен по навыкам CDL в Неваде состоит из трёх частей. Какой набор перечисляет их правильно?","options":["Осмотр транспортного средства (предрейсовый), базовое управление транспортным средством и вождение на дороге","Общие знания, пневматические тормоза и составные транспортные средства","Письменный экзамен, проверка зрения и вождение на дороге","Предрейсовый осмотр, опасные материалы и ночное вождение"],"explanation":"Трёхчастный экзамен по навыкам в Неваде состоит из осмотра транспортного средства (предрейсового), базовых навыков управления и теста вождения на дороге. Источник: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"82":{"q":"Прежде чем впервые подающий заявку на CDL в Неваде сможет сдавать экзамен по навыкам, какое обучение должно быть пройдено?","options":["Базовое обучение водителей начального уровня (ELDT) от провайдера, указанного в Федеральном реестре провайдеров обучения (Federal Training Provider Registry)","Курс безопасного вождения, одобренный судами","Курс общих знаний только онлайн","Курс сертификации по первой помощи и сердечно-лёгочной реанимации"],"explanation":"Федеральные правила ELDT применяются в Неваде: заявители должны пройти обучение у провайдера из Федерального реестра провайдеров обучения, прежде чем сдавать экзамен по навыкам. Источник: Nevada DMV (dmv.nv.gov/cdl.htm); 49 CFR Part 380."},"83":{"q":"Из скольких категорий самосертификации должен выбрать коммерческий водитель Невады при подаче заявки на CLP или CDL?","options":["Четыре","Две","Три","Пять"],"explanation":"Существует четыре категории самосертификации: межштатные неосвобождённые, межштатные освобождённые, внутриштатные неосвобождённые и внутриштатные освобождённые. Источник: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"84":{"q":"Какая категория самосертификации, как правило, требует от водителя предоставления медицинского сертификата DOT?","options":["Межштатные неосвобождённые","Межштатные освобождённые","Внутриштатные освобождённые","Освобождённый государственный служащий"],"explanation":"Неосвобождённые межштатные водители подпадают под правила физической квалификации 49 CFR Part 391 и должны иметь/предоставить медицинский сертификат (Medical Examiner's Certificate); освобождённые категории не обязаны этого делать. Источник: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"85":{"q":"Какую форму медицинского сертификата Nevada DMV принимает для медицинской сертификации CDL?","options":["Медицинский сертификат MCSA-5876 (Medical Examiner's Certificate)","Форму DOT HS-2","Медицинский отказ Nevada CDL-9","Любое письмо, подписанное врачом"],"explanation":"Nevada DMV принимает только медицинский сертификат MCSA-5876 (Medical Examiner's Certificate). Источник: страницы медицинской сертификации Nevada DMV CDL (dmv.nv.gov/cdlmedical.htm)."},"86":{"q":"В соответствии с модернизированным процессом Невады, как обычно медицинский сертификат неосвобождённого водителя попадает в DMV?","options":["Сертифицированный медицинский эксперт загружает его в электронном виде в Национальный реестр FMCSA, который передаёт его в DMV","Водитель отправляет нотариально заверенную бумажную копию по почте в Карсон-Сити","Работодатель водителя отправляет его по факсу в местное отделение DMV","Водитель сканирует его и отправляет по электронной почте напрямую в DMV"],"explanation":"С 16 июня 2025 года Невада перешла на безбумажную систему: эксперт загружает MEC в электронном виде в FMCSA, которая передаёт его в DMV, поэтому водителям больше не нужно сдавать бумажные карточки. Источник: пресс-релиз Nevada DMV 25013 (dmv.nv.gov)."},"87":{"q":"Кому разрешено проводить медосмотр DOT, который служит основанием для самосертификации неосвобождённого CDL в Неваде?","options":["Провайдеру, указанному в Национальном реестре сертифицированных медицинских экспертов (National Registry of Certified Medical Examiners)","Любой лицензированной медсестре-практику в штате","Обычному семейному врачу заявителя, независимо от статуса в реестре","Технику Nevada DMV на месте проведения экзамена"],"explanation":"Медосмотр должен проводиться провайдером, указанным в Национальном реестре сертифицированных медицинских экспертов; DMV не примет результаты от провайдеров, не включённых в реестр. Источник: медицинские страницы Nevada DMV CDL (dmv.nv.gov/cdlmedical.htm)."},"88":{"q":"Сколько действует стандартный CDL Невады до необходимости продления (для водителя младше 65 лет)?","options":["8 лет","4 года","5 лет","10 лет"],"explanation":"CDL Невады истекает на восьмую годовщину выдачи или продления для водителей младше 65 лет. Источник: Nevada Administrative Code NAC 483.832."},"89":{"q":"Для держателя CDL Невады в возрасте 65 лет и старше, сколько действует CDL?","options":["4 года","8 лет","2 года","6 лет"],"explanation":"CDL, выданный лицензиату 65 лет и старше, истекает на четвёртую годовщину дня рождения лицензиата, а не через стандартные 8 лет. Источник: Nevada Administrative Code NAC 483.832."},"90":{"q":"Каков минимальный возраст для получения CDL Невады для внутриштатного (в пределах Невады) вождения?","options":["18 лет","16 лет","19 лет","21 год"],"explanation":"Вам должно быть не менее 18 лет для получения CDL Невады для внутриштатной эксплуатации. Источник: страницы Nevada DMV Commercial Learner Permits/CDL (dmv.nv.gov/clp.htm, dmv.nv.gov/cdl.htm)."},"91":{"q":"Каков минимальный возраст, необходимый для вождения в межштатной торговле или для получения пассажирских или HazMat-эндорсментов в Неваде?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Межштатная торговля и пассажирские/HazMat-эндорсменты требуют минимального возраста 21 год в Неваде. Источник: страница Nevada DMV CLP (dmv.nv.gov/clp.htm)."},"92":{"q":"Какой тест на знания должен сдать заявитель в Неваде только в том случае, если транспортное средство, которым он будет управлять, оснащено пневматическими тормозами?","options":["Тест на знание пневматических тормозов","Тест на общие знания","Тест по составным транспортным средствам","Тест по опасным материалам"],"explanation":"Тест на знание пневматических тормозов применяется, когда транспортное средство оснащено пневматическими тормозами; провал или пропуск этого теста приводит к ограничению по пневматическим тормозам. Источник: Nevada DMV CDL Licensing (dmv.nv.gov/cdl.htm)."},"93":{"q":"Заявитель в Неваде, который сертифицируется как «внутриштатный освобождённый», как правило, НЕ обязан делать что из перечисленного?","options":["Предоставлять медицинский сертификат DOT","Сдавать тест на общие знания","Иметь CLP перед тестированием","Предоставлять подтверждение личности и места жительства"],"explanation":"Освобождённые водители (например, определённые государственные служащие, пожарные или перевозящие детей из дома в школу) не обязаны предоставлять медицинский сертификат (Medical Examiner's Certificate), хотя работодатели всё же могут требовать прохождения медосмотра. Источник: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"94":{"q":"Прежде чем может быть выдан CLP Невады, какое требование заявитель должен сначала выполнить?","options":["Сдать все необходимые тесты на знания для класса прав и эндорсментов","Пройти тест вождения на дороге","Иметь разрешение в течение 14 дней","Сдать тест на базовое управление транспортным средством"],"explanation":"Чтобы получить CLP, заявитель должен сдать все необходимые тесты на знания для класса прав и эндорсментов; экзамены по навыкам сдаются позже. Источник: страница Nevada DMV Commercial Learner Permits (dmv.nv.gov/clp.htm)."},"95":{"q":"С какого возраста в Неваде применяется ограничение CDL по составным транспортным средствам для автопоездов длиной более 70 футов?","options":["Водители должны быть не моложе 25 лет","Водители должны быть не моложе 18 лет","Водители должны быть не моложе 21 года","Нет возрастного ограничения, связанного с длиной"],"explanation":"Невада требует минимального возраста 25 лет для управления автопоездами длиной более 70 футов. Источник: страница Nevada DMV Commercial Learner Permits (dmv.nv.gov/clp.htm)."},"96":{"q":"Если неосвобождённый держатель CDL Невады допускает истечение медицинской сертификации без нового электронного MEC в базе, каково вероятное последствие?","options":["CDL понижается до некоммерческого статуса до получения действующего MEC","CDL аннулируется навсегда без возможности восстановления","Ничего не происходит до даты продления через 8 лет","Водитель автоматически переклассифицируется как освобождённый"],"explanation":"Без актуального MEC в базе Невада автоматически понижает CDL до некоммерческого статуса до получения действующего электронного MEC. Источник: пресс-релиз Nevada DMV 25013 (dmv.nv.gov)."},"97":{"q":"Какое утверждение лучше всего отражает то, как заявитель должен относиться к сборам за подачу заявки на CDL в Неваде?","options":["Сборы устанавливаются DMV и могут меняться, поэтому заявителям следует уточнить актуальные суммы в DMV перед подачей заявки","Сборы навсегда зафиксированы федеральным законом и никогда не меняются","Тестирование и лицензирование CDL в Неваде всегда бесплатны","Сборы уплачиваются напрямую в Национальный реестр FMCSA"],"explanation":"Сборы, связанные с CDL в Неваде, администрируются DMV и могут изменяться; заявителям следует уточнять актуальные суммы непосредственно в DMV, а не полагаться на фиксированную цифру. Источник: страницы Nevada DMV CDL (dmv.nv.gov/cdl.htm)."}},"tr":{"0":{"q":"Nevada'da bir karayolunda, yük dahil olmak üzere bir aracın işletilebileceği maksimum yükseklik nedir?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"Nevada yasası, yük dahil maksimum araç yüksekliğini, aracın üzerinde durduğu yüzeyden ölçülmek üzere 14 feet olarak belirler (NRS 484D.605)."},"1":{"q":"Nevada karayolunda bir aracın, araç kombinasyonunun veya yükün standart maksimum yasal genişliği nedir?","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"Nevada'da herhangi bir aracın, araç kombinasyonunun, özel hareketli ekipmanın veya yükün yasal maksimum genişliği 102 inches (8 feet 6 inches) olarak belirlenmiştir (NRS 484D.685)."},"2":{"q":"Nevada'da, bir kamuya açık karayolunda işletilen bir aracın herhangi bir tek aksında izin verilen maksimum ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,000 pounds","34,000 pounds"],"explanation":"Nevada, herhangi bir tek aks üzerindeki ağırlığı 20,000 pounds ile sınırlar (NRS 484D.635)."},"3":{"q":"Nevada'daki bir kamuya açık karayolunda, bir aracın herhangi bir tandem aksında izin verilen maksimum ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Nevada, herhangi bir tandem aks üzerindeki ağırlığı 34,000 pounds ile sınırlar (NRS 484D.635)."},"4":{"q":"Nevada'nın Eyaletler Arası Sistem (Interstate System) ve diğer federal destekli karayolları üzerindeki bölümünde, özel izin olmadan izin verilen maksimum brüt araç ağırlığı nedir?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"explanation":"Nevada, Eyaletler Arası ve federal destekli sistemlerde 80,000 pounds brüt ağırlık federal maksimumunu uygular, çünkü bunu düşürmek federal karayolu fonlarını tehlikeye atar (NRS 484D.660; 23 U.S.C. 127)."},"5":{"q":"Nevada'da, özel izin gerekmeden önce bir araç kombinasyonunun maksimum uzunluğu nedir?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"Nevada'da, birbirine bağlı hiçbir araç kombinasyonu, eklentiler dahil, Ulaştırma Departmanı'ndan (Department of Transportation) özel izin alınmadan 70 feet'i aşamaz (NRS 484D.615)."},"6":{"q":"Nevada karayolunda tek bir motorlu kamyonun (düz kamyon) maksimum uzunluğu nedir?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"Nevada'da tek bir motorlu kamyon uzunlukta 40 feet'i aşamaz (NRS 484D.615)."},"7":{"q":"Hangi Nevada kurumu, gabari dışı ve aşırı yüklü (boyut dışı) araç izinlerini düzenler?","options":["Nevada Motorlu Taşıtlar Departmanı (Nevada Department of Motor Vehicles)","Nevada Ulaştırma Departmanı (Nevada Department of Transportation)","Nevada Karayolu Devriyesi (Nevada Highway Patrol)","Her ilçenin ilçe şerifi"],"explanation":"Nevada Ulaştırma Departmanı (NDOT), çevrimiçi Boyut Dışı İzin Sistemi (Overdimensional Permitting System) dahil olmak üzere boyut dışı/aşırı yüklü izinlerini düzenler (NRS 484D.625 ve 484D.685; NDOT)."},"8":{"q":"Nevada karayolunda bir çekici-yarı römork kombinasyonunda, özel izin olmadan yarı römork için izin verilen maksimum uzunluk nedir?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Tek yarı römorklu bir çekici-traktöre, yarı römork 53 feet uzunluğu aşmadığı sürece izin verilir (NRS 484D.615)."},"9":{"q":"Nevada'da iki çekilen birim (ikiz römork) çeken bir çekici-traktör için, özel izin olmadan her römorkun maksimum uzunluğu nedir?","options":["26 feet","28 feet 6 inches","30 feet","33 feet"],"explanation":"Bir yarı römork ve römorklu çekici-traktöre, iki çekilen birimin her biri 28.5 feet uzunluğu aşmadığı sürece izin verilir (NRS 484D.615)."},"10":{"q":"Bir araç pnömatik lastiklerle donatılmıştır. Nevada'da, bir dış lastiğin dışından karşı dış lastiğin dışına kadar ölçülen maksimum toplam genişlik nedir?","options":["102 inches","104 inches","108 inches","120 inches"],"explanation":"Pnömatik lastikli araçlar için, lastikten lastiğe ölçülen genişlik 108 inches'a ulaşabilir, ancak gövde veya yükün kendisi yine de 102 inches'ı aşamaz (NRS 484D.685)."},"11":{"q":"Nevada yasasına göre, bir direksiyon aksında izin verilen lastik genişliğinin inçi başına maksimum ağırlık nedir?","options":["450 pounds per inch","500 pounds per inch","550 pounds per inch","600 pounds per inch"],"explanation":"Nevada, direksiyon aksı yüklemesini lastik genişliğinin inçi başına 600 pounds ile sınırlar (ve diğer tüm aksler için inç başına 500 pounds) (NRS 484D.635)."},"12":{"q":"Nevada yasasına göre, direksiyon aksı dışındaki akslerde izin verilen lastik genişliğinin inçi başına maksimum ağırlık nedir?","options":["400 pounds per inch","500 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"Direksiyon aksı dışındaki tüm aksler için Nevada, yüklemeyi lastik genişliğinin inçi başına 500 pounds ile sınırlar (inç başına 600 pounds yalnızca direksiyon aksında izin verilir) (NRS 484D.635)."},"13":{"q":"Nevada, ardışık aksler grubu üzerindeki maksimum ağırlığı belirlemek için federal köprü formülünü (bridge formula) uygular. İki ardışık tandem aks seti, grubun ilk ve son aksı arasındaki mesafe en az kaç feet ise her biri 34,000 pounds taşıyabilir?","options":["30 feet","33 feet","36 feet","40 feet"],"explanation":"Nevada'da uygulandığı şekliyle federal köprü formülüne göre, ilk ve son aks arasındaki toplam mesafe 36 feet veya daha fazla ise iki ardışık tandem aks seti her biri 34,000 pounds taşıyabilir (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)."},"14":{"q":"Bir taşıyıcı, Nevada karayolunda 110 inches genişliğinde bir yük taşımak istiyor. Ne gerekir?","options":["Hiçbir şey, çünkü yasal genişlik dahilindedir","Nevada Ulaştırma Departmanı'ndan (Nevada Department of Transportation) bir gabari dışı izni","Yalnızca her köşede kehribar rengi uyarı ışıkları","Nevada Karayolu Devriyesi'nden (Nevada Highway Patrol) bir muafiyet"],"explanation":"102 inches yasal sınırından daha geniş bir yük gabari dışıdır ve taşınabilmesi için önce NDOT'tan bir boyut dışı izni gerektirir (NRS 484D.685; NDOT)."},"15":{"q":"Nevada'nın Eyaletler Arası Sistem'de (Interstate System) uyguladığı federal köprü formülünün (bridge formula) amacı nedir?","options":["Ağır kamyonlar için maksimum hızı belirler","Bir aks grubundaki ağırlığı, aks sayısına ve aralarındaki mesafeye göre sınırlar","Ticari araçlar için tescil ücretini belirler","Maksimum römork uzunluğunu belirler"],"explanation":"Federal köprü formülü, herhangi bir ardışık iki veya daha fazla aks grubunun taşıyabileceği brüt ağırlığı, köprüleri korumak için aks sayısına ve grubun dış aksleri arasındaki mesafeye göre sınırlar (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)."},"16":{"q":"Saman veya saman gibi gevşek yığılmış (balyalanmamış) tarım ürünlerini dökme halinde taşıyan bir araca Nevada'da genişlik istisnası tanınır. O yük ve onun tutma rafları için izin verilen maksimum genişlik nedir?","options":["102 inches","108 inches","114 inches","120 inches"],"explanation":"Nevada, gevşek yığılmış tarım ürünlerinden (sandıklanmamış, balyalanmamış, kutulanmamış veya çuvallanmamış) oluşan bir yükün artı herhangi bir tutma rafının, 102 inches standardından bir istisna olarak 120 inches genişliğe kadar olmasına izin verir (NRS 484D.705)."},"17":{"q":"Nevada, bir balya saman yükünün normal 14-feet yükseklik sınırını aşmasına izin verir. Bir balya saman yükü için izin verilen maksimum yükseklik nedir?","options":["14 feet 6 inches","15 feet","16 feet","17 feet"],"explanation":"Genel yükseklik sınırı 14 feet olsa da, Nevada bir balya saman yükünün 15 feet yüksekliğe kadar taşınmasına izin verir (NRS 484D.605)."},"18":{"q":"NDOT, maksimum yasal ağırlıkta işletilen araçların belirli bir karayolu, köprü veya caddeye önemli ölçüde gerilim yaratma olasılığının yüksek olduğunu belirlediğinde, NDOT veya yerel yönetim organı ne yapabilir?","options":["Yolu tüm ticari trafiğe kalıcı olarak kapatabilir","O karayolu, yol veya caddedeki izin verilen ağırlık sınırlarını düşürebilir","Tüm kamyonların üçüncü bir römork eklemesini zorunlu kılabilir","Telafi etmek için eyalet genelindeki tek aks sınırını artırabilir"],"explanation":"NDOT ve yerel yönetim organları, maksimum izin verilen ağırlıktaki araçların önemli ölçüde yapısal gerilime neden olma olasılığının yüksek olduğu herhangi bir karayolu, yol veya caddedeki ağırlık sınırlarını düşürebilir (NRS 484D.660)."},"19":{"q":"Bir motorlu taşıyıcı, Nevada'da rutin taşımalar için yıllık bir aşırı yük iznine ihtiyaç duyar. NDOT yönergesine göre, taşıyıcının boyut dışı izin sistemi üzerinden ne kadar önceden başvurması tavsiye edilir?","options":["En az 24 saat önceden","En az 7 days önceden","En az 30 days önceden","En az 90 days önceden"],"explanation":"NDOT, izin sahiplerine istenen bir hareketten en az 30 days önce veya mevcut bir yıllık iznin süresi dolmadan önce plan yapmalarını tavsiye eder; başvurular NDOT Boyut Dışı İzin Sistemi (Overdimensional Permitting System) üzerinden gönderilir (NDOT; NRS 484D.625)."},"20":{"q":"Nevada'da, çekilen birimin GVWR'ı 10,000 lbs'ı aştığında, brüt kombinasyon ağırlık derecesi 26,000 lbs'ı aşan bir araç kombinasyonunu işletmek için hangi sınıf ticari sürücü ehliyeti (CDL) gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Nevada, römorkun/çekilen birimin 10,000 lbs GVWR'ı aştığı, 26,000 lbs üzerindeki kombinasyon araçları için Class A CDL gerektirir. Kaynak: Nevada DMV CDL-051 'Commercial Driver License Information' ve dmv.nv.gov/cdlcertify.htm (License Classes)."},"21":{"q":"Hangi Nevada CDL sınıfı, büyük bir otobüs veya düz kamyon gibi GVWR'ı 26,001 lbs veya daha fazla olan ve 10,000 lbs'ı aşmayan bir birim çeken herhangi bir tek aracı kapsar?","options":["Class A","Class B","Class C","Class M"],"explanation":"Bir Nevada Class B CDL, 10,001 lbs altında bir birim çeken 26,001 lbs veya daha fazla (otobüsler, büyük kamyonlar) tek araçları kapsar. Kaynak: Nevada DMV cdlcertify.htm ve CDL-051."},"22":{"q":"Nevada kurallarına göre, Class A veya B boyut sınırlarını karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış veya plakart gerektiren tehlikeli maddeler taşıyan bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class P"],"explanation":"Nevada'nın Class C CDL'i, 16 veya daha fazla yolcu (sürücü dahil) taşıyan veya tehlikeli madde plakartı gerektiren, A/B ağırlık sınırlarının altındaki araçlar içindir. Kaynak: Nevada DMV cdlcertify.htm ve CDL-051."},"23":{"q":"Eyaletler arası ticarette bir ticari motorlu taşıt işletmek için Nevada CDL'i verilmesinin minimum yaşı nedir?","options":["18 years","19 years","21 years","25 years"],"explanation":"Nevada, başvuru sahiplerinin eyaletler arası ticarette bir ticari motorlu taşıt işletmek için en az 21 yaşında olmalarını gerektirir. Kaynak: Nevada DMV CDL-051 'Minimum Age'."},"24":{"q":"Nevada'da, 18 ile 20 yaş arasındaki bir başvuru sahibine yalnızca ne tür bir işletme için CDL verilebilir?","options":["Yalnızca eyaletler arası ticaret","Yalnızca eyalet içi ticaret","Yalnızca federal hükümet güzergahları","Yalnızca yolcu taşımacılığı"],"explanation":"Nevada, 18 ila 20 yaşındakilere yalnızca eyalet içi ticaret için CDL verilmesine izin verir; ücret karşılığında yolcu taşıyamaz veya plakart gerektiren tehlikeli madde taşıyamazlar. Kaynak: Nevada DMV CDL-051 'Minimum Age'."},"25":{"q":"Nevada'da, aşırı uzun bir kombinasyon aracını (70 feet) sürmek için gereken onayı almak için minimum yaş nedir?","options":["21 years","23 years","25 years","26 years"],"explanation":"Nevada, 70 feet'lik aşırı uzun bir kombinasyon aracını sürmek için sürücülerin en az 25 yaşında olmalarını gerektirir. Kaynak: Nevada DMV CDL-051 'Minimum Age'; ayrıca bkz. NRS 484D.615 (uzunluk kısıtlamaları)."},"26":{"q":"Bir Nevada Ticari Öğrenci İzni (CLP), verildiği tarihten itibaren ne kadar süre geçerlidir?","options":["60 days","90 days","180 days","1 year"],"explanation":"Bir Nevada CLP, verildiği tarihten itibaren 180 days geçerlidir (yenileme yeniden test gerektirebilir). Kaynak: Nevada DMV dmv.nv.gov/clp.htm ve CDL-051 'CLP Conditions'."},"27":{"q":"Nevada ve federal kurallara göre, sahibinin CDL beceri testine girebilmesi için bir Ticari Öğrenci İzni'nin ne kadar süre tutulması gerekir?","options":["En az 7 days","En az 14 days","En az 21 days","En az 30 days"],"explanation":"Bir Nevada CLP, federal gereklilikle uyumlu olarak, beceri testinden önce en az 14 days tutulmalıdır. Kaynak: Nevada DMV clp.htm ve CDL-051 'CLP Conditions'."},"28":{"q":"Bir CLP veya CDL vermeden önce, Nevada DMV bir başvuru sahibinin kaç adet Nevada ikametgah kanıtı sunmasını gerektirir?","options":["Bir adet","İki adet","Üç adet","Kanıt gerekmez"],"explanation":"Nevada, başvuru sahibinin adını ve Nevada ikametgah adresini gösteren iki adet ikametgah kanıtı gerektirir. Kaynak: Nevada DMV CDL-051 'Proof of residency'."},"29":{"q":"Bir CDL için başvuru sahibinin Sosyal Güvenlik numarasının kanıtı olarak Nevada DMV tarafından hangi belge kabul edilebilir?","options":["Bir seçmen kayıt kartı","Numaranın tamamını gösteren bir Sosyal Güvenlik kartı, W-2 veya maaş bordrosu","Bir Nevada araç tescili","İmzalı bir kişisel yeminli beyan"],"explanation":"Nevada, Sosyal Güvenlik numarasının kanıtı olarak SSN'in tamamını listeleyen bir Sosyal Güvenlik kartı, W-2, 1099 veya maaş bordrosunu kabul eder. Kaynak: Nevada DMV CDL-051 'Proof of Your Social Security Number'."},"30":{"q":"ABD doğumlu bir CDL başvuru sahibi için, Nevada DMV hangi belgeyi ek kimlik kanıtı olarak kabul eder?","options":["Onaylı bir doğum belgesi veya ABD pasaportu","Bir lise diploması","Bir kütüphane kartı","Bir kredi kartı ekstresi"],"explanation":"Nevada, ABD doğumlu başvuru sahipleri için ek kimlik kanıtı olarak onaylı bir doğum belgesini (veya özetini) ya da bir ABD pasaportunu kabul eder; belgeler orijinal olmalıdır. Kaynak: Nevada DMV CDL-051 'Additional Proof of Identity'."},"31":{"q":"Amerika Birleşik Devletleri dışında doğmuş bir CDL başvuru sahibi, yasal varlığını kanıtlamak için Nevada DMV'ye aşağıdakilerden hangisini sunmalıdır?","options":["Bir yabancı sürücü ehliyeti","I-94 damgalı geçerli süresi dolmamış bir yabancı pasaport, Daimi İkamet kartı veya Vatandaşlık Belgesi","Bir konsolosluk kartviziti","Herhangi bir ülkeden bir öğrenci kimliği"],"explanation":"Nevada, yabancı doğumlu başvuru sahiplerinin geçerli süresi dolmamış bir yabancı pasaport (I-94 damgalı), bir Daimi İkamet kartı veya bir Vatandaşlık Belgesi göstermelerini gerektirir. Kaynak: Nevada DMV CDL-051 'Additional Proof of Identity'."},"32":{"q":"Plakart gerektiren miktarlarda tehlikeli madde taşımak için hangi Nevada CDL onayı gereklidir?","options":["N onayı","T onayı","H onayı","P onayı"],"explanation":"Nevada'da plakart gerektiren tehlikeli madde (hazmat) taşımak için H (Hazardous Materials) onayı gereklidir. Kaynak: Nevada DMV CDL-051 'Endorsements' ve dmv.nv.gov/cdl.htm."},"33":{"q":"Bir CDL ve geçerli kimliğe sahip olmanın yanı sıra, HazMat (H) onayı verilmeden önce bir Nevada başvuru sahibinin neyi tamamlaması gerekir?","options":["Bir defansif sürüş kursu","Parmak izi tabanlı bir geçmiş kontrolü","İkinci bir yol beceri testi","Bir 70-feet uzunluk onayı"],"explanation":"Nevada, başvuru sahibinin parmak izi tabanlı (TSA) bir geçmiş kontrolünü geçmesini gerektirir; Hazmat bilgi testi, geçmiş kontrolü tamamlanana kadar yapılamaz. Kaynak: Nevada DMV CDL-051 'Hazmat Endorsement'."},"34":{"q":"Kalıcı olarak monte edilmiş bir dökme tankta sıvı veya gaz halindeki maddeleri taşıyan bir tank aracını işletmek için hangi Nevada CDL onayı gereklidir?","options":["T onayı","N onayı","S onayı","X onayı"],"explanation":"Nevada'da tank araçlarını işletmek için N (Tank Vehicle) onayı gereklidir. Kaynak: Nevada DMV CDL-051 'Endorsements'."},"35":{"q":"Bir Nevada ticari ehliyetinde, X onayı neyi belirtir?","options":["İkili/üçlü römork yetkisi","Birleşik bir HazMat ve Tanker (Hazmat Tanker) onayı","Bir okul otobüsü onayı","Bir aşırı uzun araç onayı"],"explanation":"Nevada, X'i Hazmat Tanker onayı olarak listeler (H ve N gerekliliklerini birleştirir). Kaynak: Nevada DMV CDL-051 'Endorsements'."},"36":{"q":"Bir sürücünün ikili veya üçlü römork çekmesi için Nevada hangi onayı gerektirir?","options":["P onayı","S onayı","T onayı","N onayı"],"explanation":"Nevada'da ikili veya üçlü römork çekmek için T (Double/Triple Trailers) onayı gereklidir. Kaynak: Nevada DMV CDL-051 'Endorsements'."},"37":{"q":"Nevada'da bir devlet okulu otobüsü sürmek isteyen bir sürücünün hangi onay kombinasyonuna sahip olması gerekir?","options":["P ve S onayları","N ve T onayları","H ve X onayları","Yalnızca S onayı"],"explanation":"Bir Nevada okul otobüsü sürücüsü, her biri ek bilgi ve beceri testi gerektiren hem Yolcu (P) hem de Okul Otobüsü (S) onaylarına sahip olmalıdır. Kaynak: Nevada DMV CDL materyalleri; Nevada School Bus Driver Training Manual (P ve S için ELDT)."},"38":{"q":"Başlangıç seviyesindeki bir Nevada ticari sürücüsü, gerekli Başlangıç Seviyesi Sürücü Eğitimi'ni (ELDT) nerede tamamlamalıdır?","options":["Herhangi bir lisanslı Nevada işletmesi","Federal Eğitim Sağlayıcı Sicili'nde (Training Provider Registry) listelenen bir sağlayıcı","İlçe şerifinin ofisi","Sürücünün seçtiği bir çevrimiçi kurs"],"explanation":"Nevada, başlangıç seviyesindeki ticari sürücülerin ELDT'yi federal FMCSA Eğitim Sağlayıcı Sicili'nde (Training Provider Registry) listelenen bir sağlayıcıdan tamamlamalarını gerektirir. Kaynak: Nevada DMV CDL-051 'Entry Level Driver Training (ELDT)'; 49 CFR Part 380."},"39":{"q":"Nevada DMV ile öz beyanda bulunurken, yalnızca Nevada içinde araç kullanan ve (federal Part 391 değil) eyalet fiziksel yeterlilik standartlarına tabi olan bir CDL sahibine hangi kategori uygulanır?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Interstate-Excepted"],"explanation":"Non-Excepted Intrastate, yalnızca Nevada içinde çalışan ve eyalet sürücü yeterlilik standartlarına tabi olan sürücülere uygulanır. Kaynak: Nevada DMV dmv.nv.gov/cdlcertify.htm (öz beyan kategorileri); 49 CFR 383.71."},"40":{"q":"Nevada'da bir ticari motorlu taşıt (CMV) işletirken, bir CDL sürücüsü hangi kan alkol konsantrasyonunda (BAC) yasal olarak sarhoş kabul edilir ve büyük bir suç işler?","options":["yüzde 0.04 veya daha yüksek","yüzde 0.08 veya daha yüksek","yüzde 0.02 veya daha yüksek","yüzde 0.10 veya daha yüksek"],"explanation":"Nevada, federal CMV standardını uygular: bir CMV'yi yüzde 0.04 veya daha fazla BAC ile işletmek, ehliyet iptaline yol açan büyük bir suçtur (CDL olmayan bir sürücünün herhangi bir araçtaki yüzde 0.08'lik genel sınırı yine de geçerlidir). Kaynak: Nevada Commercial Driver Handbook (ehliyet iptalleri) ve 49 CFR 383.51."},"41":{"q":"Nevada'nın zımni rıza (implied-consent) yasası uyarınca, bir CDL sürücüsü yasal olarak talep edildiğinde kan, nefes veya idrar kimyasal testine girmeyi reddederse ne olur?","options":["Sürücünün ehliyeti otomatik olarak iptal edilir ve reddetme başlı başına ehliyet iptaline yol açan büyük bir suçtur","Sürücü daha sonra mahkemede DUI'den mahkum edilmedikçe hiçbir şey olmaz","İlk reddetme için yalnızca yazılı bir uyarı verilir","Sürücü, ehliyet işlemi olmadan 250 dolarlık bir hukuki ceza öder"],"explanation":"Nevada'da araç kullanarak bir CDL sahibi teste zımni rıza vermiş olur; reddetme, DMV tarafından otomatik bir ehliyet iptalini tetikler ve sürücü daha sonra beraat etse bile CDL'i diskalifiye eden büyük bir suç sayılır. Kaynak: Nevada zımni rıza yasaları (NRS Chapter 484C) ve Nevada Commercial Driver Handbook."},"42":{"q":"Plakart gerektiren tehlikeli madde taşımazken işlenen ilk büyük suç (DUI veya test reddi gibi) için, bir Nevada CDL'i ne kadar süre diskalifiye edilir?","options":["1 year","60 days","3 years","6 months"],"explanation":"İlk büyük suç, CDL'i en az 1 year süreyle diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook (ehliyet iptalleri) ve 49 CFR 383.51."},"43":{"q":"İlk büyük suç (DUI gibi), sürücü plakart gerektiren tehlikeli madde taşıyan bir CMV işletirken işlenirse, Nevada CDL diskalifikasyonu şuna çıkar:","options":["3 years","1 year","5 years","Ömür boyu"],"explanation":"Plakart gerektiren tehlikeli madde taşırken işlenen ilk büyük suç, standart 1 year yerine 3 years diskalifikasyon taşır. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"44":{"q":"İKİNCİ bir büyük suç için (örneğin, bir CMV'de ikinci bir DUI mahkumiyeti) Nevada CDL diskalifikasyon süresi nedir?","options":["Ömür boyu diskalifikasyon","10 years","3 years","5 years"],"explanation":"İkinci bir büyük suç, ömür boyu CDL diskalifikasyonu ile sonuçlanır (en az 10 years sonra sınırlı bir yeniden işlerlik yalnızca belirli koşullar altında mevcut olabilir). Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"45":{"q":"Nevada'daki bir CDL sürücüsü, 3 yıllık bir süre içinde ayrı olaylarda İKİ ciddi trafik ihlalinden mahkum edilir. CDL şu süreyle diskalifiye edilir:","options":["60 days","30 days","120 days","1 year"],"explanation":"3 years içinde (ayrı olaylarda) iki ciddi trafik ihlali, CDL'i 60 days süreyle diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"46":{"q":"Nevada'daki bir CDL sürücüsü, 3 yıllık bir süre içinde ayrı olaylarda ÜÇ ciddi trafik ihlalinden mahkum edilir. CDL şu süreyle diskalifiye edilir:","options":["120 days","60 days","1 year","90 days"],"explanation":"3 years içinde (ayrı olaylarda) üç ciddi trafik ihlali, daha önceki herhangi bir 60-günlük diskalifikasyona ek olarak uygulanmak üzere CDL'i 120 days süreyle diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"47":{"q":"Aşağıdakilerden hangisi Nevada'da CDL diskalifikasyon amaçları için CİDDİ bir trafik ihlali sayılır?","options":["Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","Belirtilen sınırın 5 mph üzerinde hız yapmak","Hareketsiz bir park ihlali","Süresi dolmuş bir araç tesciliyle araç kullanmak"],"explanation":"Belirtilen sınırın 15 mph veya daha fazla üzerinde olarak tanımlanan aşırı hız, listelenen ciddi bir trafik ihlalidir. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"48":{"q":"Nevada CDL kuralları uyarınca hangi suç grubunun tamamı CİDDİ trafik ihlali olarak sınıflandırılır?","options":["Dikkatsiz sürüş, çok yakın takip ve uygunsuz veya düzensiz şerit değiştirmeler","DUI, kaza yerini terk etme ve bir suçta CMV kullanma","Kimyasal testi reddetme, ikinci bir DUI ve ölümcül bir vur-kaç","Aşırı yük izni ihlali, süresi dolmuş sağlık kartı ve ödenmemiş geçiş ücretleri"],"explanation":"Dikkatsiz sürüş, çok yakın takip ve uygunsuz veya düzensiz şerit değiştirmelerin tamamı ciddi trafik ihlalleridir. Listelenen diğer suçlar büyük suçlardır veya ciddi ihlal listesinin bir parçası değildir. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"49":{"q":"Nevada'da bir CMV'yi doğru sınıf CDL veya ticari öğrenci izni olmadan ya da yanınızda bulundurmadan kullanmak şu şekilde sınıflandırılır:","options":["Bir ciddi trafik ihlali","Bir büyük suç","Bir hizmet dışı emri (out-of-service) ihlali","Diskalifiye etmeyen bir evrak hatası"],"explanation":"Bir CMV'yi doğru CDL/CLP olmadan veya yanında bulundurmadan işletmek, 60-günlük/120-günlük diskalifikasyonlara doğru sayılan ciddi bir trafik ihlalidir. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"50":{"q":"Bir CMV'de demiryolu-karayolu hemzemin geçit ihlalinin İLK mahkumiyeti için, Nevada CDL'i en az şu süreyle diskalifiye edilir:","options":["60 days","30 days","120 days","1 year"],"explanation":"İlk bir demiryolu-karayolu hemzemin geçit ihlali, CDL'i 60 days'den az olmamak üzere diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"51":{"q":"3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali, bir Nevada CDL'ini en az şu süreyle diskalifiye eder:","options":["120 days","60 days","1 year","90 days"],"explanation":"Herhangi bir 3 years süre içinde ikinci bir hemzemin geçit ihlali, CDL'i 120 days'den az olmamak üzere diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"52":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali, bir Nevada CDL'ini en az şu süreyle diskalifiye eder:","options":["1 year","120 days","180 days","60 days"],"explanation":"Herhangi bir 3 years süre içinde üçüncü bir hemzemin geçit ihlali, CDL'i 1 year'dan az olmamak üzere diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"53":{"q":"Bir sürücü, plakart gerektiren tehlikeli madde taşırken veya 16 ya da daha fazla yolcu için tasarlanmış bir aracı işletirken bir hizmet dışı emrini ihlal ederse, İLK suç diskalifikasyonu şudur:","options":["180 days'den az ve 2 years'dan fazla olmamak üzere","90 days'den az ve 1 year'dan fazla olmamak üzere","1 year'dan az ve 5 years'dan fazla olmamak üzere","Tam olarak 120 days"],"explanation":"Plakart gerektiren hazmat taşırken veya 16 ve daha fazla yolcu taşırken işlenen ilk bir OOS emri ihlali, CDL'i 180 days'den az ve 2 years'dan fazla olmamak üzere diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"54":{"q":"Diskalifiye edilmenin yanı sıra, Nevada'da bir hizmet dışı emrini ihlal etmekten mahkum olan bir sürücü en az şu kadar federal bir hukuki cezayla karşı karşıya kalır:","options":["$1,000","$250","$500","$2,750"],"explanation":"Bir OOS emrini ihlal eden bir sürücü, diskalifikasyondan ayrı olarak en az $1,000 (ve $2,500'a kadar) bir hukuki cezaya tabidir. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51."},"55":{"q":"Nevada yasasına göre (NRS 484B.165), araç kullanırken elde tutulan bir cep telefonu kullanmak veya mesajlaşmak İLK suç için hangi hukuki cezayı taşır?","options":["$50","$100","$250","$500"],"explanation":"Nevada'nın elde tutulan/mesajlaşma yasası (NRS 484B.165), ilk suç için $50, ikincisi için $100 ve 7 years içinde üçüncüsü için $250 hukuki ceza belirler; ilk suç bir hareketli ihlal olarak değerlendirilmez. Kaynak: NRS 484B.165."},"56":{"q":"Bir CDL sahibi için, bir CMV işletirken elde tutulan bir telefon kullanmak veya mesajlaşmak, Nevada/federal kurallar uyarınca ticari ehliyeti nasıl etkiler?","options":["Tekrarlanırsa 60 veya 120 günlük bir diskalifikasyona yol açabilen ciddi bir trafik ihlalidir","İlk suçta 1 yıllık bir diskalifikasyona neden olan büyük bir suçtur","Yalnızca $50 para cezasıyla sonuçlanır ve CDL üzerinde hiçbir etkisi yoktur","90 günlük bir diskalifikasyon taşıyan bir hizmet dışı ihlalidir"],"explanation":"Bir CMV kullanırken mesajlaşmak veya elde tutulan bir cep telefonu kullanmak ciddi bir trafik ihlalidir; 3 years içinde iki tanesi CDL'i 60 days ve 3 years içinde üç tanesi 120 days süreyle diskalifiye eder. Kaynak: Nevada Commercial Driver Handbook ve 49 CFR 383.51 / 392.80-392.82."},"57":{"q":"Nevada, temel kural yasası (NRS 484B.600) uyarınca bir hız ihlali için para cezasını sınırın üzerindeki saatte mil başına hangi miktarla sınırlar?","options":["Sınırın üzerindeki her mph için $20","Sınırın üzerindeki her mph için $25","Sınırın üzerindeki her mph için $10","Sınırın üzerindeki her mph için $50"],"explanation":"Nevada, hız para cezasını sürücünün belirtilen sınırın üzerinde gittiği saatte her mil için $20 ile sınırlar; bir CDL sahibi için, 15+ mph üzerinde hız yapmak, para cezası miktarından bağımsız olarak ciddi bir trafik ihlali olmaya devam eder. Kaynak: NRS 484B.600 ve Nevada Commercial Driver Handbook."},"58":{"q":"Nevada'nın Move Over (Şerit Değiştir) yasası uyarınca, bir karayolunda yanıp sönen ışıklar yakan, duran bir acil durum aracına, çekiciye veya NDOT aracına yaklaştığınızda ne yapmalısınız?","options":["Makul bir hıza yavaşlayın, dikkatli ilerleyin ve mümkünse duran araca bitişik olmayan bir şeride geçin","Acil durum aracının ışıkları kapanana kadar tamamen durun","Belirtilen hız sınırını koruyun ancak geçerken korna çalın","Sağ banket üzerine geçin ve bir görevlinin sizi geçirmesi için beklesin"],"explanation":"Nevada'nın Move Over yasası (NRS 484B.607), sürücülerin hızlarını makul ve uygun bir orana düşürmesini, dikkatli ilerlemesini, durmaya hazır olmasını ve mümkünse duran araca hemen bitişik olmayan bir şeride geçmesini gerektirir. Yetkili acil durum araçları ile yanıp sönen sarı veya yanıp sönmeyen mavi ışıklar yakan araçlar (NDOT araçları dahil) için geçerlidir. Kaynak: NRS 484B.607."},"59":{"q":"Fiziksel bir bariyer veya ayırıcı bölümle ayrılmış bir Nevada bölünmüş karayolunda, DİĞER yolda duran bir okul otobüsü çocukları almak için yanıp sönen kırmızı ışıklar yakıyor. Sizin yönünüzdeki bir sürücü ne yapmalıdır?","options":["Bölünmemiş yoldaki gibi, kırmızı ışıklar yanıp sönmeyi bırakana kadar durun","Otobüs bölünmüş bir karayolunun diğer yolunda bulunduğu için durmaya gerek yoktur","15 mph'ye yavaşlayın ve uzak şeritten dikkatli geçin","Yalnızca çocuklar refüjü geçerken görünür durumdaysa durun"],"explanation":"NRS 484B.353 uyarınca, bölünmüş bir karayolundaki bir aracın sürücüsünün, diğer yolda bulunan bir okul otobüsüyle karşılaşırken veya onu geçerken durması gerekmez. Nevada, bölünmüş karayolunu fiziksel bir bariyer veya ayırıcı bölümle ayrılmış bir yol olarak tanımlar; dolayısıyla bu istisna, yalnızca bir orta çizgi veya dönüş şeridi değil, gerçek bir bölünmüş karayolu gerektirir. Kaynak: NRS 484B.353."},"60":{"q":"Çocuk taşıyan bir Nevada okul otobüsü, yolcu taşıyan bir otobüs veya levhalı (placarded) tehlikeli madde aracı, durması gereken bir demiryolu hemzemin geçidine yaklaştığında, en yakın raya hangi mesafe içinde durmalıdır?","options":["En yakın raydan 5 feet'ten az ve 25 feet'ten fazla olmamak üzere","En yakın raydan 25 feet'ten az ve 75 feet'ten fazla olmamak üzere","En yakın raydan 15 feet'ten az ve 50 feet'ten fazla olmamak üzere","En yakın raydan 50 feet'ten az ve 100 feet'ten fazla olmamak üzere"],"explanation":"NRS 484B.560, yolcu taşıyan bir otobüsün, çocuk taşıyan bir okul otobüsünün veya levhalı tehlikeli madde taşıyan bir aracın, hemzemin geçişten önce en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durmasını gerektirir. Kaynak: NRS 484B.560."},"61":{"q":"Nevada'da, bir demiryolu hemzemin geçidinde tamamen durması GEREKMEYEN ticari bir motorlu taşıtın, geçişten önce yine de belirli bir yükümlülüğü vardır. Bu nedir?","options":["Geçidi mümkün olduğunca hızlı temizlemek için karayolu hızını koruyun","Durun, el frenini çekin ve dinlemek için camı indirin","Korna iki kez çalın ve yavaşlamadan ilerleyin","Hızı azaltın ve rayların yaklaşan herhangi bir trenden arındırıldığını teyit edin"],"explanation":"NRS 484B.560, başka türlü durması gerekmeyen ticari bir motorlu taşıtın (49 C.F.R. 383.5'te tanımlandığı gibi), hemzemin geçişten önce hızını azaltması ve rayların yaklaşan herhangi bir trenden veya ray üstü ekipmandan arındırıldığını teyit etmesi gerektiğini öngörür. Kaynak: NRS 484B.560."},"62":{"q":"Herhangi bir Nevada karayolunda belirtilebilecek azami hız sınırı nedir?","options":["65 mil/saat","80 mil/saat","75 mil/saat","85 mil/saat"],"explanation":"NRS 484B.613 uyarınca, NDOT eyalet karayollarında 80 mil/saati aşmayan hız sınırları belirleyebilir ve 80 mph, Nevada'da bulunan en yüksek belirtilen sınırdır (belirlenmiş kırsal Eyaletlerarası Otoyol kesimlerinde). Kaynak: NRS 484B.613; NRS 484B.617."},"63":{"q":"Nevada yasaları, kamyonlar için binek otomobillerin sınırından daha düşük tek bir eyalet genelinde azami hız sınırı belirler mi?","options":["Evet, kamyonlar eyaletin her yerinde 55 mph ile sınırlıdır","Evet, kamyonlar tüm eyaletlerarası otoyollarda 60 mph ile sınırlıdır","Eyalet genelinde tek bir daha düşük kamyon sınırı yoktur; NDOT, belirtildiği yerde kamyonlar için daha düşük bir sınır belirleyebilir","Evet, kamyonlar her zaman belirtilen otomobil sınırının tam 10 mph altında seyretmelidir"],"explanation":"Bazı eyaletlerin aksine, Nevada eyalet genelinde toptan daha düşük bir kamyon hız sınırı dayatmaz. NRS 484B.613, NDOT'a kamyonlar, gabari dışı araçlar ve otobüsler için, çalışmaların gerektirdiği yerlerde işaretle belirtilmek üzere daha düşük bir hız sınırı belirleme yetkisi verir; aksi takdirde kamyonlar belirtilen sınırı izler. Kaynak: NRS 484B.613."},"64":{"q":"Nevada'da erişimi kontrollü bir karayolunda, bir sürücünün en sol şeritten çıkması ne zaman gerekir?","options":["Yalnızca bir işaret kamyonların sol şeritte bulunmasını özellikle yasakladığında","Hızdan bağımsız olarak, herhangi bir araç arkadan 500 feet içinde olduğunda her zaman","Yalnızca gece karanlık saatlerinde","Belirtilen hız sınırından daha yavaş seyrederken ve arkadan daha hızlı bir araç tarafından geçilirken"],"explanation":"NRS 484B.208, erişimi kontrollü bir karayolunun en sol şeridindeki bir sürücünün, belirtilen hız sınırının altında seyrederken ve daha hızlı bir araç tarafından geçilirken o şeritten çıkmasını gerektirir. İstisnalar arasında sollama, sola dönüşe hazırlanma, yol inşaatı, HOV şeridi kullanımı ve bir şehir veya kasaba içinde seyahat yer alır. Kaynak: NRS 484B.208."},"65":{"q":"İki şeritli, iki yönlü bir Nevada karayolunun banketinde ticari bir aracı durdurduktan sonra, acil durum uyarı cihazlarınızı kaç dakika içinde yerleştirmelisiniz?","options":["10 dakika içinde","5 dakika içinde","15 dakika içinde","30 dakika içinde"],"explanation":"Nevada'nın CMV'ler için uyguladığı federal kural 49 C.F.R. 392.22, karayolunun gidiş kısmında veya banketinde durduktan sonra 10 dakika içinde yansıtıcı üçgenlerin (veya diğer onaylı cihazların) yerleştirilmesini gerektirir. Kaynak: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook."},"66":{"q":"İki şeritli, iki yönlü bir Nevada yolunda, duran bir CMV için üç acil durum uyarı üçgeninizi nereye yerleştirirsiniz (tepe veya viraj yakınında değil)?","options":["10 feet, 50 feet ve 100 feet, hepsi aracın arkasında","Aracın arkasında 25 feet, 75 feet ve 150 feet","Aracın 10 feet arkasında, 100 feet arkasında ve 100 feet önünde","50 feet önde, 50 feet arkada ve biri aracın tavanında"],"explanation":"49 C.F.R. 392.22 uyarınca, iki şeritli, iki yönlü bir yolda bir üçgeni araçtan yaklaşan trafiğe doğru yaklaşık 10 feet uzağa, birini yaklaşık 100 feet arkaya ve birini yaklaşık 100 feet öne yerleştirirsiniz; böylece trafik her iki yönden de uyarılır. Kaynak: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook."},"67":{"q":"Bir Nevada karayolunda, gabari dışı izni gerekmeden önce ticari bir aracın veya yükünün azami yasal genişliği nedir?","options":["96 inches (8 feet)","114 inches (9 feet 6 inches)","120 inches (10 feet)","102 inches (8 feet 6 inches)"],"explanation":"NRS 484D.685, bir aracın, kombinasyonun veya yükün azami yasal genişliğini belirli güvenlik cihazları hariç 102 inches (8 feet 6 inches) olarak belirler. Daha geniş olan her şey gabari dışı izni gerektirir. Kaynak: NRS 484D.685."},"68":{"q":"Bir Nevada karayolundaki bir araç için, yük dahil azami yasal yükseklik nedir?","options":["14 feet","13 feet 6 inches","15 feet","16 feet"],"explanation":"NRS 484D.605, herhangi bir yük dahil yüksekliği 14 feet'i aşan bir aracın bir Nevada karayolunda işletilmesini yasaklar. (Dar bir istisna, balyalanmış samana 15 feet'e kadar izin verir.) Kaynak: NRS 484D.605."},"69":{"q":"Bir Nevada bölünmüş karayolunda veya tek yönlü caddesinde, duran bir CMV'nin arkasındaki EN UZAK acil durum uyarı üçgeni nereye yerleştirilir?","options":["Yaklaşan trafiğe doğru yaklaşık 100 feet","Yaklaşan trafiğe doğru yaklaşık 200 feet","Yaklaşan trafiğe doğru yaklaşık 50 feet","Yaklaşan trafiğe doğru yaklaşık 500 feet"],"explanation":"49 C.F.R. 392.22 uyarınca, tek yönlü veya bölünmüş bir karayolunda üçgenler, aracın arkasında yaklaşan trafiğe doğru yaklaşık 10, 100 ve 200 feet'e yerleştirilir. Kaynak: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook."},"70":{"q":"Nevada yasalarına göre, (bir istisna olmadığı sürece) her demiryolu hemzemin geçidinde DURMASI gereken araç hangisidir?","options":["Levhasız boş bir açık kasa kamyon (flatbed)","10.000 pound altında bir dağıtım minibüsü","Küçük bir römork çeken bir binek otomobil","Çocuk taşıyan bir okul otobüsü"],"explanation":"NRS 484B.560, yolcu taşıyan otobüslerin, çocuk taşıyan okul otobüslerinin ve levhalı tehlikeli madde taşıyan araçların tüm demiryolu hemzemin geçitlerinde durmasını gerektirir. Levhasız boş bir açık kasa kamyon, hafif bir minibüs veya otomobil, zorunlu durma kategorisinde değildir. Kaynak: NRS 484B.560."},"71":{"q":"Bir Nevada otobüsü veya levhalı aracı bir demiryolu geçidinde durduğunda ve geçmeye hazırlandığında, hangi vites kuralı geçerlidir?","options":["Geçit üzerindeyken vites değiştirmeyi gerektirmeyen bir viteste geçin","Geçidin ortasında en düşük vitese düşürün","Boşa alın ve rayların üzerinden serbest hareketle (kayarak) geçin","Rayları en hızlı şekilde temizlemek için mevcut en yüksek vitesi kullanın"],"explanation":"NRS 484B.560, durduktan sonra sürücünün yalnızca geçişi geçerken vites değiştirmeyi gerektirmeyecek bir viteste geçmesini ve raylar üzerinde vites değiştirmemesini öngörür. Kaynak: NRS 484B.560."},"72":{"q":"Bir Nevada otobüsünü veya levhalı aracı zorunlu demiryolu geçidi durmasından muaf kılan bir İSTİSNA hangi durumdur?","options":["Sürücü programının gerisinde kalıyor","Geçitte bir polis memuru veya işaretçi (flagman) trafiği yönlendiriyor","Geçitte açık konumda olan otomatik bariyerler var","Ray boyunca görüş mesafesi 400 feet'i aşıyor"],"explanation":"NRS 484B.560, bir polis memuru veya işaretçi tarafından kontrol edilen geçitler, terk edilmiş veya muaf olarak işaretlenmiş raylar ve bir ticari bölgedeki belirli sanayi manevraları gibi istisnaları listeler. Açık bir görüş veya geç kalmak bir istisna değildir. Kaynak: NRS 484B.560."},"73":{"q":"Bir Nevada karayolunda, fazla yük izni gerekmeden önce azami yasal brüt araç ağırlığı nedir?","options":["73.280 pound","90.000 pound","80.000 pound","100.000 pound"],"explanation":"Nevada federal sınırı izler: azami brüt ağırlık 80.000 pound olup, köprü formülüne tabi olarak tek bir aksta 20.000 pound ve tandem aksta 34.000 pound'dur. Daha ağır yükler bir NDOT fazla yük izni gerektirir. Kaynak: NRS Chapter 484D (boyut/ağırlık); NDOT Over Dimensional izinleri."},"74":{"q":"Bir sürücü, normal (çalışma bölgesi olmayan) bir karayolunda Nevada'nın Move Over yasasını ilk kez ihlal ediyor. Bu suç genellikle nasıl sınıflandırılır?","options":["Para cezası (yaklaşık $395) ve ceza puanı içeren bir hafif suç (misdemeanor)","Puansız ve para cezasız, hareketsiz bir kabahat","Zorunlu ehliyet iptali gerektiren bir ağır suç (felony)","İlk suç için cezasız, yalnızca bir uyarı"],"explanation":"NRS 484B.607'nin ihlali bir hafif suçtur (misdemeanor); ilk suç genellikle yaklaşık $395 aralığında bir para cezası (ve bir çalışma bölgesinde yaklaşık $790'a kadar) artı ceza puanı taşır. Kaynak: NRS 484B.607."},"75":{"q":"Nevada'da tek bir yarı römork çeken bir çekici-kamyon (truck-tractor) için, yarı römorkun azami yasal uzunluğu nedir (özel izin yok)?","options":["48 feet","57 feet","60 feet","53 feet"],"explanation":"NRS 484D.615, genel 70 feet'lik toplam kombinasyon sınırına bir istisna olarak, yarı römorkun 53 feet'i aşmadığı bir çekici-kamyon ve yarı römork kombinasyonuna izin verir. Kaynak: NRS 484D.615."},"76":{"q":"Bir Nevada okul otobüsünde bir demiryolu geçidinde dururken, uygun mesafede durmanın yanı sıra, sürücü ilerlemeden önce ne yapmalıdır?","options":["Yalnızca geçit sinyal ışıklarını ve bariyerlerini izleyin","Yaklaşan bir tren için ray boyunca her iki yöne dinleyin ve bakın","Otobüsü geçirmek için bir yolcunun dışarı çıkıp işaret vermesini sağlayın","Güvenli olduğunu belirtmek için yalnızca tren kornasına güvenin"],"explanation":"NRS 484B.560, sürücünün dururken, geçişten önce ray boyunca her iki yöne, yaklaşan herhangi bir tren ve bir trenin yaklaştığını gösteren sinyaller için dinlemesini ve bakmasını gerektirir. Sürücülere yalnızca sinyallere güvenmemeleri öğretilir. Kaynak: NRS 484B.560; Nevada Commercial Driver Handbook."},"77":{"q":"Nevada'da bir NDOT izni kapsamında seyahat eden gabari dışı yüklü bir aracın genellikle hareketi durdurması ne zaman gerekir?","options":["Yalnızca her gün öğlen ile 1:00 p.m. arasında","Belirtilen hız sınırı 65 mph'yi aştığında her zaman","İzin veya özel talimatlar gece seyahatine izin vermedikçe, karanlık saatlerinde","Yalnızca tüzel kişiliği olan şehir sınırları içinde, herhangi bir saatte"],"explanation":"Nevada NDOT gabari dışı izin koşulları, izin veya özel talimatlar özellikle yetki vermedikçe genellikle karanlık saatlerinde seyahati yasaklar ve hafta sonu ve tatil hareketini kısıtlayabilir. Kaynak: NDOT Over Dimensional Vehicle izin hükümleri."},"78":{"q":"Nevada'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Nevada Motorlu Taşıtlar Dairesi (DMV)","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)","Nevada Ulaştırma Dairesi (NDOT)","Nevada Otoyol Devriyesi (Nevada Highway Patrol)"],"explanation":"Nevada'da Motorlu Taşıtlar Dairesi (DMV), CDL ve CLP'leri verir; FMCSA federal standartları belirler ancak belgeyi vermez. Kaynak: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"79":{"q":"Bir Nevada Ticari Öğrenci İzni (CLP) ne kadar süre geçerlidir?","options":["180 gün","30 gün","60 gün","1 yıl"],"explanation":"Nevada, 180 gün geçerli olan CLP'ler verir. Kaynak: Nevada DMV Commercial Learner Permits sayfası (dmv.nv.gov/clp.htm)."},"80":{"q":"Nevada'da, herhangi bir CDL beceri testine girebilmeniz için bir CLP'yi elinizde tutmanız gereken asgari süre nedir?","options":["14 gün","7 gün","30 gün","60 gün"],"explanation":"Nevada, federal CLP kuralıyla tutarlı olarak, herhangi bir beceri testinden önce bir CLP'yi en az 14 gün elinizde tutmanızı gerektirir. Kaynak: Nevada DMV Commercial Learner Permits sayfası (dmv.nv.gov/clp.htm)."},"81":{"q":"Nevada CDL beceri testi üç bölümden oluşur. Hangi grup bunları doğru şekilde listeler?","options":["Araç (sefer öncesi) muayenesi, temel araç kontrolü ve yol üzerinde sürüş","Genel bilgi, hava frenleri ve kombine araçlar","Yazılı sınav, görme taraması ve yol üzerinde sürüş","Sefer öncesi muayene, tehlikeli maddeler ve gece sürüşü"],"explanation":"Nevada'nın üç bölümlü beceri testi, araç (sefer öncesi) muayenesi, temel kontrol becerileri ve yol üzerinde sürüş testinden oluşur. Kaynak: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"82":{"q":"Nevada'da ilk kez CDL başvurusunda bulunan biri beceri testine girebilmeden önce hangi eğitimi tamamlamış olmalıdır?","options":["Federal Eğitim Sağlayıcı Sicilinde (Federal Training Provider Registry) listelenen bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT)","Mahkemelerce onaylanmış bir defansif sürüş kursu","Yalnızca çevrim içi bir genel bilgi kursu","Bir ilk yardım ve CPR sertifikası kursu"],"explanation":"Federal ELDT kuralları Nevada'da geçerlidir: başvuru sahipleri, beceri testine girmeden önce Federal Training Provider Registry'de yer alan bir sağlayıcıdan eğitimi tamamlamalıdır. Kaynak: Nevada DMV (dmv.nv.gov/cdl.htm); 49 CFR Part 380."},"83":{"q":"Bir Nevada ticari sürücüsünün, bir CLP veya CDL başvurusunda bulunurken kaç öz beyan (self-certification) kategorisi arasından seçim yapması gerekir?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz beyan kategorisi vardır: eyaletlerarası muaf olmayan, eyaletlerarası muaf, eyalet içi muaf olmayan ve eyalet içi muaf. Kaynak: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"84":{"q":"Hangi öz beyan kategorisi genellikle sürücünün bir DOT tıbbi muayene uzmanı sertifikası sunmasını gerektirir?","options":["Eyaletlerarası muaf olmayan","Eyaletlerarası muaf","Eyalet içi muaf","Muaf devlet çalışanı"],"explanation":"Muaf olmayan eyaletlerarası sürücüler 49 CFR Part 391 fiziksel yeterlilik kurallarına tabidir ve bir Medical Examiner's Certificate bulundurmalı/sunmalıdır; muaf kategorilerin bunu yapması gerekmez. Kaynak: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"85":{"q":"Nevada DMV, CDL tıbbi sertifikasyonu için hangi tıbbi muayene uzmanı sertifikası formunu kabul eder?","options":["MCSA-5876 Medical Examiner's Certificate","DOT Form HS-2","Nevada CDL-9 sağlık muafiyeti","Bir hekim tarafından imzalanmış herhangi bir mektup"],"explanation":"Nevada DMV yalnızca MCSA-5876 Medical Examiner's Certificate'ı kabul eder. Kaynak: Nevada DMV CDL tıbbi sertifikasyon sayfaları (dmv.nv.gov/cdlmedical.htm)."},"86":{"q":"Nevada'nın modernleştirilmiş süreci itibarıyla, muaf olmayan bir sürücünün tıbbi sertifikası DMV'ye normalde nasıl ulaşır?","options":["Sertifikalı tıbbi muayene uzmanı bunu elektronik olarak FMCSA National Registry'ye yükler ve burası DMV'ye iletir","Sürücü, noter onaylı bir kağıt kopyayı Carson City'ye postalar","Sürücünün işvereni bunu yerel DMV ofisine fakslar","Sürücü bunu tarar ve doğrudan DMV'ye e-postayla gönderir"],"explanation":"16 Haziran 2025 itibarıyla, Nevada kağıtsız bir sisteme geçti: muayene uzmanı MEC'i elektronik olarak FMCSA'ya yükler, FMCSA bunu DMV'ye iletir, böylece sürücüler artık kağıt kartları teslim etmez. Kaynak: Nevada DMV haber bülteni 25013 (dmv.nv.gov)."},"87":{"q":"Bir Nevada muaf olmayan CDL öz beyanını destekleyen DOT fiziksel muayenesini yapma izni kime verilir?","options":["National Registry of Certified Medical Examiners'da listelenen bir sağlayıcı","Eyaletteki herhangi bir lisanslı hemşire uygulayıcısı","Sicil durumuna bakılmaksızın başvuru sahibinin olağan aile hekimi","Test bölgesindeki bir Nevada DMV teknisyeni"],"explanation":"Muayene, National Registry of Certified Medical Examiners'da listelenen bir sağlayıcı tarafından yapılmalıdır; DMV listelenmemiş sağlayıcılardan gelen sonuçları kabul etmez. Kaynak: Nevada DMV CDL tıbbi sayfaları (dmv.nv.gov/cdlmedical.htm)."},"88":{"q":"Standart bir Nevada CDL'si yenilenmesi gerekene kadar ne kadar süre geçerlidir (65 yaşın altındaki bir sürücü için)?","options":["8 yıl","4 yıl","5 yıl","10 yıl"],"explanation":"Bir Nevada CDL'si, 65 yaşın altındaki sürücüler için verildiği veya yenilendiği tarihin sekizinci yıl dönümünde sona erer. Kaynak: Nevada Administrative Code NAC 483.832."},"89":{"q":"65 yaşında veya daha büyük bir Nevada CDL sahibi için, CDL ne kadar süre geçerlidir?","options":["4 yıl","8 yıl","2 yıl","6 yıl"],"explanation":"65 yaşında veya daha büyük bir ruhsat sahibine verilen bir CDL, standart 8 yıl yerine, ruhsat sahibinin doğum gününün dördüncü yıl dönümünde sona erer. Kaynak: Nevada Administrative Code NAC 483.832."},"90":{"q":"Eyalet içi (Nevada içinde) sürüş için bir Nevada CDL'si almanın asgari yaşı nedir?","options":["18 yaşında","16 yaşında","19 yaşında","21 yaşında"],"explanation":"Eyalet içi işletim için bir Nevada CDL'si almak üzere en az 18 yaşında olmalısınız. Kaynak: Nevada DMV Commercial Learner Permits/CDL sayfaları (dmv.nv.gov/clp.htm, dmv.nv.gov/cdl.htm)."},"91":{"q":"Nevada'da eyaletlerarası ticarette araç kullanmak veya yolcu ya da hazmat ek belgeleri (endorsement) bulundurmak için gereken asgari yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Eyaletlerarası ticaret ve yolcu/hazmat ek belgeleri, Nevada'da asgari 21 yaş gerektirir. Kaynak: Nevada DMV CLP sayfası (dmv.nv.gov/clp.htm)."},"92":{"q":"Bir Nevada başvuru sahibinin yalnızca kullanacağı aracın hava frenleriyle donatılmış olması durumunda geçmesi gereken bilgi testi hangisidir?","options":["Hava frenleri bilgi testi","Genel bilgi testi","Kombine araçlar testi","Tehlikeli maddeler testi"],"explanation":"Hava frenleri bilgi testi, araç hava frenleriyle donatıldığında geçerlidir; bu testte başarısız olmak veya atlamak bir hava freni kısıtlamasıyla sonuçlanır. Kaynak: Nevada DMV CDL Licensing (dmv.nv.gov/cdl.htm)."},"93":{"q":"'Muaf eyalet içi' (excepted intrastate) olarak öz beyanda bulunan bir Nevada başvuru sahibinin genellikle aşağıdakilerden hangisini yapması GEREKMEZ?","options":["Bir DOT tıbbi muayene uzmanı sertifikası sunmak","Genel bilgi testini geçmek","Test öncesi bir CLP bulundurmak","Kimlik ve ikamet kanıtı sağlamak"],"explanation":"Muaf sürücülerin (örneğin belirli devlet, itfaiye veya evden okula taşıma) bir Medical Examiner's Certificate sağlaması gerekmez, ancak işverenler yine de bir muayene isteyebilir. Kaynak: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"94":{"q":"Bir Nevada CLP'si verilebilmeden önce, başvuru sahibinin önce hangi şartı yerine getirmesi gerekir?","options":["Ehliyet sınıfı ve ek belgeler için gerekli tüm bilgi testlerini geçmek","Yol üzerinde beceri testini tamamlamak","İzni 14 gün elinde tutmak","Temel araç kontrolü testini geçmek"],"explanation":"Bir CLP almak için, başvuru sahibinin ehliyet sınıfı ve ek belgeler için gerekli tüm bilgi testlerini geçmesi gerekir; beceri testleri daha sonra gelir. Kaynak: Nevada DMV Commercial Learner Permits sayfası (dmv.nv.gov/clp.htm)."},"95":{"q":"70 feet uzunluğu aşan kombinasyonlar için bir Nevada kombine araç CDL kısıtlaması hangi yaşta geçerli olur?","options":["Sürücüler en az 25 yaşında olmalıdır","Sürücüler en az 18 yaşında olmalıdır","Sürücüler en az 21 yaşında olmalıdır","Uzunluğa bağlı bir yaş kısıtlaması yoktur"],"explanation":"Nevada, 70 feet'i aşan araç kombinasyonlarını işletmek için asgari 25 yaş gerektirir. Kaynak: Nevada DMV Commercial Learner Permits sayfası (dmv.nv.gov/clp.htm)."},"96":{"q":"Muaf olmayan bir Nevada CDL sahibi, dosyada yeni bir elektronik MEC olmadan tıbbi sertifikasyonunun süresinin dolmasına izin verirse, olası sonuç nedir?","options":["Geçerli bir MEC alınana kadar CDL, ticari olmayan statüye düşürülür","CDL, geri kazanma imkanı olmadan kalıcı olarak iptal edilir","8 yıllık yenileme tarihine kadar hiçbir şey olmaz","Sürücü otomatik olarak muaf olarak yeniden sınıflandırılır"],"explanation":"Dosyada güncel bir MEC olmadan, Nevada, geçerli bir elektronik MEC alınana kadar CDL'yi otomatik olarak ticari olmayan statüye düşürür. Kaynak: Nevada DMV haber bülteni 25013 (dmv.nv.gov)."},"97":{"q":"Nevada CDL başvuru ücretlerinin bir başvuru sahibi tarafından nasıl ele alınması gerektiğini en iyi hangi ifade yansıtır?","options":["Ücretler DMV tarafından belirlenir ve değişebilir, bu nedenle başvuru sahipleri başvurmadan önce güncel tutarları DMV ile teyit etmelidir","Ücretler federal yasayla kalıcı olarak sabitlenmiştir ve asla değişmez","Nevada'da CDL testi ve ruhsatlandırma her zaman ücretsizdir","Ücretler doğrudan FMCSA National Registry'ye ödenir"],"explanation":"Nevada CDL ile ilgili ücretler DMV tarafından yönetilir ve değişikliğe tabidir; başvuru sahipleri sabit bir rakama güvenmek yerine güncel tutarları doğrudan DMV ile doğrulamalıdır. Kaynak: Nevada DMV CDL sayfaları (dmv.nv.gov/cdl.htm)."}},"es":{"0":{"q":"¿Cuál es la altura máxima, incluyendo cualquier carga, a la que puede circular un vehículo por una carretera de Nevada?","options":["13 pies","13 pies 6 pulgadas","14 pies","15 pies"],"explanation":"La ley de Nevada fija la altura máxima del vehículo, incluyendo la carga, en 14 pies medidos desde la superficie sobre la que se apoya el vehículo (NRS 484D.605)."},"1":{"q":"¿Cuál es el ancho máximo legal estándar de un vehículo, combinación de vehículos o carga en una carretera de Nevada?","options":["96 pulgadas","98 pulgadas","102 pulgadas","108 pulgadas"],"explanation":"El ancho máximo legal de cualquier vehículo, combinación de vehículos, equipo móvil especial o carga es de 102 pulgadas (8 pies 6 pulgadas) en Nevada (NRS 484D.685)."},"2":{"q":"En Nevada, ¿cuál es el peso máximo permitido sobre cualquier eje simple de un vehículo que circula por una carretera pública?","options":["18,000 libras","20,000 libras","22,000 libras","34,000 libras"],"explanation":"Nevada limita el peso sobre cualquier eje simple a 20,000 libras (NRS 484D.635)."},"3":{"q":"¿Cuál es el peso máximo permitido sobre cualquier eje tándem de un vehículo en una carretera pública de Nevada?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Nevada limita el peso sobre cualquier eje tándem a 34,000 libras (NRS 484D.635)."},"4":{"q":"En la parte de Nevada del Sistema Interestatal y otras carreteras de ayuda federal, ¿cuál es el peso bruto vehicular máximo permitido sin un permiso especial?","options":["73,280 libras","80,000 libras","88,000 libras","105,500 libras"],"explanation":"Nevada aplica el máximo federal de 80,000 libras de peso bruto en los sistemas Interestatal y de ayuda federal, ya que reducirlo pondría en riesgo los fondos federales para carreteras (NRS 484D.660; 23 U.S.C. 127)."},"5":{"q":"¿Cuál es la longitud máxima de una combinación de vehículos en Nevada antes de que se requiera un permiso especial?","options":["65 pies","70 pies","75 pies","80 pies"],"explanation":"Ninguna combinación de vehículos acoplados entre sí, incluyendo los accesorios, puede exceder los 70 pies en Nevada sin un permiso especial del Departamento de Transporte (NRS 484D.615)."},"6":{"q":"¿Cuál es la longitud máxima de un camión motorizado individual (camión rígido) en una carretera de Nevada?","options":["35 pies","40 pies","45 pies","53 pies"],"explanation":"Un camión motorizado individual no puede exceder los 40 pies de longitud en Nevada (NRS 484D.615)."},"7":{"q":"¿Qué agencia de Nevada emite los permisos para vehículos sobredimensionados y con sobrepeso (de dimensiones excedidas)?","options":["El Departamento de Vehículos Motorizados de Nevada","El Departamento de Transporte de Nevada","La Patrulla de Caminos de Nevada","El alguacil (sheriff) de cada condado"],"explanation":"El Departamento de Transporte de Nevada (NDOT) emite los permisos por dimensiones excedidas o sobrepeso, incluyendo a través de su sistema en línea de permisos para dimensiones excedidas (Overdimensional Permitting System) (NRS 484D.625 y 484D.685; NDOT)."},"8":{"q":"En una combinación de tractocamión y semirremolque en una carretera de Nevada, ¿cuál es la longitud máxima permitida para el semirremolque sin un permiso especial?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"Se permite un tractocamión con un solo semirremolque cuando el semirremolque no excede los 53 pies de longitud (NRS 484D.615)."},"9":{"q":"Para un tractocamión que arrastra dos unidades remolcadas (remolques gemelos) en Nevada, ¿cuál es la longitud máxima de cada remolque sin un permiso especial?","options":["26 pies","28 pies 6 pulgadas","30 pies","33 pies"],"explanation":"Se permite un tractocamión con un semirremolque y un remolque cuando ninguna de las dos unidades remolcadas excede los 28.5 pies de longitud (NRS 484D.615)."},"10":{"q":"Un vehículo está equipado con neumáticos. En Nevada, ¿cuál es el ancho total máximo medido desde la parte exterior de un neumático externo hasta la parte exterior del neumático externo del lado opuesto?","options":["102 pulgadas","104 pulgadas","108 pulgadas","120 pulgadas"],"explanation":"Para vehículos con neumáticos, el ancho medido de neumático a neumático puede llegar a 108 pulgadas, pero la carrocería o la carga en sí no puede exceder las 102 pulgadas (NRS 484D.685)."},"11":{"q":"Según la ley de Nevada, ¿cuál es el peso máximo permitido por pulgada de ancho de neumático en un eje de dirección?","options":["450 libras por pulgada","500 libras por pulgada","550 libras por pulgada","600 libras por pulgada"],"explanation":"Nevada limita la carga del eje de dirección a 600 libras por pulgada de ancho de neumático (y 500 libras por pulgada para todos los demás ejes) (NRS 484D.635)."},"12":{"q":"Según la ley de Nevada, ¿cuál es el peso máximo permitido por pulgada de ancho de neumático en ejes distintos al eje de dirección?","options":["400 libras por pulgada","500 libras por pulgada","600 libras por pulgada","650 libras por pulgada"],"explanation":"Para todos los ejes distintos al eje de dirección, Nevada limita la carga a 500 libras por pulgada de ancho de neumático (las 600 libras por pulgada solo se permiten en el eje de dirección) (NRS 484D.635)."},"13":{"q":"Nevada aplica la fórmula federal de puentes para determinar el peso máximo sobre un grupo de ejes consecutivos. Dos conjuntos consecutivos de ejes tándem pueden cargar cada uno 34,000 libras si la distancia entre el primer y el último eje del grupo es de al menos cuántos pies?","options":["30 pies","33 pies","36 pies","40 pies"],"explanation":"Según la fórmula federal de puentes tal como se aplica en Nevada, dos conjuntos consecutivos de ejes tándem pueden cargar cada uno 34,000 libras si la distancia total entre el primer y el último eje es de 36 pies o más (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)."},"14":{"q":"Un transportista quiere mover una carga de 110 pulgadas de ancho por una carretera de Nevada. ¿Qué se requiere?","options":["Nada, porque está dentro del ancho legal","Un permiso de sobredimensión del Departamento de Transporte de Nevada","Solo luces de advertencia ámbar en cada esquina","Una exención de la Patrulla de Caminos de Nevada"],"explanation":"Una carga más ancha que el límite legal de 102 pulgadas se considera sobredimensionada y requiere un permiso por dimensiones excedidas del NDOT antes de poder moverse (NRS 484D.685; NDOT)."},"15":{"q":"¿Cuál es el propósito de la fórmula federal de puentes que Nevada aplica en el Sistema Interestatal?","options":["Establece la velocidad máxima para camiones pesados","Limita el peso sobre un grupo de ejes según la cantidad de ejes y la distancia entre ellos","Establece la tarifa de registro para vehículos comerciales","Determina la longitud máxima del remolque"],"explanation":"La fórmula federal de puentes limita el peso bruto que puede cargar cualquier grupo de dos o más ejes consecutivos, según la cantidad de ejes y la separación entre los ejes extremos del grupo, para proteger los puentes (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)."},"16":{"q":"A un vehículo que transporta productos agrícolas apilados sueltos (sin enfardar) como heno o paja a granel se le otorga una variación de ancho en Nevada. ¿Cuál es el ancho máximo permitido para esa carga y sus rejillas de retención?","options":["102 pulgadas","108 pulgadas","114 pulgadas","120 pulgadas"],"explanation":"Nevada permite que una carga de productos agrícolas apilados sueltos (no embalados, enfardados, encajonados ni ensacados) más cualquier rejilla de retención tenga hasta 120 pulgadas de ancho, una variación respecto al estándar de 102 pulgadas (NRS 484D.705)."},"17":{"q":"Nevada permite que una carga de heno enfardado exceda el límite normal de altura de 14 pies. ¿Cuál es la altura máxima permitida para una carga de heno enfardado?","options":["14 pies 6 pulgadas","15 pies","16 pies","17 pies"],"explanation":"Aunque el límite general de altura es de 14 pies, Nevada permite que una carga de heno enfardado se transporte hasta una altura de 15 pies (NRS 484D.605)."},"18":{"q":"Cuando el NDOT determina que los vehículos que operan al peso legal máximo probablemente causarán un esfuerzo sustancial a una carretera, puente o calle en particular, ¿qué puede hacer el NDOT o el órgano de gobierno local?","options":["Cerrar la vía permanentemente a todo el tránsito comercial","Reducir los límites de peso permitidos en esa carretera, camino o calle","Exigir que todos los camiones agreguen un tercer remolque","Aumentar el límite estatal de eje simple para compensar"],"explanation":"El NDOT y los órganos de gobierno locales pueden reducir los límites de peso en cualquier carretera, camino o calle donde los vehículos al peso máximo permitido probablemente causen un esfuerzo estructural sustancial (NRS 484D.660)."},"19":{"q":"Un transportista necesita un permiso anual de sobrepeso para acarreos de rutina en Nevada. Según las directrices del NDOT, ¿con cuánta anticipación se le aconseja al transportista solicitarlo a través del sistema de permisos para dimensiones excedidas?","options":["Al menos con 24 horas de anticipación","Al menos con 7 días de anticipación","Al menos con 30 días de anticipación","Al menos con 90 días de anticipación"],"explanation":"El NDOT aconseja a los titulares de permisos planificar con al menos 30 días de anticipación al movimiento deseado o antes de que venza un permiso anual existente; las solicitudes se presentan a través del NDOT Overdimensional Permitting System (NDOT; NRS 484D.625)."},"20":{"q":"En Nevada, ¿qué clase de licencia de conducir comercial (CDL) se requiere para operar una combinación de vehículos con una clasificación de peso bruto combinado superior a 26,000 lbs cuando la unidad remolcada tiene un GVWR superior a 10,000 lbs?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Nevada requiere una CDL de Clase A para vehículos combinados de más de 26,000 lbs donde el remolque/unidad remolcada excede los 10,000 lbs de GVWR. Fuente: Nevada DMV CDL-051 'Commercial Driver License Information' y dmv.nv.gov/cdlcertify.htm (License Classes)."},"21":{"q":"¿Qué clase de CDL de Nevada cubre cualquier vehículo individual con un GVWR de 26,001 lbs o más, como un autobús grande o un camión rígido, que remolca una unidad que no excede las 10,000 lbs?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Una CDL de Clase B de Nevada cubre vehículos individuales de 26,001 lbs o más (autobuses, camiones grandes) que remolcan una unidad de menos de 10,001 lbs. Fuente: Nevada DMV cdlcertify.htm y CDL-051."},"22":{"q":"Según las reglas de Nevada, un vehículo que no cumple con los límites de tamaño de la Clase A o B pero que está diseñado para transportar 16 o más pasajeros (incluyendo al conductor) o que transporta materiales peligrosos con placa (placarded), ¿qué clase de CDL requiere?","options":["Clase A","Clase B","Clase C","Clase P"],"explanation":"La CDL de Clase C de Nevada es para vehículos por debajo de los límites de peso de A/B que transportan 16 o más pasajeros (incluyendo al conductor) o que requieren una placa de materiales peligrosos. Fuente: Nevada DMV cdlcertify.htm y CDL-051."},"23":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Nevada para operar un vehículo motorizado comercial en comercio interestatal?","options":["18 años","19 años","21 años","25 años"],"explanation":"Nevada requiere que los solicitantes tengan al menos 21 años para operar un vehículo motorizado comercial en comercio interestatal. Fuente: Nevada DMV CDL-051 'Minimum Age'."},"24":{"q":"En Nevada, a un solicitante de entre 18 y 20 años de edad se le puede otorgar una CDL únicamente para qué tipo de operación?","options":["Solo comercio interestatal","Solo comercio intraestatal","Solo rutas del gobierno federal","Solo transporte de pasajeros"],"explanation":"Nevada permite a los jóvenes de 18 a 20 años una CDL solo para comercio intraestatal; no pueden transportar pasajeros con fines de lucro ni acarrear materiales peligrosos con placa. Fuente: Nevada DMV CDL-051 'Minimum Age'."},"25":{"q":"¿Cuál es la edad mínima en Nevada para recibir el endoso requerido para conducir una combinación de vehículos de longitud excedida (70 pies)?","options":["21 años","23 años","25 años","26 años"],"explanation":"Nevada requiere que los conductores tengan al menos 25 años para conducir una combinación de vehículos de longitud excedida de 70 pies. Fuente: Nevada DMV CDL-051 'Minimum Age'; véase también NRS 484D.615 (restricciones de longitud)."},"26":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Nevada desde su fecha de emisión?","options":["60 días","90 días","180 días","1 año"],"explanation":"Un CLP de Nevada es válido por 180 días desde su emisión (la renovación puede requerir volver a hacer el examen). Fuente: Nevada DMV dmv.nv.gov/clp.htm y CDL-051 'CLP Conditions'."},"27":{"q":"Según las reglas de Nevada y federales, ¿por cuánto tiempo debe poseerse un Permiso de Aprendiz Comercial antes de que el titular pueda presentar el examen de habilidades de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 21 días","Al menos 30 días"],"explanation":"Un CLP de Nevada debe poseerse al menos 14 días antes del examen de habilidades, lo que coincide con el requisito federal. Fuente: Nevada DMV clp.htm y CDL-051 'CLP Conditions'."},"28":{"q":"Antes de emitir un CLP o una CDL, ¿cuántas formas de comprobante de residencia en Nevada requiere el Nevada DMV que presente un solicitante?","options":["Una forma","Dos formas","Tres formas","No se requiere comprobante"],"explanation":"Nevada requiere dos formas de comprobante de residencia que muestren el nombre del solicitante y su domicilio residencial en Nevada. Fuente: Nevada DMV CDL-051 'Proof of residency'."},"29":{"q":"¿Qué documento acepta el Nevada DMV como comprobante del número de Seguro Social de un solicitante para una CDL?","options":["Una tarjeta de registro de votante","Una tarjeta del Seguro Social, un W-2 o un talón de nómina que muestre el número completo","Un registro vehicular de Nevada","Una declaración jurada personal firmada"],"explanation":"Nevada acepta una tarjeta del Seguro Social, un W-2, un 1099 o un talón de nómina que indique el número de Seguro Social completo como comprobante del número de Seguro Social. Fuente: Nevada DMV CDL-051 'Proof of Your Social Security Number'."},"30":{"q":"Para un solicitante de CDL nacido en EE. UU., ¿qué documento acepta el Nevada DMV como comprobante adicional de identidad?","options":["Un acta de nacimiento certificada o un pasaporte de EE. UU.","Un diploma de preparatoria","Una tarjeta de biblioteca","Un estado de cuenta de tarjeta de crédito"],"explanation":"Nevada acepta un acta de nacimiento certificada (o extracto) o un pasaporte de EE. UU. como comprobante adicional de identidad para los solicitantes nacidos en EE. UU.; los documentos deben ser originales. Fuente: Nevada DMV CDL-051 'Additional Proof of Identity'."},"31":{"q":"Un solicitante de CDL nacido fuera de los Estados Unidos debe presentar cuál de los siguientes al Nevada DMV para establecer su presencia legal?","options":["Una licencia de conducir extranjera","Un pasaporte extranjero válido y vigente con sello I-94, una tarjeta de Residente Permanente o un Certificado de Naturalización","Una tarjeta de presentación consular","Una identificación de estudiante de cualquier país"],"explanation":"Nevada requiere que los solicitantes nacidos en el extranjero muestren un pasaporte extranjero válido y vigente (con sello I-94), una tarjeta de Residente Permanente o un Certificado de Naturalización. Fuente: Nevada DMV CDL-051 'Additional Proof of Identity'."},"32":{"q":"¿Qué endoso de CDL de Nevada se requiere para transportar materiales peligrosos en cantidades que requieren placas?","options":["Endoso N","Endoso T","Endoso H","Endoso P"],"explanation":"El endoso H (Hazardous Materials) se requiere para acarrear materiales peligrosos con placa en Nevada. Fuente: Nevada DMV CDL-051 'Endorsements' y dmv.nv.gov/cdl.htm."},"33":{"q":"Además de poseer una CDL y una identificación válida, ¿qué debe completar un solicitante de Nevada antes de que se le pueda emitir el endoso de HazMat (H)?","options":["Un curso de manejo defensivo","Una verificación de antecedentes basada en huellas dactilares","Un segundo examen de habilidades en carretera","Un endoso de longitud de 70 pies"],"explanation":"Nevada requiere que el solicitante apruebe una verificación de antecedentes basada en huellas dactilares (TSA); el examen de conocimientos de HazMat no puede presentarse hasta que se complete la verificación de antecedentes. Fuente: Nevada DMV CDL-051 'Hazmat Endorsement'."},"34":{"q":"¿Qué endoso de CDL de Nevada se requiere para operar un vehículo cisterna que acarrea materiales líquidos o gaseosos en un tanque a granel montado permanentemente?","options":["Endoso T","Endoso N","Endoso S","Endoso X"],"explanation":"El endoso N (Tank Vehicle) se requiere para operar vehículos cisterna en Nevada. Fuente: Nevada DMV CDL-051 'Endorsements'."},"35":{"q":"En una licencia comercial de Nevada, ¿qué designa el endoso X?","options":["Autoridad para dobles/triples","Un endoso combinado de HazMat y Cisterna (Hazmat Tanker)","Un endoso de autobús escolar","Un endoso de vehículo de longitud excedida"],"explanation":"Nevada designa la X como el endoso Hazmat Tanker (que combina los requisitos H y N). Fuente: Nevada DMV CDL-051 'Endorsements'."},"36":{"q":"¿Qué endoso requiere Nevada para que un conductor pueda arrastrar remolques dobles o triples?","options":["Endoso P","Endoso S","Endoso T","Endoso N"],"explanation":"El endoso T (Double/Triple Trailers) se requiere para arrastrar dobles o triples en Nevada. Fuente: Nevada DMV CDL-051 'Endorsements'."},"37":{"q":"Un conductor que quiere conducir un autobús escolar público en Nevada debe poseer qué combinación de endosos?","options":["Endosos P y S","Endosos N y T","Endosos H y X","Solo el endoso S"],"explanation":"Un conductor de autobús escolar de Nevada debe poseer tanto el endoso de Pasajeros (P) como el de Autobús Escolar (S), cada uno de los cuales requiere exámenes adicionales de conocimientos y habilidades. Fuente: materiales de CDL del Nevada DMV; Nevada School Bus Driver Training Manual (ELDT para P y S)."},"38":{"q":"¿Dónde debe completar un conductor comercial principiante de Nevada la Capacitación Requerida para Conductores Principiantes (ELDT)?","options":["Cualquier negocio con licencia en Nevada","Un proveedor incluido en el Registro Federal de Proveedores de Capacitación (Training Provider Registry)","La oficina del alguacil del condado","Un curso en línea a elección del conductor"],"explanation":"Nevada requiere que los conductores comerciales principiantes completen el ELDT con un proveedor incluido en el Registro Federal de Proveedores de Capacitación de la FMCSA (Training Provider Registry). Fuente: Nevada DMV CDL-051 'Entry Level Driver Training (ELDT)'; 49 CFR Part 380."},"39":{"q":"Al autocertificarse ante el Nevada DMV, ¿qué categoría aplica a un titular de CDL que conduce únicamente dentro de Nevada y está sujeto a las normas estatales de calificación física (no a la Parte 391 federal)?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Interstate-Excepted"],"explanation":"Non-Excepted Intrastate aplica a los conductores que operan únicamente dentro de Nevada y que están sujetos a las normas estatales de calificación del conductor. Fuente: Nevada DMV dmv.nv.gov/cdlcertify.htm (categorías de autocertificación); 49 CFR 383.71."},"40":{"q":"Mientras opera un vehículo motorizado comercial (CMV) en Nevada, un conductor con CDL se considera legalmente intoxicado y comete una infracción grave a partir de qué concentración de alcohol en la sangre (BAC)?","options":["0.04 por ciento o más","0.08 por ciento o más","0.02 por ciento o más","0.10 por ciento o más"],"explanation":"Nevada aplica el estándar federal para CMV: es una infracción grave descalificante operar un CMV con un BAC de 0.04 por ciento o más (el límite general de 0.08 por ciento de un conductor sin CDL sigue aplicando en cualquier vehículo). Fuente: Nevada Commercial Driver Handbook (descalificaciones) y 49 CFR 383.51."},"41":{"q":"Bajo la ley de consentimiento implícito de Nevada, ¿qué sucede si un conductor con CDL se niega a someterse a una prueba química de sangre, aliento u orina cuando se le solicita legalmente?","options":["La licencia del conductor se revoca automáticamente, y la negativa es en sí misma una infracción grave descalificante","No sucede nada a menos que el conductor sea posteriormente condenado por DUI en un tribunal","Solo se emite una advertencia por escrito por la primera negativa","El conductor paga una multa civil de $250 sin acción sobre la licencia"],"explanation":"Al conducir en Nevada, un titular de CDL da su consentimiento implícito a las pruebas; la negativa provoca una revocación automática de la licencia por parte del DMV y cuenta como una infracción grave que descalifica la CDL incluso si el conductor es posteriormente absuelto. Fuente: estatutos de consentimiento implícito de Nevada (NRS Chapter 484C) y Nevada Commercial Driver Handbook."},"42":{"q":"Por una primera infracción grave (como DUI o negativa a la prueba) cometida mientras NO se acarrean materiales peligrosos con placa, ¿por cuánto tiempo se descalifica una CDL de Nevada?","options":["1 año","60 días","3 años","6 meses"],"explanation":"Una primera infracción grave descalifica la CDL por un mínimo de 1 año. Fuente: Nevada Commercial Driver Handbook (descalificaciones) y 49 CFR 383.51."},"43":{"q":"Si una primera infracción grave (como DUI) se comete mientras el conductor opera un CMV que transporta materiales peligrosos con placa, la descalificación de la CDL de Nevada aumenta a:","options":["3 años","1 año","5 años","De por vida"],"explanation":"Una primera infracción grave cometida mientras se transportan materiales peligrosos con placa conlleva una descalificación de 3 años en lugar del estándar de 1 año. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"44":{"q":"¿Cuál es el periodo de descalificación de la CDL de Nevada por una SEGUNDA infracción grave (por ejemplo, una segunda condena por DUI en un CMV)?","options":["Descalificación de por vida","10 años","3 años","5 años"],"explanation":"Una segunda infracción grave resulta en una descalificación de la CDL de por vida (una reinstauración limitada después de al menos 10 años puede estar disponible solo bajo condiciones específicas). Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"45":{"q":"Un conductor con CDL en Nevada es condenado por DOS infracciones de tránsito graves en incidentes separados dentro de un periodo de 3 años. La CDL se descalifica por:","options":["60 días","30 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años (en incidentes separados) descalifican la CDL por 60 días. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"46":{"q":"Un conductor con CDL en Nevada es condenado por TRES infracciones de tránsito graves en incidentes separados dentro de un periodo de 3 años. La CDL se descalifica por:","options":["120 días","60 días","1 año","90 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años (en incidentes separados) descalifican la CDL por 120 días, que se cumplen además de cualquier descalificación previa de 60 días. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"47":{"q":"¿Cuál de las siguientes cuenta como una infracción de tránsito GRAVE para fines de descalificación de la CDL en Nevada?","options":["Exceso de velocidad de 15 mph o más por encima del límite señalizado","Exceso de velocidad de 5 mph por encima del límite señalizado","Una infracción de estacionamiento sin movimiento","Conducir con un registro vehicular vencido"],"explanation":"El exceso de velocidad excesivo, definido como 15 mph o más por encima del límite señalizado, es una infracción de tránsito grave incluida en la lista. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"48":{"q":"¿Qué conjunto de infracciones está clasificado en su totalidad como infracciones de tránsito GRAVES bajo las reglas de CDL de Nevada?","options":["Conducción imprudente, seguir demasiado de cerca y cambios de carril indebidos o erráticos","DUI, abandonar el lugar de un accidente y usar un CMV en un delito grave","Negarse a una prueba química, un segundo DUI y un atropello y fuga fatal","Infracción de permiso de sobrepeso, tarjeta médica vencida y peajes sin pagar"],"explanation":"La conducción imprudente, seguir demasiado de cerca y los cambios de carril indebidos o erráticos son todas infracciones de tránsito graves. Las demás infracciones enumeradas son infracciones graves (major offenses) o no forman parte de la lista de infracciones serias. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"49":{"q":"Conducir un CMV en Nevada sin la clase adecuada de CDL o permiso de aprendiz comercial, o sin tenerlo en su posesión, se clasifica como:","options":["Una infracción de tránsito grave","Una infracción mayor (major offense)","Una violación de una orden de fuera de servicio","Un error de papeleo no descalificante"],"explanation":"Operar un CMV sin la CDL/CLP adecuada, o sin tenerla en su posesión, es una infracción de tránsito grave que cuenta para las descalificaciones de 60 días/120 días. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"50":{"q":"Por una PRIMERA condena de una infracción en un cruce a nivel entre ferrocarril y carretera en un CMV, la CDL de Nevada se descalifica por al menos:","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce a nivel entre ferrocarril y carretera descalifica la CDL por no menos de 60 días. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"51":{"q":"Una SEGUNDA infracción en un cruce a nivel entre ferrocarril y carretera dentro de un periodo de 3 años descalifica una CDL de Nevada por al menos:","options":["120 días","60 días","1 año","90 días"],"explanation":"Una segunda infracción de cruce a nivel dentro de cualquier periodo de 3 años descalifica la CDL por no menos de 120 días. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"52":{"q":"Una TERCERA infracción en un cruce a nivel entre ferrocarril y carretera dentro de un periodo de 3 años descalifica una CDL de Nevada por al menos:","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera infracción de cruce a nivel dentro de cualquier periodo de 3 años descalifica la CDL por no menos de 1 año. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"53":{"q":"Si un conductor viola una orden de fuera de servicio mientras transporta materiales peligrosos con placa u opera un vehículo diseñado para 16 o más pasajeros, la descalificación por PRIMERA infracción es:","options":["No menos de 180 días y no más de 2 años","No menos de 90 días y no más de 1 año","No menos de 1 año y no más de 5 años","Exactamente 120 días"],"explanation":"Una primera violación de orden OOS mientras se acarrean materiales peligrosos con placa o se transportan 16 o más pasajeros descalifica la CDL por no menos de 180 días y no más de 2 años. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"54":{"q":"Además de ser descalificado, un conductor condenado por violar una orden de fuera de servicio en Nevada enfrenta una multa civil federal de al menos:","options":["$1,000","$250","$500","$2,750"],"explanation":"Un conductor que viola una orden OOS está sujeto a una multa civil de no menos de $1,000 (y hasta $2,500), aparte de la descalificación. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51."},"55":{"q":"Bajo la ley de Nevada (NRS 484B.165), usar un teléfono celular de mano o enviar mensajes de texto mientras se conduce conlleva qué multa civil por una PRIMERA infracción?","options":["$50","$100","$250","$500"],"explanation":"La ley de Nevada sobre dispositivos de mano/mensajes de texto (NRS 484B.165) establece una multa civil de $50 por una primera infracción, $100 por una segunda y $250 por una tercera dentro de 7 años; una primera infracción no se trata como una infracción de movimiento. Fuente: NRS 484B.165."},"56":{"q":"Para un titular de CDL, ¿cómo afecta a la licencia comercial el uso de un teléfono de mano o el envío de mensajes de texto mientras se opera un CMV bajo las reglas de Nevada/federales?","options":["Es una infracción de tránsito grave que puede llevar a una descalificación de 60 o 120 días si se repite","Es una infracción mayor que causa una descalificación de 1 año en la primera infracción","Solo resulta en una multa de $50 sin efecto sobre la CDL","Es una violación de fuera de servicio que conlleva una descalificación de 90 días"],"explanation":"Enviar mensajes de texto o usar un teléfono móvil de mano mientras se conduce un CMV es una infracción de tránsito grave; dos dentro de 3 años descalifican la CDL por 60 días y tres dentro de 3 años por 120 días. Fuente: Nevada Commercial Driver Handbook y 49 CFR 383.51 / 392.80-392.82."},"57":{"q":"Nevada limita la multa por una infracción de exceso de velocidad bajo el estatuto de la regla básica (NRS 484B.600) a qué cantidad por milla por hora por encima del límite?","options":["$20 por cada mph por encima del límite","$25 por cada mph por encima del límite","$10 por cada mph por encima del límite","$50 por cada mph por encima del límite"],"explanation":"Nevada limita la multa por exceso de velocidad a $20 por cada milla por hora que el conductor circule por encima del límite señalizado; para un titular de CDL, exceder la velocidad en 15 mph o más sigue siendo una infracción de tránsito grave independientemente del monto de la multa. Fuente: NRS 484B.600 y Nevada Commercial Driver Handbook."},"58":{"q":"Según la ley \"Muévase\" (Move Over) de Nevada, cuando se acerca a un vehículo de emergencia detenido, una grúa o un vehículo de NDOT que muestra luces intermitentes en una carretera, ¿qué debe hacer?","options":["Reducir a una velocidad razonable, avanzar con precaución y, de ser posible, cambiarse a un carril que no esté adyacente al vehículo detenido","Detenerse por completo hasta que se apaguen las luces del vehículo de emergencia","Mantener el límite de velocidad señalizado, pero tocar la bocina al pasar","Pasarse al acotamiento derecho y esperar a que un oficial le indique con la mano que avance"],"explanation":"La ley \"Muévase\" de Nevada (NRS 484B.607) exige que los conductores reduzcan la velocidad a un nivel razonable y adecuado, avancen con precaución, estén listos para detenerse y, de ser posible, se cambien a un carril que no esté inmediatamente adyacente al vehículo detenido. Aplica a vehículos de emergencia autorizados y a vehículos que muestran luces intermitentes ámbar o luces azules fijas, incluidos los vehículos de NDOT. Fuente: NRS 484B.607."},"59":{"q":"En una carretera dividida de Nevada con una barrera física o una sección divisoria, un autobús escolar detenido en la OTRA calzada muestra luces rojas intermitentes para recoger niños. ¿Qué debe hacer un conductor que va en su dirección?","options":["Detenerse hasta que dejen de parpadear las luces rojas, igual que en una carretera no dividida","No necesita detenerse, porque el autobús está ubicado en la otra calzada de una carretera dividida","Reducir a 15 mph y pasar con precaución por el carril más alejado","Detenerse solo si se ve a niños cruzando el camellón"],"explanation":"Según la NRS 484B.353, el conductor de un vehículo en una carretera dividida no necesita detenerse al encontrar o pasar un autobús escolar ubicado en la otra calzada. Nevada define una carretera dividida como aquella separada por una barrera física o una sección divisoria, por lo que esta excepción requiere una carretera verdaderamente dividida, no simplemente una línea central o un carril de giro. Fuente: NRS 484B.353."},"60":{"q":"Cuando un autobús escolar de Nevada que transporta niños, un autobús que lleva pasajeros o un vehículo con materiales peligrosos rotulados se acerca a un cruce ferroviario a nivel donde debe detenerse, ¿dentro de qué distancia del riel más cercano debe detenerse?","options":["No menos de 5 pies ni más de 25 pies del riel más cercano","No menos de 25 pies ni más de 75 pies del riel más cercano","No menos de 15 pies ni más de 50 pies del riel más cercano","No menos de 50 pies ni más de 100 pies del riel más cercano"],"explanation":"La NRS 484B.560 exige que un autobús que lleva pasajeros, un autobús escolar que transporta niños o un vehículo que transporta materiales peligrosos rotulados se detenga dentro de los 50 pies, pero no a menos de 15 pies del riel más cercano, antes de cruzar a nivel. Fuente: NRS 484B.560."},"61":{"q":"En Nevada, un vehículo motorizado comercial que NO está obligado a detenerse por completo en un cruce ferroviario a nivel aún tiene un deber específico antes de cruzar. ¿Cuál es?","options":["Mantener la velocidad de la carretera para despejar el cruce lo más rápido posible","Detenerse, poner el freno de estacionamiento y bajar la ventanilla para escuchar","Tocar la bocina dos veces y avanzar sin reducir la velocidad","Reducir la velocidad y confirmar que las vías estén libres de cualquier tren que se aproxime"],"explanation":"La NRS 484B.560 establece que un vehículo motorizado comercial (según se define en 49 C.F.R. 383.5) que no esté obligado a detenerse de otro modo debe, antes de cruzar a nivel, reducir su velocidad y confirmar que las vías estén libres de cualquier tren que se aproxime o equipo sobre los rieles. Fuente: NRS 484B.560."},"62":{"q":"¿Cuál es el límite de velocidad máximo que puede señalizarse en cualquier carretera de Nevada?","options":["65 millas por hora","80 millas por hora","75 millas por hora","85 millas por hora"],"explanation":"Según la NRS 484B.613, NDOT puede establecer límites de velocidad que no excedan 80 millas por hora en las carreteras estatales, y 80 mph es el límite señalizado más alto que existe en Nevada (en tramos rurales designados de carreteras interestatales). Fuente: NRS 484B.613; NRS 484B.617."},"63":{"q":"¿La ley de Nevada establece un único límite de velocidad máximo estatal para camiones que sea más bajo que el límite para automóviles de pasajeros?","options":["Sí, los camiones están limitados a 55 mph en todo el estado","Sí, los camiones están limitados a 60 mph en todas las carreteras interestatales","No existe un único límite estatal más bajo para camiones; NDOT puede establecer un límite más bajo para camiones donde esté señalizado","Sí, los camiones siempre deben circular exactamente 10 mph por debajo del límite señalizado para automóviles"],"explanation":"A diferencia de algunos estados, Nevada no impone un límite de velocidad más bajo generalizado a nivel estatal para camiones. La NRS 484B.613 autoriza a NDOT a establecer un límite de velocidad más bajo para camiones, vehículos sobredimensionados y autobuses donde los estudios lo justifiquen, señalizado mediante letreros; de lo contrario, los camiones siguen el límite señalizado. Fuente: NRS 484B.613."},"64":{"q":"En una carretera de acceso controlado de Nevada, ¿cuándo está obligado un conductor a salirse del carril del extremo izquierdo?","options":["Solo cuando un letrero prohíbe específicamente a los camiones circular por el carril izquierdo","Siempre que cualquier vehículo esté a 500 pies por detrás, sin importar la velocidad","Solo durante las horas nocturnas de oscuridad","Cuando circula a menor velocidad que el límite señalizado y es alcanzado por un vehículo más rápido que viene por detrás"],"explanation":"La NRS 484B.208 exige que un conductor en el carril del extremo izquierdo de una carretera de acceso controlado se salga de ese carril cuando circula por debajo del límite de velocidad señalizado y es alcanzado por un vehículo más rápido. Las excepciones incluyen rebasar, prepararse para girar a la izquierda, obras viales, uso de carriles HOV y la circulación dentro de una ciudad o pueblo. Fuente: NRS 484B.208."},"65":{"q":"Después de detener un vehículo comercial en el acotamiento de una carretera de Nevada de dos carriles y doble sentido, ¿dentro de cuántos minutos debe colocar sus dispositivos de advertencia de emergencia?","options":["Dentro de los 10 minutos","Dentro de los 5 minutos","Dentro de los 15 minutos","Dentro de los 30 minutos"],"explanation":"La norma federal 49 C.F.R. 392.22, que Nevada aplica a los CMV, exige que los triángulos reflectantes (u otros dispositivos aprobados) se coloquen dentro de los 10 minutos de haberse detenido en la parte transitada o en el acotamiento de una carretera. Fuente: 49 C.F.R. 392.22; Manual del Conductor Comercial de Nevada."},"66":{"q":"En un camino de Nevada de dos carriles y doble sentido, ¿dónde coloca sus tres triángulos de advertencia de emergencia para un CMV detenido (no cerca de una colina o curva)?","options":["A 10 pies, 50 pies y 100 pies, todos detrás del vehículo","A 25 pies, 75 pies y 150 pies detrás del vehículo","A 10 pies detrás del vehículo, a 100 pies detrás y a 100 pies adelante del vehículo","A 50 pies adelante, a 50 pies detrás y uno sobre el techo del vehículo"],"explanation":"Según la 49 C.F.R. 392.22, en un camino de dos carriles y doble sentido se coloca un triángulo a unos 10 pies del vehículo hacia el tráfico que se aproxima, uno a unos 100 pies hacia atrás y uno a unos 100 pies hacia adelante, de modo que el tráfico quede advertido en ambas direcciones. Fuente: 49 C.F.R. 392.22; Manual del Conductor Comercial de Nevada."},"67":{"q":"¿Cuál es el ancho máximo legal de un vehículo comercial o su carga en una carretera de Nevada antes de que se requiera un permiso por sobredimensión?","options":["96 pulgadas (8 pies)","114 pulgadas (9 pies 6 pulgadas)","120 pulgadas (10 pies)","102 pulgadas (8 pies 6 pulgadas)"],"explanation":"La NRS 484D.685 fija el ancho máximo legal de un vehículo, combinación o carga en 102 pulgadas (8 pies 6 pulgadas), excluyendo ciertos dispositivos de seguridad. Cualquier ancho mayor requiere un permiso por sobredimensión. Fuente: NRS 484D.685."},"68":{"q":"¿Cuál es la altura máxima legal, incluida la carga, para un vehículo en una carretera de Nevada?","options":["14 pies","13 pies 6 pulgadas","15 pies","16 pies"],"explanation":"La NRS 484D.605 prohíbe operar un vehículo en una carretera de Nevada si su altura, incluida cualquier carga, excede los 14 pies. (Una excepción limitada permite la paja en pacas hasta 15 pies.) Fuente: NRS 484D.605."},"69":{"q":"En una carretera dividida o calle de un solo sentido de Nevada, ¿dónde se coloca el triángulo de advertencia de emergencia MÁS LEJANO detrás de un CMV detenido?","options":["A unos 100 pies hacia el tráfico que se aproxima","A unos 200 pies hacia el tráfico que se aproxima","A unos 50 pies hacia el tráfico que se aproxima","A unos 500 pies hacia el tráfico que se aproxima"],"explanation":"Según la 49 C.F.R. 392.22, en una carretera de un solo sentido o dividida los triángulos se colocan a unos 10, 100 y 200 pies hacia el tráfico que se aproxima por detrás del vehículo. Fuente: 49 C.F.R. 392.22; Manual del Conductor Comercial de Nevada."},"70":{"q":"¿Cuál vehículo está obligado por la ley de Nevada a DETENERSE en todo cruce ferroviario a nivel (salvo una excepción)?","options":["Una plataforma plana vacía sin rótulos","Una camioneta de reparto de menos de 10,000 libras","Un automóvil de pasajeros que remolca un pequeño remolque","Un autobús escolar que transporta niños"],"explanation":"La NRS 484B.560 exige que los autobuses que llevan pasajeros, los autobuses escolares que transportan niños y los vehículos que transportan materiales peligrosos rotulados se detengan en todos los cruces ferroviarios a nivel. Una plataforma plana vacía sin rótulos, una camioneta ligera o un automóvil no entran en la categoría de detención obligatoria. Fuente: NRS 484B.560."},"71":{"q":"Cuando un autobús o vehículo rotulado de Nevada está detenido en un cruce ferroviario y se prepara para cruzar, ¿qué regla de cambios de velocidad aplica?","options":["Cruzar en una velocidad que no requiera hacer cambios mientras se está sobre el cruce","Reducir a la velocidad más baja en medio del cruce","Poner en neutral y cruzar las vías por inercia","Usar la velocidad más alta disponible para despejar las vías lo más rápido posible"],"explanation":"La NRS 484B.560 indica que, después de detenerse, el conductor debe cruzar solo en una velocidad que no requiera hacer cambios mientras atraviesa el cruce, y no debe cambiar de velocidad sobre las vías. Fuente: NRS 484B.560."},"72":{"q":"¿Cuál situación es una EXCEPCIÓN que libera a un autobús o vehículo rotulado de Nevada de la detención obligatoria en el cruce ferroviario?","options":["El conductor va retrasado con respecto a su horario","Un oficial de policía o un señalero está dirigiendo el tráfico en el cruce","El cruce tiene barreras automáticas que están levantadas","La visibilidad por la vía supera los 400 pies"],"explanation":"La NRS 484B.560 enumera excepciones que incluyen los cruces controlados por un oficial de policía o señalero, las vías abandonadas o marcadas como exentas, y ciertas maniobras industriales de cambio de vías en un distrito comercial. Tener una vista despejada o ir retrasado no es una excepción. Fuente: NRS 484B.560."},"73":{"q":"¿Cuál es el peso bruto vehicular máximo legal en una carretera de Nevada antes de que se requiera un permiso por sobrepeso?","options":["73,280 libras","90,000 libras","80,000 libras","100,000 libras"],"explanation":"Nevada sigue el límite federal: el peso bruto máximo es de 80,000 libras, con 20,000 libras sobre un eje sencillo y 34,000 libras sobre un eje tándem, sujeto a la fórmula de puentes. Las cargas más pesadas necesitan un permiso por sobrepeso de NDOT. Fuente: NRS Capítulo 484D (tamaño/peso); permisos sobredimensionales de NDOT."},"74":{"q":"Un conductor infringe por primera vez la ley \"Muévase\" de Nevada en una carretera normal (no en zona de obras). ¿Cómo se clasifica generalmente la infracción?","options":["Un delito menor que conlleva una multa (de unos $395) y puntos de penalización","Una infracción sin movimiento, sin puntos y sin multa","Un delito grave que requiere la revocación obligatoria de la licencia","Solo una advertencia, sin sanción para una primera infracción"],"explanation":"Una infracción de la NRS 484B.607 es un delito menor; una primera infracción normalmente conlleva una multa del orden de unos $395 (y hasta aproximadamente $790 en una zona de obras) más puntos de penalización. Fuente: NRS 484B.607."},"75":{"q":"Para un tractocamión que arrastra un solo semirremolque en Nevada, ¿cuál es la longitud máxima legal del semirremolque (sin permiso especial)?","options":["48 pies","57 pies","60 pies","53 pies"],"explanation":"La NRS 484D.615 permite una combinación de tractocamión y semirremolque en la que el semirremolque no exceda los 53 pies, como excepción al límite general de 70 pies de longitud total de la combinación. Fuente: NRS 484D.615."},"76":{"q":"Mientras está detenido en un cruce ferroviario en un autobús escolar de Nevada, además de detenerse a la distancia adecuada, ¿qué debe hacer el conductor antes de avanzar?","options":["Solo observar las luces de señalización y las barreras del cruce","Escuchar y mirar en ambas direcciones a lo largo de la vía en busca de un tren que se aproxime","Hacer que un pasajero baje para guiar al autobús al cruzar","Confiar únicamente en la bocina del tren para indicar que es seguro"],"explanation":"La NRS 484B.560 exige que el conductor, mientras está detenido, escuche y mire en ambas direcciones a lo largo de la vía en busca de cualquier tren que se aproxime y de señales que indiquen la aproximación de un tren antes de cruzar. A los conductores se les enseña a no confiar únicamente en las señales. Fuente: NRS 484B.560; Manual del Conductor Comercial de Nevada."},"77":{"q":"¿Cuándo debe generalmente dejar de circular en Nevada un vehículo con carga sobredimensionada que viaja con un permiso de NDOT?","options":["Solo entre el mediodía y la 1:00 p.m. cada día","Siempre que el límite de velocidad señalizado supere las 65 mph","Durante las horas de oscuridad, a menos que el permiso o las instrucciones especiales autoricen el viaje nocturno","Solo dentro de los límites de una ciudad incorporada, a cualquier hora"],"explanation":"Las condiciones del permiso sobredimensional de NDOT en Nevada generalmente prohíben circular durante las horas de oscuridad y pueden restringir el movimiento en fines de semana y días festivos, a menos que el permiso o las instrucciones especiales lo autoricen específicamente. Fuente: disposiciones del permiso de Vehículo Sobredimensional de NDOT."},"78":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Nevada?","options":["El Departamento de Vehículos Motorizados de Nevada (DMV)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Transporte de Nevada (NDOT)","La Patrulla de Caminos de Nevada"],"explanation":"En Nevada, el Departamento de Vehículos Motorizados (DMV) emite las CDL y los CLP; la FMCSA establece los estándares federales, pero no emite la licencia. Fuente: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"79":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Nevada?","options":["180 días","30 días","60 días","1 año"],"explanation":"Nevada emite CLP que son válidos por 180 días. Fuente: página de Permisos de Aprendiz Comercial del Nevada DMV (dmv.nv.gov/clp.htm)."},"80":{"q":"En Nevada, ¿cuál es la cantidad mínima de tiempo que debe tener un CLP antes de poder presentar cualquier examen de habilidades de la CDL?","options":["14 días","7 días","30 días","60 días"],"explanation":"Nevada exige que tenga un CLP por al menos 14 días antes de cualquier examen de habilidades, de acuerdo con la regla federal del CLP. Fuente: página de Permisos de Aprendiz Comercial del Nevada DMV (dmv.nv.gov/clp.htm)."},"81":{"q":"El examen de habilidades de la CDL de Nevada consta de tres partes. ¿Cuál conjunto las enumera correctamente?","options":["Inspección del vehículo (previa al viaje), control básico del vehículo y conducción en carretera","Conocimientos generales, frenos de aire y vehículos combinados","Examen escrito, prueba de visión y conducción en carretera","Inspección previa al viaje, materiales peligrosos y conducción nocturna"],"explanation":"El examen de habilidades de tres partes de Nevada consta de la inspección del vehículo (previa al viaje), las habilidades de control básico y la prueba de conducción en carretera. Fuente: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"82":{"q":"Antes de que un solicitante de CDL por primera vez en Nevada pueda presentar el examen de habilidades, ¿qué capacitación debe completarse?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor incluido en el Registro Federal de Proveedores de Capacitación","Un curso de manejo defensivo aprobado por los tribunales","Un curso de conocimientos generales únicamente en línea","Un curso de certificación de primeros auxilios y RCP"],"explanation":"Las reglas federales de ELDT aplican en Nevada: los solicitantes deben completar la capacitación de un proveedor que figure en el Registro Federal de Proveedores de Capacitación antes de presentar el examen de habilidades. Fuente: Nevada DMV (dmv.nv.gov/cdl.htm); 49 CFR Part 380."},"83":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un conductor comercial de Nevada al solicitar un CLP o una CDL?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: interestatal no exenta, interestatal exenta, intraestatal no exenta e intraestatal exenta. Fuente: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"84":{"q":"¿Cuál categoría de autocertificación generalmente exige que el conductor presente un certificado de examinador médico del DOT?","options":["Interestatal no exenta","Interestatal exenta","Intraestatal exenta","Empleado gubernamental exento"],"explanation":"Los conductores interestatales no exentos están sujetos a las reglas de calificación física de 49 CFR Part 391 y deben tener/presentar un Certificado de Examinador Médico; las categorías exentas no están obligadas a hacerlo. Fuente: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"85":{"q":"¿Qué formulario de certificado de examinador médico acepta el Nevada DMV para la certificación médica de la CDL?","options":["El Certificado de Examinador Médico MCSA-5876","El Formulario HS-2 del DOT","La exención de salud CDL-9 de Nevada","Cualquier carta firmada por un médico"],"explanation":"El Nevada DMV acepta únicamente el Certificado de Examinador Médico MCSA-5876. Fuente: páginas de certificación médica de la CDL del Nevada DMV (dmv.nv.gov/cdlmedical.htm)."},"86":{"q":"Según el proceso modernizado de Nevada, ¿cómo llega normalmente al DMV el certificado médico de un conductor no exento?","options":["El examinador médico certificado lo sube electrónicamente al Registro Nacional de la FMCSA, que lo transmite al DMV","El conductor envía por correo una copia en papel notariada a Carson City","El empleador del conductor lo envía por fax a la oficina local del DMV","El conductor lo escanea y lo envía por correo electrónico directamente al DMV"],"explanation":"A partir del 16 de junio de 2025, Nevada pasó a un sistema sin papel: el examinador sube el MEC electrónicamente a la FMCSA, que lo transmite al DMV, por lo que los conductores ya no entregan tarjetas en papel. Fuente: comunicado de prensa 25013 del Nevada DMV (dmv.nv.gov)."},"87":{"q":"¿Quién está autorizado a realizar el examen físico del DOT que respalda una autocertificación de CDL no exenta en Nevada?","options":["Un proveedor que figure en el Registro Nacional de Examinadores Médicos Certificados","Cualquier enfermero practicante con licencia en el estado","El médico de cabecera habitual del solicitante, sin importar su estatus en el registro","Un técnico del Nevada DMV en el sitio de examen"],"explanation":"El examen debe ser realizado por un proveedor que figure en el Registro Nacional de Examinadores Médicos Certificados; el DMV no aceptará resultados de proveedores que no estén en la lista. Fuente: páginas médicas de la CDL del Nevada DMV (dmv.nv.gov/cdlmedical.htm)."},"88":{"q":"¿Por cuánto tiempo es válida una CDL estándar de Nevada antes de que deba renovarse (para un conductor menor de 65 años)?","options":["8 años","4 años","5 años","10 años"],"explanation":"Una CDL de Nevada vence en el octavo aniversario de su emisión o renovación para conductores menores de 65 años. Fuente: Código Administrativo de Nevada NAC 483.832."},"89":{"q":"Para un titular de CDL de Nevada que tiene 65 años de edad o más, ¿por cuánto tiempo es válida la CDL?","options":["4 años","8 años","2 años","6 años"],"explanation":"Una CDL emitida a un licenciatario que tiene 65 años o más vence en el cuarto aniversario del cumpleaños del licenciatario, en lugar de los 8 años estándar. Fuente: Código Administrativo de Nevada NAC 483.832."},"90":{"q":"¿Cuál es la edad mínima para obtener una CDL de Nevada para conducir intraestatal (dentro de Nevada)?","options":["18 años","16 años","19 años","21 años"],"explanation":"Debe tener al menos 18 años para obtener una CDL de Nevada para operación intraestatal. Fuente: páginas de Permisos de Aprendiz Comercial/CDL del Nevada DMV (dmv.nv.gov/clp.htm, dmv.nv.gov/cdl.htm)."},"91":{"q":"¿Cuál es la edad mínima requerida para conducir en comercio interestatal o para tener endosos de pasajeros o HazMat en Nevada?","options":["21 años","18 años","19 años","25 años"],"explanation":"El comercio interestatal y los endosos de pasajeros/HazMat requieren una edad mínima de 21 años en Nevada. Fuente: página del CLP del Nevada DMV (dmv.nv.gov/clp.htm)."},"92":{"q":"¿Cuál examen de conocimientos debe aprobar un solicitante de Nevada solo si el vehículo que conducirá está equipado con frenos de aire?","options":["El examen de conocimientos sobre frenos de aire","El examen de conocimientos generales","El examen de vehículos combinados","El examen de materiales peligrosos"],"explanation":"El examen de conocimientos sobre frenos de aire aplica cuando el vehículo está equipado con frenos de aire; reprobarlo u omitirlo resulta en una restricción de frenos de aire. Fuente: Nevada DMV CDL Licensing (dmv.nv.gov/cdl.htm)."},"93":{"q":"Un solicitante de Nevada que se certifica como 'intraestatal exento' generalmente NO está obligado a hacer cuál de las siguientes cosas?","options":["Presentar un certificado de examinador médico del DOT","Aprobar el examen de conocimientos generales","Tener un CLP antes de presentar los exámenes","Proporcionar comprobante de identidad y residencia"],"explanation":"Los conductores exentos (p. ej., ciertos transportes gubernamentales, de combate de incendios o de transporte de casa a la escuela) no están obligados a proporcionar un Certificado de Examinador Médico, aunque los empleadores aún pueden exigir un examen. Fuente: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"94":{"q":"Antes de que se pueda emitir un CLP de Nevada, ¿cuál requisito debe satisfacer primero el solicitante?","options":["Aprobar todos los exámenes de conocimientos requeridos para la clase de licencia y los endosos","Completar el examen de habilidades de conducción en carretera","Tener el permiso por 14 días","Aprobar el examen de control básico del vehículo"],"explanation":"Para recibir un CLP, el solicitante debe aprobar todos los exámenes de conocimientos requeridos para la clase de licencia y los endosos; los exámenes de habilidades vienen después. Fuente: página de Permisos de Aprendiz Comercial del Nevada DMV (dmv.nv.gov/clp.htm)."},"95":{"q":"¿A qué edad aplica una restricción de CDL de vehículo combinado de Nevada para combinaciones que exceden los 70 pies de longitud?","options":["Los conductores deben tener al menos 25 años","Los conductores deben tener al menos 18 años","Los conductores deben tener al menos 21 años","No hay restricción de edad vinculada a la longitud"],"explanation":"Nevada exige una edad mínima de 25 años para operar combinaciones de vehículos que excedan los 70 pies. Fuente: página de Permisos de Aprendiz Comercial del Nevada DMV (dmv.nv.gov/clp.htm)."},"96":{"q":"Si un titular de CDL no exento de Nevada deja que su certificación médica caduque sin un nuevo MEC electrónico registrado, ¿cuál es la consecuencia probable?","options":["La CDL se degrada a estatus no comercial hasta que se reciba un MEC válido","La CDL se revoca permanentemente sin posibilidad de restauración","No pasa nada hasta la fecha de renovación de los 8 años","El conductor se reclasifica automáticamente como exento"],"explanation":"Sin un MEC vigente en el archivo, Nevada degrada automáticamente la CDL a estatus no comercial hasta que se reciba un MEC electrónico válido. Fuente: comunicado de prensa 25013 del Nevada DMV (dmv.nv.gov)."},"97":{"q":"¿Cuál afirmación refleja mejor cómo debe tratar un solicitante las tarifas de solicitud de CDL de Nevada?","options":["Las tarifas las establece el DMV y pueden cambiar, así que los solicitantes deben confirmar los montos vigentes con el DMV antes de solicitar","Las tarifas están fijadas permanentemente por la ley federal y nunca cambian","Los exámenes y la licencia de CDL siempre son gratuitos en Nevada","Las tarifas se pagan directamente al Registro Nacional de la FMCSA"],"explanation":"Las tarifas relacionadas con la CDL de Nevada las administra el DMV y están sujetas a cambios; los solicitantes deben verificar los montos vigentes directamente con el DMV en lugar de basarse en una cifra fija. Fuente: páginas de la CDL del Nevada DMV (dmv.nv.gov/cdl.htm)."}},"hi":{"0":{"q":"नेवादा के राजमार्ग पर किसी वाहन को, उसके लदान सहित, अधिकतम कितनी ऊँचाई पर संचालित किया जा सकता है?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"नेवादा कानून वाहन की अधिकतम ऊँचाई, लदान सहित, उस सतह से मापते हुए जिस पर वाहन खड़ा होता है, 14 feet निर्धारित करता है (NRS 484D.605)।"},"1":{"q":"नेवादा के राजमार्ग पर किसी वाहन, वाहनों के संयोजन, या लदान की मानक अधिकतम कानूनी चौड़ाई क्या है?","options":["96 inches","98 inches","102 inches","108 inches"],"explanation":"नेवादा में किसी भी वाहन, वाहनों के संयोजन, विशेष चल उपकरण, या लदान की कानूनी अधिकतम चौड़ाई 102 inches (8 feet 6 inches) है (NRS 484D.685)।"},"2":{"q":"नेवादा में, किसी सार्वजनिक राजमार्ग पर संचालित वाहन के किसी एकल धुरी (single axle) पर अधिकतम अनुमेय भार क्या है?","options":["18,000 pounds","20,000 pounds","22,000 pounds","34,000 pounds"],"explanation":"नेवादा किसी भी एकल धुरी पर भार को 20,000 pounds तक सीमित करता है (NRS 484D.635)।"},"3":{"q":"नेवादा के सार्वजनिक राजमार्ग पर किसी वाहन के किसी टैंडम धुरी (tandem axle) पर अधिकतम अनुमेय भार क्या है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"नेवादा किसी भी टैंडम धुरी पर भार को 34,000 pounds तक सीमित करता है (NRS 484D.635)।"},"4":{"q":"नेवादा के अंतरराज्यीय प्रणाली (Interstate System) और अन्य संघीय-सहायता राजमार्गों के हिस्से पर, विशेष परमिट के बिना अधिकतम सकल वाहन भार (gross vehicle weight) कितना अनुमत है?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"explanation":"नेवादा अंतरराज्यीय और संघीय-सहायता प्रणालियों पर 80,000 pounds सकल भार की संघीय अधिकतम सीमा लागू करता है, क्योंकि इसे कम करने से संघीय राजमार्ग निधि खतरे में पड़ जाएगी (NRS 484D.660; 23 U.S.C. 127)।"},"5":{"q":"नेवादा में विशेष परमिट की आवश्यकता होने से पहले वाहनों के संयोजन की अधिकतम लंबाई कितनी है?","options":["65 feet","70 feet","75 feet","80 feet"],"explanation":"नेवादा में परिवहन विभाग (Department of Transportation) से विशेष परमिट के बिना, संलग्नकों सहित आपस में जुड़े वाहनों के किसी भी संयोजन की लंबाई 70 feet से अधिक नहीं हो सकती (NRS 484D.615)।"},"6":{"q":"नेवादा के राजमार्ग पर किसी एकल मोटरट्रक (सीधे ट्रक) की अधिकतम लंबाई कितनी है?","options":["35 feet","40 feet","45 feet","53 feet"],"explanation":"नेवादा में किसी एकल मोटरट्रक की लंबाई 40 feet से अधिक नहीं हो सकती (NRS 484D.615)।"},"7":{"q":"कौन-सी नेवादा एजेंसी ओवरसाइज़ और ओवरवेट (अति-आयामी) वाहन परमिट जारी करती है?","options":["नेवादा मोटर वाहन विभाग (Nevada Department of Motor Vehicles)","नेवादा परिवहन विभाग (Nevada Department of Transportation)","नेवादा राजमार्ग गश्ती दल (Nevada Highway Patrol)","प्रत्येक काउंटी का काउंटी शेरिफ"],"explanation":"नेवादा परिवहन विभाग (NDOT) अति-आयामी/ओवरवेट परमिट जारी करता है, जिसमें इसकी ऑनलाइन Overdimensional Permitting System के माध्यम से भी शामिल है (NRS 484D.625 और 484D.685; NDOT)।"},"8":{"q":"नेवादा के राजमार्ग पर एक ट्रैक्टर-सेमीट्रेलर संयोजन में, विशेष परमिट के बिना सेमीट्रेलर के लिए अनुमत अधिकतम लंबाई कितनी है?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"एकल सेमीट्रेलर वाला ट्रक-ट्रैक्टर तब अनुमत है जब सेमीट्रेलर की लंबाई 53 feet से अधिक न हो (NRS 484D.615)।"},"9":{"q":"नेवादा में दो खींची जाने वाली इकाइयों (twin trailers) को खींचने वाले ट्रक-ट्रैक्टर के लिए, विशेष परमिट के बिना प्रत्येक ट्रेलर की अधिकतम लंबाई कितनी है?","options":["26 feet","28 feet 6 inches","30 feet","33 feet"],"explanation":"सेमीट्रेलर और ट्रेलर वाला ट्रक-ट्रैक्टर तब अनुमत है जब दोनों खींची जाने वाली इकाइयों में से प्रत्येक की लंबाई 28.5 feet से अधिक न हो (NRS 484D.615)।"},"10":{"q":"एक वाहन वायवीय टायरों (pneumatic tires) से सुसज्जित है। नेवादा में, एक बाहरी टायर के बाहरी किनारे से विपरीत बाहरी टायर के बाहरी किनारे तक मापी गई अधिकतम कुल चौड़ाई क्या है?","options":["102 inches","104 inches","108 inches","120 inches"],"explanation":"वायवीय टायरों वाले वाहनों के लिए, टायर-से-टायर मापी गई चौड़ाई 108 inches तक पहुँच सकती है, लेकिन बॉडी या लदान स्वयं फिर भी 102 inches से अधिक नहीं हो सकता (NRS 484D.685)।"},"11":{"q":"नेवादा कानून के तहत, किसी स्टीयरिंग धुरी (steering axle) पर टायर की चौड़ाई के प्रति इंच अधिकतम अनुमत भार क्या है?","options":["450 pounds per inch","500 pounds per inch","550 pounds per inch","600 pounds per inch"],"explanation":"नेवादा स्टीयरिंग-धुरी पर भार को टायर की चौड़ाई के प्रति इंच 600 pounds तक सीमित करता है (और अन्य सभी धुरियों के लिए प्रति इंच 500 pounds) (NRS 484D.635)।"},"12":{"q":"नेवादा कानून के तहत, स्टीयरिंग धुरी के अलावा अन्य धुरियों पर टायर की चौड़ाई के प्रति इंच अधिकतम अनुमत भार क्या है?","options":["400 pounds per inch","500 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"स्टीयरिंग धुरी के अलावा अन्य सभी धुरियों के लिए, नेवादा भार को टायर की चौड़ाई के प्रति इंच 500 pounds तक सीमित करता है (प्रति इंच 600 pounds केवल स्टीयरिंग धुरी पर अनुमत है) (NRS 484D.635)।"},"13":{"q":"नेवादा क्रमागत धुरियों के समूह पर अधिकतम भार निर्धारित करने के लिए संघीय ब्रिज फॉर्मूला (federal bridge formula) लागू करता है। टैंडम धुरियों के दो क्रमागत सेट प्रत्येक 34,000 pounds ढो सकते हैं यदि समूह की पहली और अंतिम धुरी के बीच की दूरी कम से कम कितने feet हो?","options":["30 feet","33 feet","36 feet","40 feet"],"explanation":"नेवादा में लागू संघीय ब्रिज फॉर्मूला के तहत, टैंडम धुरियों के दो क्रमागत सेट प्रत्येक 34,000 pounds ढो सकते हैं यदि पहली और अंतिम धुरी के बीच कुल दूरी 36 feet या अधिक हो (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)।"},"14":{"q":"एक वाहक नेवादा के राजमार्ग पर 110 inches चौड़ा लदान ले जाना चाहता है। क्या आवश्यक है?","options":["कुछ नहीं, क्योंकि यह कानूनी चौड़ाई के भीतर है","नेवादा परिवहन विभाग (Nevada Department of Transportation) से एक ओवरसाइज़ परमिट","केवल प्रत्येक कोने पर एम्बर चेतावनी लाइटें","नेवादा राजमार्ग गश्ती दल (Nevada Highway Patrol) से एक छूट"],"explanation":"102-inch की कानूनी सीमा से अधिक चौड़ा लदान ओवरसाइज़ है और इसे ले जाने से पहले NDOT से अति-आयामी परमिट की आवश्यकता होती है (NRS 484D.685; NDOT)।"},"15":{"q":"उस संघीय ब्रिज फॉर्मूला का उद्देश्य क्या है जिसे नेवादा अंतरराज्यीय प्रणाली पर लागू करता है?","options":["यह भारी ट्रकों के लिए अधिकतम गति निर्धारित करता है","यह धुरियों की संख्या और उनके बीच की दूरी के आधार पर धुरियों के समूह पर भार सीमित करता है","यह वाणिज्यिक वाहनों के लिए पंजीकरण शुल्क निर्धारित करता है","यह अधिकतम ट्रेलर लंबाई निर्धारित करता है"],"explanation":"संघीय ब्रिज फॉर्मूला उस सकल भार की ऊपरी सीमा तय करता है जिसे दो या अधिक क्रमागत धुरियों का कोई समूह ढो सकता है, जो धुरियों की संख्या और समूह की बाहरी धुरियों के बीच की दूरी पर आधारित होता है, ताकि पुलों की रक्षा हो सके (NRS 484D.660; 23 U.S.C. 127, Bridge Formula)।"},"16":{"q":"नेवादा में थोक रूप में ढीले-ढाले रखे (गठरी रहित) कृषि उत्पाद जैसे घास या भूसा ढोने वाले वाहन को चौड़ाई में छूट दी जाती है। उस लदान और उसके रोकने वाले रैक के लिए अनुमत अधिकतम चौड़ाई क्या है?","options":["102 inches","108 inches","114 inches","120 inches"],"explanation":"नेवादा ढीले-ढाले रखे कृषि उत्पादों (जो पेटी, गठरी, बक्से या बोरे में न हों) के लदान के साथ-साथ किसी भी रोकने वाले रैक को 120 inches तक चौड़ा होने की अनुमति देता है, जो 102-inch मानक से एक छूट है (NRS 484D.705)।"},"17":{"q":"नेवादा गठरीबद्ध घास (baled hay) के लदान को सामान्य 14-feet ऊँचाई सीमा से अधिक होने की अनुमति देता है। गठरीबद्ध घास के लदान के लिए अनुमत अधिकतम ऊँचाई क्या है?","options":["14 feet 6 inches","15 feet","16 feet","17 feet"],"explanation":"जबकि सामान्य ऊँचाई सीमा 14 feet है, नेवादा गठरीबद्ध घास के लदान को 15 feet तक की ऊँचाई पर ढोने की अनुमति देता है (NRS 484D.605)।"},"18":{"q":"जब NDOT यह निर्धारित करता है कि अधिकतम कानूनी भार पर संचालित वाहन किसी विशेष राजमार्ग, पुल, या सड़क पर पर्याप्त तनाव डालने की संभावना रखते हैं, तो NDOT या स्थानीय शासी निकाय क्या कर सकता है?","options":["उस सड़क को सभी वाणिज्यिक यातायात के लिए स्थायी रूप से बंद कर दे","उस राजमार्ग, सड़क, या गली पर अनुमत भार सीमा को कम कर दे","सभी ट्रकों को एक तीसरा ट्रेलर जोड़ने के लिए बाध्य करे","क्षतिपूर्ति के लिए राज्यव्यापी एकल-धुरी सीमा बढ़ा दे"],"explanation":"NDOT और स्थानीय शासी निकाय किसी भी राजमार्ग, सड़क, या गली पर भार सीमा को कम कर सकते हैं जहाँ अधिकतम अनुमत भार पर वाहन पर्याप्त संरचनात्मक तनाव डालने की संभावना रखते हैं (NRS 484D.660)।"},"19":{"q":"एक मोटर वाहक को नेवादा में नियमित ढुलाई के लिए वार्षिक ओवरवेट परमिट की आवश्यकता है। NDOT मार्गदर्शन के अनुसार, वाहक को अति-आयामी परमिटिंग प्रणाली के माध्यम से कितना पहले आवेदन करने की सलाह दी जाती है?","options":["कम से कम 24 hours पहले","कम से कम 7 days पहले","कम से कम 30 days पहले","कम से कम 90 days पहले"],"explanation":"NDOT परमिट धारकों को किसी इच्छित आवाजाही से या किसी मौजूदा वार्षिक परमिट के समाप्त होने से कम से कम 30 days पहले योजना बनाने की सलाह देता है; आवेदन NDOT Overdimensional Permitting System के माध्यम से प्रस्तुत किए जाते हैं (NDOT; NRS 484D.625)।"},"20":{"q":"नेवादा में, 26,000 lbs से अधिक सकल संयोजन भार रेटिंग वाले वाहनों के संयोजन को संचालित करने के लिए वाणिज्यिक चालक लाइसेंस (CDL) की कौन-सी श्रेणी आवश्यक है, जब खींची जाने वाली इकाई का GVWR 10,000 lbs से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"नेवादा 26,000 lbs से अधिक के संयोजन वाहनों के लिए Class A CDL की आवश्यकता रखता है जहाँ ट्रेलर/खींची जाने वाली इकाई 10,000 lbs GVWR से अधिक हो। स्रोत: Nevada DMV CDL-051 'Commercial Driver License Information' और dmv.nv.gov/cdlcertify.htm (License Classes)।"},"21":{"q":"कौन-सी नेवादा CDL श्रेणी 26,001 lbs या अधिक GVWR वाले किसी एकल वाहन को शामिल करती है, जैसे कोई बड़ी बस या सीधा ट्रक, जो 10,000 lbs से अधिक न होने वाली इकाई को खींचता हो?","options":["Class A","Class B","Class C","Class M"],"explanation":"एक नेवादा Class B CDL 26,001 lbs या अधिक वाले एकल वाहनों (बसें, बड़े ट्रक) को शामिल करता है जो 10,001 lbs से कम की इकाई को खींचते हों। स्रोत: Nevada DMV cdlcertify.htm और CDL-051।"},"22":{"q":"नेवादा नियमों के तहत, एक वाहन जो Class A या B आकार सीमा को पूरा नहीं करता लेकिन 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या जो प्लेकार्ड वाले खतरनाक पदार्थ ढोता है, उसके लिए कौन-सी CDL श्रेणी आवश्यक है?","options":["Class A","Class B","Class C","Class P"],"explanation":"नेवादा का Class C CDL उन वाहनों के लिए है जो A/B भार सीमा से कम हैं तथा 16+ यात्रियों (चालक सहित) को ले जाते हैं या खतरनाक-पदार्थ प्लेकार्ड की आवश्यकता रखते हैं। स्रोत: Nevada DMV cdlcertify.htm और CDL-051।"},"23":{"q":"अंतरराज्यीय वाणिज्य (interstate commerce) में वाणिज्यिक मोटर वाहन संचालित करने के लिए नेवादा CDL जारी करने हेतु न्यूनतम आयु क्या है?","options":["18 years","19 years","21 years","25 years"],"explanation":"नेवादा को आवेदकों के लिए अंतरराज्यीय वाणिज्य में वाणिज्यिक मोटर वाहन संचालित करने हेतु कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: Nevada DMV CDL-051 'Minimum Age'।"},"24":{"q":"नेवादा में, 18 से 20 वर्ष की आयु के बीच के आवेदक को केवल किस प्रकार के संचालन के लिए CDL दिया जा सकता है?","options":["केवल अंतरराज्यीय वाणिज्य","केवल राज्य-आंतरिक वाणिज्य (intrastate commerce)","केवल संघीय सरकार के मार्ग","केवल यात्री परिवहन"],"explanation":"नेवादा 18 से 20 वर्ष के व्यक्तियों को केवल राज्य-आंतरिक वाणिज्य के लिए CDL की अनुमति देता है; वे किराए पर यात्रियों को नहीं ले जा सकते या प्लेकार्ड वाले खतरनाक पदार्थ नहीं ढो सकते। स्रोत: Nevada DMV CDL-051 'Minimum Age'।"},"25":{"q":"नेवादा में अति-लंबाई वाले संयोजन वाहन (70 feet) चलाने के लिए आवश्यक एंडोर्समेंट प्राप्त करने की न्यूनतम आयु क्या है?","options":["21 years","23 years","25 years","26 years"],"explanation":"नेवादा को चालकों के लिए 70 feet के अति-लंबाई वाले संयोजन वाहन चलाने हेतु कम से कम 25 वर्ष का होना आवश्यक है। स्रोत: Nevada DMV CDL-051 'Minimum Age'; NRS 484D.615 (लंबाई प्रतिबंध) भी देखें।"},"26":{"q":"नेवादा वाणिज्यिक शिक्षार्थी परमिट (CLP) इसके जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["60 days","90 days","180 days","1 year"],"explanation":"एक नेवादा CLP जारी होने से 180 days तक वैध रहता है (नवीनीकरण के लिए पुनः परीक्षण की आवश्यकता हो सकती है)। स्रोत: Nevada DMV dmv.nv.gov/clp.htm और CDL-051 'CLP Conditions'।"},"27":{"q":"नेवादा और संघीय नियमों के तहत, CDL कौशल परीक्षण देने से पहले वाणिज्यिक शिक्षार्थी परमिट को कितने समय तक धारण किया जाना चाहिए?","options":["कम से कम 7 days","कम से कम 14 days","कम से कम 21 days","कम से कम 30 days"],"explanation":"एक नेवादा CLP को कौशल परीक्षण से कम से कम 14 days पहले धारण किया जाना चाहिए, जो संघीय आवश्यकता के अनुरूप है। स्रोत: Nevada DMV clp.htm और CDL-051 'CLP Conditions'।"},"28":{"q":"CLP या CDL जारी करने से पहले, Nevada DMV किसी आवेदक से नेवादा निवास के कितने प्रकार के प्रमाण प्रस्तुत करने की आवश्यकता रखता है?","options":["एक प्रकार","दो प्रकार","तीन प्रकार","किसी प्रमाण की आवश्यकता नहीं"],"explanation":"नेवादा आवेदक का नाम और नेवादा आवासीय पता दर्शाने वाले दो प्रकार के निवास प्रमाण की आवश्यकता रखता है। स्रोत: Nevada DMV CDL-051 'Proof of residency'।"},"29":{"q":"CDL के लिए किसी आवेदक के सामाजिक सुरक्षा नंबर (Social Security number) के प्रमाण के रूप में Nevada DMV को कौन-सा दस्तावेज़ स्वीकार्य है?","options":["एक मतदाता पंजीकरण कार्ड","पूरा नंबर दर्शाने वाला एक Social Security card, W-2, या वेतन पर्ची","एक नेवादा वाहन पंजीकरण","एक हस्ताक्षरित व्यक्तिगत शपथपत्र"],"explanation":"नेवादा सामाजिक सुरक्षा नंबर के प्रमाण के रूप में पूरा SSN दर्शाने वाले Social Security card, W-2, 1099, या वेतन पर्ची को स्वीकार करता है। स्रोत: Nevada DMV CDL-051 'Proof of Your Social Security Number'।"},"30":{"q":"अमेरिका में जन्मे CDL आवेदक के लिए, Nevada DMV पहचान के अतिरिक्त प्रमाण के रूप में कौन-सा दस्तावेज़ स्वीकार करता है?","options":["एक प्रमाणित जन्म प्रमाणपत्र या U.S. passport","एक हाई स्कूल डिप्लोमा","एक पुस्तकालय कार्ड","एक क्रेडिट कार्ड विवरण"],"explanation":"नेवादा अमेरिका में जन्मे आवेदकों के लिए पहचान के अतिरिक्त प्रमाण के रूप में एक प्रमाणित जन्म प्रमाणपत्र (या सार) या एक U.S. passport स्वीकार करता है; दस्तावेज़ मूल होने चाहिए। स्रोत: Nevada DMV CDL-051 'Additional Proof of Identity'।"},"31":{"q":"संयुक्त राज्य अमेरिका के बाहर जन्मे CDL आवेदक को वैध उपस्थिति स्थापित करने के लिए Nevada DMV को निम्नलिखित में से क्या प्रस्तुत करना होगा?","options":["एक विदेशी चालक लाइसेंस","I-94 स्टैम्प के साथ एक वैध अनवसमाप्त विदेशी पासपोर्ट, Permanent Resident card, या Certificate of Naturalization","एक वाणिज्य दूतावास का बिज़नेस कार्ड","किसी भी देश से एक छात्र ID"],"explanation":"नेवादा विदेश में जन्मे आवेदकों से एक वैध अनवसमाप्त विदेशी पासपोर्ट (I-94 स्टैम्प के साथ), एक Permanent Resident card, या एक Certificate of Naturalization दिखाने की आवश्यकता रखता है। स्रोत: Nevada DMV CDL-051 'Additional Proof of Identity'।"},"32":{"q":"प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक पदार्थों के परिवहन के लिए कौन-सा नेवादा CDL एंडोर्समेंट आवश्यक है?","options":["N endorsement","T endorsement","H endorsement","P endorsement"],"explanation":"नेवादा में प्लेकार्ड वाले HazMat को ढोने के लिए H (Hazardous Materials) एंडोर्समेंट आवश्यक है। स्रोत: Nevada DMV CDL-051 'Endorsements' और dmv.nv.gov/cdl.htm।"},"33":{"q":"CDL और वैध पहचान रखने के अलावा, HazMat (H) एंडोर्समेंट जारी होने से पहले किसी नेवादा आवेदक को क्या पूरा करना होगा?","options":["एक रक्षात्मक ड्राइविंग पाठ्यक्रम","एक फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच","एक दूसरा सड़क कौशल परीक्षण","एक 70-foot लंबाई एंडोर्समेंट"],"explanation":"नेवादा को आवेदक का एक फिंगरप्रिंट-आधारित (TSA) पृष्ठभूमि जाँच पास करना आवश्यक है; पृष्ठभूमि जाँच पूरी होने तक HazMat ज्ञान परीक्षण नहीं दिया जा सकता। स्रोत: Nevada DMV CDL-051 'Hazmat Endorsement'।"},"34":{"q":"स्थायी रूप से लगे थोक टैंक में तरल या गैसीय पदार्थ ढोने वाले टैंक वाहन को संचालित करने के लिए कौन-सा नेवादा CDL एंडोर्समेंट आवश्यक है?","options":["T endorsement","N endorsement","S endorsement","X endorsement"],"explanation":"नेवादा में टैंक वाहनों को संचालित करने के लिए N (Tank Vehicle) एंडोर्समेंट आवश्यक है। स्रोत: Nevada DMV CDL-051 'Endorsements'।"},"35":{"q":"किसी नेवादा वाणिज्यिक लाइसेंस पर, X एंडोर्समेंट किसे निर्दिष्ट करता है?","options":["Doubles/triples प्राधिकार","एक संयुक्त HazMat और Tanker (Hazmat Tanker) एंडोर्समेंट","एक स्कूल बस एंडोर्समेंट","एक अति-लंबाई वाहन एंडोर्समेंट"],"explanation":"नेवादा X को Hazmat Tanker एंडोर्समेंट के रूप में सूचीबद्ध करता है (जो H और N आवश्यकताओं को जोड़ता है)। स्रोत: Nevada DMV CDL-051 'Endorsements'।"},"36":{"q":"किसी चालक को डबल या ट्रिपल ट्रेलर खींचने के लिए नेवादा कौन-सा एंडोर्समेंट आवश्यक रखता है?","options":["P endorsement","S endorsement","T endorsement","N endorsement"],"explanation":"नेवादा में doubles या triples खींचने के लिए T (Double/Triple Trailers) एंडोर्समेंट आवश्यक है। स्रोत: Nevada DMV CDL-051 'Endorsements'।"},"37":{"q":"नेवादा में सार्वजनिक स्कूल बस चलाने का इच्छुक चालक एंडोर्समेंट के किस संयोजन को रखता हो?","options":["P और S एंडोर्समेंट","N और T एंडोर्समेंट","H और X एंडोर्समेंट","केवल S एंडोर्समेंट"],"explanation":"एक नेवादा स्कूल बस चालक को Passenger (P) और School Bus (S) दोनों एंडोर्समेंट रखने चाहिए, जिनमें से प्रत्येक के लिए अतिरिक्त ज्ञान और कौशल परीक्षण आवश्यक है। स्रोत: Nevada DMV CDL सामग्री; Nevada School Bus Driver Training Manual (P और S के लिए ELDT)।"},"38":{"q":"एक प्रवेश-स्तर के नेवादा वाणिज्यिक चालक को आवश्यक प्रवेश-स्तर चालक प्रशिक्षण (ELDT) कहाँ पूरा करना होगा?","options":["किसी भी लाइसेंसप्राप्त नेवादा व्यवसाय में","संघीय Training Provider Registry पर सूचीबद्ध एक प्रदाता के पास","काउंटी शेरिफ के कार्यालय में","चालक की पसंद का एक ऑनलाइन पाठ्यक्रम"],"explanation":"नेवादा प्रवेश-स्तर के वाणिज्यिक चालकों के लिए संघीय FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता से ELDT पूरा करना आवश्यक रखता है। स्रोत: Nevada DMV CDL-051 'Entry Level Driver Training (ELDT)'; 49 CFR Part 380।"},"39":{"q":"Nevada DMV के साथ स्व-प्रमाणन (self-certifying) करते समय, कौन-सी श्रेणी ऐसे CDL धारक पर लागू होती है जो केवल नेवादा के भीतर चलाता है और राज्य (न कि संघीय Part 391) शारीरिक योग्यता मानकों के अधीन है?","options":["Non-Excepted Interstate","Excepted Interstate","Non-Excepted Intrastate","Excepted Interstate-Excepted"],"explanation":"Non-Excepted Intrastate उन चालकों पर लागू होता है जो केवल नेवादा के भीतर संचालन करते हैं और राज्य चालक योग्यता मानकों के अधीन हैं। स्रोत: Nevada DMV dmv.nv.gov/cdlcertify.htm (self-certification श्रेणियाँ); 49 CFR 383.71।"},"40":{"q":"नेवादा में वाणिज्यिक मोटर वाहन (CMV) संचालित करते समय, किसी CDL चालक को किस रक्त अल्कोहल सांद्रता (BAC) पर कानूनी रूप से नशे में माना जाता है और वह एक प्रमुख अपराध करता है?","options":["0.04 percent या अधिक","0.08 percent या अधिक","0.02 percent या अधिक","0.10 percent या अधिक"],"explanation":"नेवादा संघीय CMV मानक लागू करता है: 0.04 percent या अधिक के BAC के साथ CMV संचालित करना एक अयोग्य ठहराने वाला प्रमुख अपराध है (किसी भी वाहन में गैर-CDL चालक की 0.08 percent की सामान्य सीमा फिर भी लागू होती है)। स्रोत: Nevada Commercial Driver Handbook (अयोग्यताएँ) और 49 CFR 383.51।"},"41":{"q":"नेवादा के अंतर्निहित-सहमति (implied-consent) कानून के तहत, यदि कोई CDL चालक कानूनी रूप से अनुरोध किए जाने पर रक्त, श्वास, या मूत्र के रासायनिक परीक्षण के लिए मना कर देता है तो क्या होता है?","options":["चालक का लाइसेंस स्वतः रद्द हो जाता है, और इनकार करना स्वयं एक अयोग्य ठहराने वाला प्रमुख अपराध है","जब तक चालक को बाद में अदालत में DUI का दोषी न ठहराया जाए, तब तक कुछ नहीं होता","पहले इनकार के लिए केवल एक लिखित चेतावनी जारी की जाती है","चालक बिना किसी लाइसेंस कार्रवाई के $250 का सिविल जुर्माना भरता है"],"explanation":"नेवादा में गाड़ी चलाने से एक CDL धारक परीक्षण के लिए अंतर्निहित सहमति देता है; इनकार करने पर DMV द्वारा स्वतः लाइसेंस रद्दीकरण शुरू हो जाता है और यह एक प्रमुख अपराध के रूप में गिना जाता है जो CDL को अयोग्य ठहराता है, भले ही चालक बाद में बरी हो जाए। स्रोत: Nevada implied-consent statutes (NRS Chapter 484C) और Nevada Commercial Driver Handbook।"},"42":{"q":"प्लेकार्ड वाले खतरनाक पदार्थ न ढोते समय किए गए पहले प्रमुख अपराध (जैसे DUI या परीक्षण से इनकार) के लिए, नेवादा CDL कितने समय तक अयोग्य रहता है?","options":["1 year","60 days","3 years","6 months"],"explanation":"पहला प्रमुख अपराध CDL को न्यूनतम 1 year के लिए अयोग्य ठहराता है। स्रोत: Nevada Commercial Driver Handbook (अयोग्यताएँ) और 49 CFR 383.51।"},"43":{"q":"यदि पहला प्रमुख अपराध (जैसे DUI) तब किया जाता है जब चालक प्लेकार्ड वाले खतरनाक पदार्थ ले जाने वाला CMV संचालित कर रहा हो, तो नेवादा CDL अयोग्यता बढ़कर हो जाती है:","options":["3 years","1 year","5 years","आजीवन"],"explanation":"प्लेकार्ड वाले खतरनाक पदार्थों के परिवहन के दौरान किया गया पहला प्रमुख अपराध मानक 1 year के बजाय 3-year अयोग्यता रखता है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"44":{"q":"किसी दूसरे प्रमुख अपराध (उदाहरण के लिए, CMV में दूसरी DUI दोषसिद्धि) के लिए नेवादा CDL अयोग्यता अवधि क्या है?","options":["आजीवन अयोग्यता","10 years","3 years","5 years"],"explanation":"दूसरा प्रमुख अपराध आजीवन CDL अयोग्यता का परिणाम देता है (कम से कम 10 years के बाद एक सीमित पुनर्बहाली केवल विशिष्ट शर्तों के तहत उपलब्ध हो सकती है)। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"45":{"q":"नेवादा में एक CDL चालक को 3-year की अवधि के भीतर अलग-अलग घटनाओं में दो गंभीर यातायात उल्लंघनों का दोषी ठहराया जाता है। CDL कितने समय के लिए अयोग्य होता है:","options":["60 days","30 days","120 days","1 year"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघन (अलग-अलग घटनाओं में) CDL को 60 days के लिए अयोग्य ठहराते हैं। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"46":{"q":"नेवादा में एक CDL चालक को 3-year की अवधि के भीतर अलग-अलग घटनाओं में तीन गंभीर यातायात उल्लंघनों का दोषी ठहराया जाता है। CDL कितने समय के लिए अयोग्य होता है:","options":["120 days","60 days","1 year","90 days"],"explanation":"3 years के भीतर तीन गंभीर यातायात उल्लंघन (अलग-अलग घटनाओं में) CDL को 120 days के लिए अयोग्य ठहराते हैं, जो किसी भी पूर्व 60-day अयोग्यता के अतिरिक्त है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"47":{"q":"नेवादा में CDL अयोग्यता के उद्देश्यों के लिए निम्नलिखित में से कौन-सा एक गंभीर यातायात उल्लंघन गिना जाता है?","options":["निर्धारित सीमा से 15 mph या अधिक गति","निर्धारित सीमा से 5 mph अधिक गति","एक गैर-चलित पार्किंग उल्लंघन","समाप्त वाहन पंजीकरण के साथ गाड़ी चलाना"],"explanation":"अत्यधिक गति, जिसे निर्धारित सीमा से 15 mph या अधिक के रूप में परिभाषित किया गया है, एक सूचीबद्ध गंभीर यातायात उल्लंघन है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"48":{"q":"नेवादा CDL नियमों के तहत अपराधों का कौन-सा समूह सभी गंभीर यातायात उल्लंघन के रूप में वर्गीकृत है?","options":["लापरवाह ड्राइविंग, बहुत पास-पास चलना, और अनुचित या अनियमित लेन परिवर्तन","DUI, दुर्घटना स्थल से भागना, और किसी अपराध में CMV का उपयोग","रासायनिक परीक्षण से इनकार, दूसरी DUI, और एक घातक हिट-एंड-रन","ओवरवेट परमिट उल्लंघन, समाप्त मेडिकल कार्ड, और अदा न किए गए टोल"],"explanation":"लापरवाह ड्राइविंग, बहुत पास-पास चलना, और अनुचित या अनियमित लेन परिवर्तन सभी गंभीर यातायात उल्लंघन हैं। अन्य सूचीबद्ध अपराध प्रमुख अपराध हैं या गंभीर-उल्लंघन सूची का हिस्सा नहीं हैं। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"49":{"q":"नेवादा में बिना उचित श्रेणी के CDL या वाणिज्यिक शिक्षार्थी परमिट के, या उसे अपने पास रखे बिना, किसी CMV को चलाना किस रूप में वर्गीकृत है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक out-of-service आदेश उल्लंघन","एक गैर-अयोग्य ठहराने वाली कागज़ी त्रुटि"],"explanation":"उचित CDL/CLP के बिना, या उसे पास रखे बिना, किसी CMV को संचालित करना एक गंभीर यातायात उल्लंघन है जो 60-day/120-day अयोग्यताओं की ओर गिना जाता है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"50":{"q":"किसी CMV में रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए, नेवादा CDL कम से कम कितने समय के लिए अयोग्य होता है:","options":["60 days","30 days","120 days","1 year"],"explanation":"पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन CDL को 60 days से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"51":{"q":"3-year की अवधि के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन नेवादा CDL को कम से कम कितने समय के लिए अयोग्य ठहराता है:","options":["120 days","60 days","1 year","90 days"],"explanation":"किसी भी 3-year की अवधि के भीतर दूसरा ग्रेड-क्रॉसिंग उल्लंघन CDL को 120 days से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"52":{"q":"3-year की अवधि के भीतर तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन नेवादा CDL को कम से कम कितने समय के लिए अयोग्य ठहराता है:","options":["1 year","120 days","180 days","60 days"],"explanation":"किसी भी 3-year की अवधि के भीतर तीसरा ग्रेड-क्रॉसिंग उल्लंघन CDL को 1 year से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"53":{"q":"यदि कोई चालक प्लेकार्ड वाले खतरनाक पदार्थ ले जाते समय या 16 या अधिक यात्रियों के लिए डिज़ाइन किए गए वाहन को संचालित करते समय out-of-service आदेश का उल्लंघन करता है, तो पहले-अपराध की अयोग्यता है:","options":["180 days से कम नहीं और 2 years से अधिक नहीं","90 days से कम नहीं और 1 year से अधिक नहीं","1 year से कम नहीं और 5 years से अधिक नहीं","ठीक 120 days"],"explanation":"प्लेकार्ड वाले HazMat को ढोते समय या 16+ यात्रियों को ले जाते समय पहला OOS-आदेश उल्लंघन CDL को 180 days से कम नहीं और 2 years से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"54":{"q":"अयोग्य ठहराए जाने के अलावा, नेवादा में out-of-service आदेश के उल्लंघन का दोषी चालक कम से कम कितने संघीय सिविल जुर्माने का सामना करता है:","options":["$1,000","$250","$500","$2,750"],"explanation":"OOS आदेश का उल्लंघन करने वाला चालक अयोग्यता से अलग, $1,000 से कम नहीं (और $2,500 तक) के सिविल जुर्माने के अधीन है। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51।"},"55":{"q":"नेवादा कानून (NRS 484B.165) के तहत, गाड़ी चलाते समय हैंडहेल्ड सेलफोन का उपयोग करना या टेक्स्टिंग करना पहले अपराध के लिए क्या सिविल जुर्माना रखता है?","options":["$50","$100","$250","$500"],"explanation":"नेवादा का हैंडहेल्ड/टेक्स्टिंग कानून (NRS 484B.165) पहले अपराध के लिए $50, दूसरे के लिए $100, और 7 years के भीतर तीसरे के लिए $250 का सिविल जुर्माना निर्धारित करता है; पहले अपराध को चलित उल्लंघन के रूप में नहीं माना जाता। स्रोत: NRS 484B.165।"},"56":{"q":"किसी CDL धारक के लिए, CMV संचालित करते समय हैंडहेल्ड फोन का उपयोग करना या टेक्स्टिंग करना नेवादा/संघीय नियमों के तहत वाणिज्यिक लाइसेंस को कैसे प्रभावित करता है?","options":["यह एक गंभीर यातायात उल्लंघन है जो दोहराए जाने पर 60- या 120-day की अयोग्यता का कारण बन सकता है","यह पहले अपराध पर 1-year की अयोग्यता का कारण बनने वाला एक प्रमुख अपराध है","इसका परिणाम केवल $50 जुर्माने में होता है और CDL पर कोई प्रभाव नहीं पड़ता","यह एक out-of-service उल्लंघन है जो 90-day की अयोग्यता रखता है"],"explanation":"CMV चलाते समय टेक्स्टिंग या हैंडहेल्ड मोबाइल फोन का उपयोग एक गंभीर यातायात उल्लंघन है; 3 years के भीतर दो ऐसे उल्लंघन CDL को 60 days के लिए और 3 years के भीतर तीन उल्लंघन 120 days के लिए अयोग्य ठहराते हैं। स्रोत: Nevada Commercial Driver Handbook और 49 CFR 383.51 / 392.80-392.82।"},"57":{"q":"नेवादा मूल-नियम क़ानून (NRS 484B.600) के तहत गति उल्लंघन के लिए जुर्माने को सीमा से ऊपर प्रति मील प्रति घंटा कितनी राशि पर सीमित करता है?","options":["सीमा से ऊपर प्रत्येक mph के लिए $20","सीमा से ऊपर प्रत्येक mph के लिए $25","सीमा से ऊपर प्रत्येक mph के लिए $10","सीमा से ऊपर प्रत्येक mph के लिए $50"],"explanation":"नेवादा गति जुर्माने को चालक द्वारा निर्धारित सीमा से ऊपर चलाए गए प्रत्येक मील प्रति घंटे के लिए $20 पर सीमित करता है; किसी CDL धारक के लिए, जुर्माने की राशि की परवाह किए बिना सीमा से 15+ mph ऊपर गति एक गंभीर यातायात उल्लंघन बनी रहती है। स्रोत: NRS 484B.600 और Nevada Commercial Driver Handbook।"},"58":{"q":"नेवादा के 'मूव ओवर' कानून के तहत, जब आप किसी हाईवे पर चमकती रोशनी (फ्लैशिंग लाइट्स) दिखा रहे रुके हुए आपातकालीन वाहन, टो ट्रक, या NDOT वाहन के पास पहुंचते हैं, तो आपको क्या करना चाहिए?","options":["गति को उचित स्तर तक धीमा करें, सावधानी से आगे बढ़ें, और यदि संभव हो तो रुके हुए वाहन से सटी हुई लेन से हटकर किसी दूसरी लेन में चले जाएं","जब तक आपातकालीन वाहन की रोशनी बंद न हो जाए, तब तक पूरी तरह रुके रहें","निर्धारित गति सीमा बनाए रखें लेकिन गुजरते समय अपना हॉर्न बजाएं","दाईं ओर के शोल्डर पर चले जाएं और किसी अधिकारी द्वारा आपको आगे जाने का इशारा करने तक प्रतीक्षा करें"],"explanation":"नेवादा का 'मूव ओवर' कानून (NRS 484B.607) ड्राइवरों से अपेक्षा करता है कि वे गति को उचित और सही दर तक कम करें, सावधानी से आगे बढ़ें, रुकने के लिए तैयार रहें, और यदि संभव हो तो रुके हुए वाहन से तुरंत सटी हुई लेन से हटकर दूसरी लेन में चले जाएं। यह अधिकृत आपातकालीन वाहनों पर और चमकती एम्बर या स्थिर नीली रोशनी दिखाने वाले वाहनों पर लागू होता है, जिसमें NDOT वाहन शामिल हैं। स्रोत: NRS 484B.607."},"59":{"q":"किसी भौतिक अवरोध या विभाजक खंड वाले नेवादा के डिवाइडेड हाईवे पर, दूसरी सड़क (other roadway) पर रुकी हुई एक स्कूल बस बच्चों को चढ़ाने के लिए चमकती लाल रोशनी दिखा रही है। आपकी दिशा में चल रहे ड्राइवर को क्या करना चाहिए?","options":["जब तक लाल रोशनी चमकना बंद न कर दे तब तक रुकें, ठीक उसी तरह जैसे बिना विभाजित सड़क पर करते हैं","रुकने की आवश्यकता नहीं है, क्योंकि बस किसी डिवाइडेड हाईवे की दूसरी सड़क पर स्थित है","15 mph तक धीमा करें और दूर वाली लेन में सावधानी से गुजरें","केवल तभी रुकें यदि बच्चे स्पष्ट रूप से मीडियन पार करते दिख रहे हों"],"explanation":"NRS 484B.353 के तहत, डिवाइडेड हाईवे पर चल रहे वाहन के ड्राइवर को दूसरी सड़क पर स्थित स्कूल बस से मिलने या उसे पार करते समय रुकने की आवश्यकता नहीं होती। नेवादा डिवाइडेड हाईवे को ऐसे हाईवे के रूप में परिभाषित करता है जो किसी भौतिक अवरोध या विभाजक खंड द्वारा अलग किया गया हो, इसलिए इस अपवाद के लिए वास्तविक डिवाइडेड हाईवे आवश्यक है, केवल एक केंद्र रेखा या टर्न लेन पर्याप्त नहीं है। स्रोत: NRS 484B.353."},"60":{"q":"जब बच्चों को ले जा रही नेवादा स्कूल बस, यात्रियों को ले जा रही बस, या प्लेकार्ड लगा खतरनाक सामग्री वाला वाहन किसी रेलरोड ग्रेड क्रॉसिंग पर पहुंचता है जहां रुकना आवश्यक है, तो उसे निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["निकटतम रेल से 5 फीट से कम नहीं और 25 फीट से अधिक नहीं","निकटतम रेल से 25 फीट से कम नहीं और 75 फीट से अधिक नहीं","निकटतम रेल से 15 फीट से कम नहीं और 50 फीट से अधिक नहीं","निकटतम रेल से 50 फीट से कम नहीं और 100 फीट से अधिक नहीं"],"explanation":"NRS 484B.560 के अनुसार, यात्रियों को ले जा रही बस, बच्चों को ले जा रही स्कूल बस, या प्लेकार्ड लगी खतरनाक सामग्री ले जा रहे वाहन को ग्रेड पर क्रॉसिंग से पहले निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं की दूरी पर रुकना आवश्यक है। स्रोत: NRS 484B.560."},"61":{"q":"नेवादा में, एक व्यावसायिक मोटर वाहन जिसे किसी रेलरोड ग्रेड क्रॉसिंग पर पूरी तरह रुकना आवश्यक नहीं है, फिर भी क्रॉसिंग से पहले उसका एक विशिष्ट कर्तव्य होता है। वह क्या है?","options":["क्रॉसिंग को जितनी जल्दी हो सके पार करने के लिए हाईवे की गति बनाए रखें","रुकें, पार्किंग ब्रेक लगाएं, और सुनने के लिए खिड़की नीचे करें","हॉर्न दो बार बजाएं और बिना धीमा हुए आगे बढ़ें","गति कम करें और सुनिश्चित करें कि पटरियां किसी भी आ रही ट्रेन से खाली हैं"],"explanation":"NRS 484B.560 यह प्रावधान करता है कि एक व्यावसायिक मोटर वाहन (जैसा कि 49 C.F.R. 383.5 में परिभाषित है) जिसे अन्यथा रुकना आवश्यक नहीं है, उसे ग्रेड पर क्रॉसिंग से पहले अपनी गति कम करनी चाहिए और सुनिश्चित करना चाहिए कि पटरियां किसी भी आ रही ट्रेन या ट्रैक पर मौजूद उपकरण से खाली हैं। स्रोत: NRS 484B.560."},"62":{"q":"किसी भी नेवादा हाईवे पर पोस्ट की जा सकने वाली अधिकतम गति सीमा क्या है?","options":["65 मील प्रति घंटा","80 मील प्रति घंटा","75 मील प्रति घंटा","85 मील प्रति घंटा"],"explanation":"NRS 484B.613 के तहत, NDOT राज्य हाईवे पर 80 मील प्रति घंटा से अधिक न होने वाली गति सीमाएं स्थापित कर सकता है, और 80 mph नेवादा में पाई जाने वाली सबसे ऊंची पोस्ट की गई सीमा है (निर्दिष्ट ग्रामीण इंटरस्टेट खंडों पर)। स्रोत: NRS 484B.613; NRS 484B.617."},"63":{"q":"क्या नेवादा कानून ट्रकों के लिए राज्यव्यापी एक अधिकतम गति सीमा निर्धारित करता है जो यात्री कारों की सीमा से कम हो?","options":["हां, राज्य भर में हर जगह ट्रक 55 mph तक सीमित हैं","हां, सभी इंटरस्टेट पर ट्रक 60 mph तक सीमित हैं","ऐसी कोई एकल राज्यव्यापी कम ट्रक सीमा मौजूद नहीं है; NDOT जहां पोस्ट किया गया हो वहां ट्रकों के लिए कम सीमा निर्धारित कर सकता है","हां, ट्रकों को हमेशा पोस्ट की गई कार सीमा से ठीक 10 mph कम चलना चाहिए"],"explanation":"कुछ राज्यों के विपरीत, नेवादा ट्रकों के लिए कोई व्यापक राज्यव्यापी कम गति सीमा नहीं लगाता। NRS 484B.613 NDOT को अधिकृत करता है कि वह ट्रकों, अति-आकार वाहनों और बसों के लिए जहां अध्ययन इसे उचित ठहराते हैं, साइन द्वारा पोस्ट करके कम गति सीमा स्थापित कर सके; अन्यथा ट्रक पोस्ट की गई सीमा का पालन करते हैं। स्रोत: NRS 484B.613."},"64":{"q":"नेवादा के किसी नियंत्रित-पहुंच (controlled-access) हाईवे पर, ड्राइवर को सबसे बाईं लेन से हटना कब आवश्यक होता है?","options":["केवल तभी जब कोई साइन विशेष रूप से ट्रकों को बाईं लेन से प्रतिबंधित करे","जब भी कोई वाहन पीछे 500 फीट के भीतर हो, चाहे गति कुछ भी हो","केवल रात के अंधेरे के घंटों के दौरान","जब पोस्ट की गई गति सीमा से धीमा चल रहे हों और पीछे से कोई तेज वाहन आपको पार कर रहा हो"],"explanation":"NRS 484B.208 के अनुसार किसी नियंत्रित-पहुंच हाईवे की सबसे बाईं लेन में चल रहे ड्राइवर को उस लेन से हटना आवश्यक है जब वह पोस्ट की गई गति सीमा से कम पर चल रहा हो और कोई तेज वाहन उसे पार कर रहा हो। अपवादों में पासिंग, बाएं मुड़ने की तैयारी, सड़क निर्माण, HOV-लेन का उपयोग, और किसी शहर या कस्बे के भीतर यात्रा शामिल हैं। स्रोत: NRS 484B.208."},"65":{"q":"किसी दो-लेन, दो-तरफा नेवादा हाईवे के शोल्डर पर व्यावसायिक वाहन रोकने के बाद, आपको अपने आपातकालीन चेतावनी उपकरण कितने मिनट के भीतर रखने चाहिए?","options":["10 मिनट के भीतर","5 मिनट के भीतर","15 मिनट के भीतर","30 मिनट के भीतर"],"explanation":"संघीय नियम 49 C.F.R. 392.22, जिसे नेवादा CMVs के लिए लागू करता है, के अनुसार हाईवे के चलने योग्य भाग या शोल्डर पर रुकने के 10 मिनट के भीतर परावर्तक त्रिकोण (या अन्य स्वीकृत उपकरण) रखे जाने आवश्यक हैं। स्रोत: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook."},"66":{"q":"किसी दो-लेन, दो-तरफा नेवादा सड़क पर, रुके हुए CMV के लिए आप अपने तीन आपातकालीन चेतावनी त्रिकोण कहां रखते हैं (किसी पहाड़ी या मोड़ के पास नहीं)?","options":["10 फीट, 50 फीट, और 100 फीट, सभी वाहन के पीछे","वाहन के पीछे 25 फीट, 75 फीट, और 150 फीट","वाहन के 10 फीट पीछे, 100 फीट पीछे, और वाहन के 100 फीट आगे","50 फीट आगे, 50 फीट पीछे, और एक वाहन की छत पर"],"explanation":"49 C.F.R. 392.22 के अनुसार, दो-लेन, दो-तरफा सड़क पर आप एक त्रिकोण वाहन से लगभग 10 फीट आ रहे ट्रैफिक की ओर, एक लगभग 100 फीट पीछे की ओर, और एक लगभग 100 फीट आगे की ओर रखते हैं, ताकि दोनों दिशाओं से ट्रैफिक को चेतावनी मिले। स्रोत: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook."},"67":{"q":"ओवरसाइज परमिट आवश्यक होने से पहले, नेवादा हाईवे पर किसी व्यावसायिक वाहन या उसके लोड की अधिकतम कानूनी चौड़ाई क्या है?","options":["96 इंच (8 फीट)","114 इंच (9 फीट 6 इंच)","120 इंच (10 फीट)","102 इंच (8 फीट 6 इंच)"],"explanation":"NRS 484D.685 किसी वाहन, संयोजन, या लोड की अधिकतम कानूनी चौड़ाई 102 इंच (8 फीट 6 इंच) निर्धारित करता है, कुछ सुरक्षा उपकरणों को छोड़कर। इससे अधिक चौड़ी किसी भी चीज के लिए ओवरसाइज परमिट आवश्यक है। स्रोत: NRS 484D.685."},"68":{"q":"नेवादा हाईवे पर किसी वाहन के लिए, लोड सहित, अधिकतम कानूनी ऊंचाई क्या है?","options":["14 फीट","13 फीट 6 इंच","15 फीट","16 फीट"],"explanation":"NRS 484D.605 किसी वाहन को नेवादा हाईवे पर चलाने से प्रतिबंधित करता है यदि उसकी ऊंचाई, किसी भी लोड सहित, 14 फीट से अधिक हो। (एक सीमित अपवाद गठरीदार घास (baled hay) को 15 फीट तक की अनुमति देता है।) स्रोत: NRS 484D.605."},"69":{"q":"किसी नेवादा डिवाइडेड हाईवे या एकतरफा सड़क पर, रुके हुए CMV के पीछे सबसे दूर वाला आपातकालीन चेतावनी त्रिकोण कहां रखा जाता है?","options":["आ रहे ट्रैफिक की ओर लगभग 100 फीट","आ रहे ट्रैफिक की ओर लगभग 200 फीट","आ रहे ट्रैफिक की ओर लगभग 50 फीट","आ रहे ट्रैफिक की ओर लगभग 500 फीट"],"explanation":"49 C.F.R. 392.22 के तहत, किसी एकतरफा या डिवाइडेड हाईवे पर त्रिकोण वाहन के पीछे आ रहे ट्रैफिक की ओर लगभग 10, 100, और 200 फीट पर रखे जाते हैं। स्रोत: 49 C.F.R. 392.22; Nevada Commercial Driver Handbook."},"70":{"q":"नेवादा कानून के अनुसार किस वाहन को हर रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक है (किसी अपवाद के अभाव में)?","options":["बिना प्लेकार्ड वाला एक खाली फ्लैटबेड","10,000 पाउंड से कम का एक डिलीवरी वैन","एक छोटी ट्रेलर खींचती हुई यात्री कार","बच्चों को ले जा रही एक स्कूल बस"],"explanation":"NRS 484B.560 के अनुसार यात्रियों को ले जा रही बसों, बच्चों को ले जा रही स्कूल बसों, और प्लेकार्ड लगी खतरनाक सामग्री ले जा रहे वाहनों को सभी रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक है। बिना प्लेकार्ड वाला खाली फ्लैटबेड, हल्का वैन, या कार अनिवार्य-रुकने वाली श्रेणी में नहीं आते। स्रोत: NRS 484B.560."},"71":{"q":"जब कोई नेवादा बस या प्लेकार्ड लगा वाहन किसी रेलरोड क्रॉसिंग पर रुका हो और पार करने की तैयारी करता हो, तो कौन सा गियर नियम लागू होता है?","options":["ऐसे गियर में पार करें जिसमें क्रॉसिंग पर रहते हुए गियर बदलने की आवश्यकता न पड़े","क्रॉसिंग के बीच में सबसे निचले गियर में डाउनशिफ्ट करें","न्यूट्रल में शिफ्ट करें और पटरियों के पार लुढ़कते हुए जाएं","पटरियों को सबसे तेजी से पार करने के लिए उपलब्ध सबसे ऊंचे गियर का उपयोग करें"],"explanation":"NRS 484B.560 निर्देश देता है कि रुकने के बाद, ड्राइवर को केवल ऐसे गियर में पार करना चाहिए जिसमें क्रॉसिंग पार करते समय गियर बदलने की आवश्यकता न पड़े, और पटरियों पर गियर नहीं बदलना चाहिए। स्रोत: NRS 484B.560."},"72":{"q":"कौन सी स्थिति एक अपवाद है जो किसी नेवादा बस या प्लेकार्ड लगे वाहन को अनिवार्य रेलरोड-क्रॉसिंग रुकाव से मुक्त करती है?","options":["ड्राइवर निर्धारित समय से पीछे चल रहा है","क्रॉसिंग पर कोई पुलिस अधिकारी या फ्लैगमैन ट्रैफिक का निर्देशन कर रहा है","क्रॉसिंग पर स्वचालित गेट हैं जो ऊपर उठे हुए हैं","पटरी के नीचे की दृश्यता 400 फीट से अधिक है"],"explanation":"NRS 484B.560 ऐसे अपवादों को सूचीबद्ध करता है जिनमें किसी पुलिस अधिकारी या फ्लैगमैन द्वारा नियंत्रित क्रॉसिंग, परित्यक्त या छूट-चिह्नित पटरियां, और किसी व्यापारिक जिले में कुछ औद्योगिक स्विचिंग शामिल हैं। स्पष्ट दृश्यता या देर होना अपवाद नहीं है। स्रोत: NRS 484B.560."},"73":{"q":"ओवरवेट परमिट आवश्यक होने से पहले, नेवादा हाईवे पर अधिकतम कानूनी सकल वाहन भार (gross vehicle weight) क्या है?","options":["73,280 पाउंड","90,000 पाउंड","80,000 पाउंड","100,000 पाउंड"],"explanation":"नेवादा संघीय सीमा का पालन करता है: अधिकतम सकल भार 80,000 पाउंड है, जिसमें एकल एक्सल पर 20,000 पाउंड और टैंडम एक्सल पर 34,000 पाउंड, ब्रिज फॉर्मूला के अधीन। भारी लोड के लिए NDOT ओवरवेट परमिट आवश्यक है। स्रोत: NRS Chapter 484D (size/weight); NDOT Over Dimensional permits."},"74":{"q":"एक ड्राइवर किसी सामान्य (गैर-कार्यक्षेत्र) हाईवे पर पहली बार नेवादा के 'मूव ओवर' कानून का उल्लंघन करता है। यह अपराध आम तौर पर कैसे वर्गीकृत किया जाता है?","options":["एक मिसडिमिनर जिसमें जुर्माना (लगभग $395) और डिमेरिट पॉइंट लगते हैं","बिना पॉइंट और बिना जुर्माने वाला एक गैर-गतिशील (non-moving) उल्लंघन","एक फेलनी जिसमें अनिवार्य लाइसेंस निरस्तीकरण आवश्यक है","केवल एक चेतावनी, पहले अपराध के लिए कोई दंड नहीं"],"explanation":"NRS 484B.607 का उल्लंघन एक मिसडिमिनर है; पहले अपराध में आम तौर पर लगभग $395 की सीमा में जुर्माना (और कार्यक्षेत्र में लगभग $790 तक) के साथ डिमेरिट पॉइंट लगते हैं। स्रोत: NRS 484B.607."},"75":{"q":"नेवादा में एक ट्रक-ट्रैक्टर जो एक अकेली सेमीट्रेलर खींच रहा हो, उसके लिए सेमीट्रेलर की अधिकतम कानूनी लंबाई क्या है (बिना किसी विशेष परमिट के)?","options":["48 फीट","57 फीट","60 फीट","53 फीट"],"explanation":"NRS 484D.615 एक ट्रक-ट्रैक्टर और सेमीट्रेलर संयोजन की अनुमति देता है जिसमें सेमीट्रेलर 53 फीट से अधिक न हो, यह सामान्य 70-फीट कुल संयोजन सीमा के अपवाद के रूप में है। स्रोत: NRS 484D.615."},"76":{"q":"किसी नेवादा स्कूल बस में रेलरोड क्रॉसिंग पर रुके होने पर, उचित दूरी पर रुकने के अलावा, ड्राइवर को आगे बढ़ने से पहले क्या करना चाहिए?","options":["केवल क्रॉसिंग के सिग्नल लाइट और गेट देखें","किसी आ रही ट्रेन के लिए पटरी के साथ दोनों दिशाओं में सुनें और देखें","एक यात्री को बाहर निकलकर बस को पार कराने के लिए फ्लैग करने को कहें","केवल ट्रेन के हॉर्न पर भरोसा करें कि यह संकेत दे कि यह सुरक्षित है"],"explanation":"NRS 484B.560 के अनुसार ड्राइवर को रुके रहते हुए, क्रॉसिंग से पहले किसी आ रही ट्रेन और ट्रेन के आने का संकेत देने वाले सिग्नलों के लिए पटरी के साथ दोनों दिशाओं में सुनना और देखना आवश्यक है। ड्राइवरों को सिखाया जाता है कि वे केवल सिग्नलों पर भरोसा न करें। स्रोत: NRS 484B.560; Nevada Commercial Driver Handbook."},"77":{"q":"किसी NDOT परमिट के तहत यात्रा कर रहे ओवरसाइज-लोड वाहन को नेवादा में आम तौर पर चलना कब बंद करना पड़ता है?","options":["केवल हर दिन दोपहर 12 बजे से 1:00 बजे के बीच","जब भी पोस्ट की गई गति सीमा 65 mph से अधिक हो","अंधेरे के घंटों के दौरान, जब तक कि परमिट या विशेष निर्देश रात्रि यात्रा को अधिकृत न करें","केवल निगमित शहर की सीमा के भीतर किसी भी समय"],"explanation":"नेवादा NDOT ओवर-डाइमेंशनल परमिट शर्तें आम तौर पर अंधेरे के घंटों के दौरान यात्रा पर प्रतिबंध लगाती हैं और सप्ताहांत व अवकाश के आवागमन को सीमित कर सकती हैं, जब तक कि परमिट या विशेष निर्देश विशेष रूप से इसे अधिकृत न करें। स्रोत: NDOT Over Dimensional Vehicle permit provisions."},"78":{"q":"नेवादा में व्यावसायिक ड्राइवर लाइसेंस (CDLs) कौन सी एजेंसी जारी करती है?","options":["नेवादा मोटर वाहन विभाग (DMV)","Federal Motor Carrier Safety Administration (FMCSA)","नेवादा परिवहन विभाग (NDOT)","नेवादा हाईवे पैट्रोल"],"explanation":"नेवादा में मोटर वाहन विभाग (DMV) CDLs और CLPs जारी करता है; FMCSA संघीय मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता। स्रोत: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"79":{"q":"नेवादा कमर्शियल लर्नर परमिट (CLP) कितने समय तक वैध रहता है?","options":["180 दिन","30 दिन","60 दिन","1 वर्ष"],"explanation":"नेवादा ऐसे CLPs जारी करता है जो 180 दिनों तक वैध रहते हैं। स्रोत: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm)."},"80":{"q":"नेवादा में, कोई भी CDL कौशल परीक्षण (skills test) देने से पहले आपको CLP कम से कम कितने समय तक रखना आवश्यक है?","options":["14 दिन","7 दिन","30 दिन","60 दिन"],"explanation":"नेवादा के अनुसार आपको किसी भी कौशल परीक्षण से पहले CLP कम से कम 14 दिनों तक रखना आवश्यक है, जो संघीय CLP नियम के अनुरूप है। स्रोत: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm)."},"81":{"q":"नेवादा CDL कौशल परीक्षण तीन भागों से बना होता है। कौन सा सेट इन्हें सही ढंग से सूचीबद्ध करता है?","options":["वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","सामान्य ज्ञान, एयर ब्रेक, और संयोजन वाहन (combination vehicles)","लिखित परीक्षा, दृष्टि जांच, और सड़क पर ड्राइविंग","प्री-ट्रिप निरीक्षण, खतरनाक सामग्री, और रात्रि ड्राइविंग"],"explanation":"नेवादा के तीन-भागीय कौशल परीक्षण में वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी नियंत्रण कौशल, और सड़क पर ड्राइविंग परीक्षण शामिल हैं। स्रोत: Nevada DMV Commercial Driver Licensing (dmv.nv.gov/cdl.htm)."},"82":{"q":"नेवादा में पहली बार CDL आवेदन करने वाला व्यक्ति कौशल परीक्षण देने से पहले, कौन सा प्रशिक्षण पूरा करना आवश्यक है?","options":["Federal Training Provider Registry में सूचीबद्ध किसी प्रदाता से Entry-Level Driver Training (ELDT)","अदालतों द्वारा अनुमोदित एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","केवल-ऑनलाइन सामान्य ज्ञान पाठ्यक्रम","एक प्राथमिक चिकित्सा और CPR प्रमाणन पाठ्यक्रम"],"explanation":"नेवादा में संघीय ELDT नियम लागू होते हैं: आवेदकों को कौशल परीक्षण देने से पहले Federal Training Provider Registry पर सूचीबद्ध किसी प्रदाता से प्रशिक्षण पूरा करना आवश्यक है। स्रोत: Nevada DMV (dmv.nv.gov/cdl.htm); 49 CFR Part 380."},"83":{"q":"नेवादा में किसी व्यावसायिक ड्राइवर को CLP या CDL के लिए आवेदन करते समय कितनी स्व-प्रमाणन (self-certification) श्रेणियों में से चुनना आवश्यक है?","options":["चार","दो","तीन","पांच"],"explanation":"चार स्व-प्रमाणन श्रेणियां हैं: इंटरस्टेट नॉन-एक्सेप्टेड, इंटरस्टेट एक्सेप्टेड, इंट्रास्टेट नॉन-एक्सेप्टेड, और इंट्रास्टेट एक्सेप्टेड। स्रोत: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"84":{"q":"कौन सी स्व-प्रमाणन श्रेणी में आम तौर पर ड्राइवर को DOT मेडिकल परीक्षक का प्रमाणपत्र जमा करना आवश्यक होता है?","options":["इंटरस्टेट नॉन-एक्सेप्टेड","इंटरस्टेट एक्सेप्टेड","इंट्रास्टेट एक्सेप्टेड","एक्सेप्टेड सरकारी कर्मचारी"],"explanation":"नॉन-एक्सेप्टेड इंटरस्टेट ड्राइवर 49 CFR Part 391 की शारीरिक-योग्यता नियमों के अधीन हैं और उन्हें एक Medical Examiner's Certificate रखना/जमा करना आवश्यक है; एक्सेप्टेड श्रेणियों के लिए यह आवश्यक नहीं है। स्रोत: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"85":{"q":"नेवादा DMV CDL मेडिकल प्रमाणन के लिए कौन सा मेडिकल परीक्षक प्रमाणपत्र फॉर्म स्वीकार करता है?","options":["MCSA-5876 Medical Examiner's Certificate","DOT Form HS-2","Nevada CDL-9 हेल्थ वेवर","किसी चिकित्सक द्वारा हस्ताक्षरित कोई भी पत्र"],"explanation":"नेवादा DMV केवल MCSA-5876 Medical Examiner's Certificate स्वीकार करता है। स्रोत: Nevada DMV CDL medical certification pages (dmv.nv.gov/cdlmedical.htm)."},"86":{"q":"नेवादा की आधुनिकीकृत प्रक्रिया के अनुसार, किसी नॉन-एक्सेप्टेड ड्राइवर का मेडिकल प्रमाणपत्र सामान्यतः DMV तक कैसे पहुंचता है?","options":["प्रमाणित मेडिकल परीक्षक इसे इलेक्ट्रॉनिक रूप से FMCSA National Registry पर अपलोड करता है, जो इसे DMV को भेज देता है","ड्राइवर एक नोटरीकृत कागजी प्रति Carson City को डाक से भेजता है","ड्राइवर का नियोक्ता इसे स्थानीय DMV कार्यालय में फैक्स करता है","ड्राइवर इसे स्कैन करके सीधे DMV को ईमेल करता है"],"explanation":"16 जून, 2025 से प्रभावी, नेवादा एक पेपरलेस प्रणाली में स्थानांतरित हो गया: परीक्षक MEC को इलेक्ट्रॉनिक रूप से FMCSA पर अपलोड करता है, जो इसे DMV को भेज देता है, इसलिए ड्राइवरों को अब कागजी कार्ड जमा नहीं करने पड़ते। स्रोत: Nevada DMV news release 25013 (dmv.nv.gov)."},"87":{"q":"नेवादा नॉन-एक्सेप्टेड CDL स्व-प्रमाणन का समर्थन करने वाली DOT शारीरिक जांच करने की अनुमति किसे है?","options":["National Registry of Certified Medical Examiners पर सूचीबद्ध एक प्रदाता","राज्य में कोई भी लाइसेंस प्राप्त नर्स प्रैक्टिशनर","आवेदक का नियमित पारिवारिक डॉक्टर, चाहे रजिस्ट्री की स्थिति कुछ भी हो","परीक्षण स्थल पर एक नेवादा DMV तकनीशियन"],"explanation":"परीक्षा National Registry of Certified Medical Examiners पर सूचीबद्ध किसी प्रदाता द्वारा की जानी चाहिए; DMV असूचीबद्ध प्रदाताओं के परिणाम स्वीकार नहीं करेगा। स्रोत: Nevada DMV CDL medical pages (dmv.nv.gov/cdlmedical.htm)."},"88":{"q":"एक मानक नेवादा CDL नवीनीकरण से पहले कितने समय तक वैध रहता है (65 वर्ष से कम आयु के ड्राइवर के लिए)?","options":["8 वर्ष","4 वर्ष","5 वर्ष","10 वर्ष"],"explanation":"65 वर्ष से कम आयु के ड्राइवरों के लिए एक नेवादा CDL जारी होने या नवीनीकरण की आठवीं वर्षगांठ पर समाप्त होता है। स्रोत: Nevada Administrative Code NAC 483.832."},"89":{"q":"65 वर्ष या उससे अधिक आयु वाले नेवादा CDL धारक के लिए, CDL कितने समय तक वैध रहता है?","options":["4 वर्ष","8 वर्ष","2 वर्ष","6 वर्ष"],"explanation":"65 वर्ष या उससे अधिक आयु के किसी लाइसेंसधारक को जारी किया गया CDL मानक 8 वर्षों के बजाय, लाइसेंसधारक के जन्मदिन की चौथी वर्षगांठ पर समाप्त होता है। स्रोत: Nevada Administrative Code NAC 483.832."},"90":{"q":"इंट्रास्टेट (नेवादा-के-भीतर) ड्राइविंग के लिए नेवादा CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","19 वर्ष","21 वर्ष"],"explanation":"इंट्रास्टेट संचालन के लिए नेवादा CDL प्राप्त करने हेतु आपकी आयु कम से कम 18 वर्ष होनी चाहिए। स्रोत: Nevada DMV Commercial Learner Permits/CDL pages (dmv.nv.gov/clp.htm, dmv.nv.gov/cdl.htm)."},"91":{"q":"नेवादा में इंटरस्टेट वाणिज्य में ड्राइविंग करने या यात्री या हैज़मैट (hazmat) एंडोर्समेंट रखने के लिए न्यूनतम आवश्यक आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य और यात्री/हैज़मैट एंडोर्समेंट के लिए नेवादा में न्यूनतम आयु 21 वर्ष आवश्यक है। स्रोत: Nevada DMV CLP page (dmv.nv.gov/clp.htm)."},"92":{"q":"किसी नेवादा आवेदक को कौन सा ज्ञान परीक्षण केवल तभी पास करना आवश्यक है यदि वह जो वाहन चलाएगा वह एयर ब्रेक से सुसज्जित हो?","options":["एयर ब्रेक ज्ञान परीक्षण","सामान्य ज्ञान परीक्षण","संयोजन वाहन (combination vehicles) परीक्षण","खतरनाक सामग्री परीक्षण"],"explanation":"एयर ब्रेक ज्ञान परीक्षण तब लागू होता है जब वाहन एयर ब्रेक से सुसज्जित हो; इसे फेल करने या छोड़ने पर एयर-ब्रेक प्रतिबंध लग जाता है। स्रोत: Nevada DMV CDL Licensing (dmv.nv.gov/cdl.htm)."},"93":{"q":"एक नेवादा आवेदक जो 'एक्सेप्टेड इंट्रास्टेट' के रूप में प्रमाणित करता है, उससे आम तौर पर निम्न में से क्या करने की आवश्यकता नहीं होती?","options":["एक DOT मेडिकल परीक्षक का प्रमाणपत्र जमा करना","सामान्य ज्ञान परीक्षण पास करना","परीक्षण से पहले एक CLP रखना","पहचान और निवास का प्रमाण प्रदान करना"],"explanation":"एक्सेप्टेड ड्राइवरों (जैसे, कुछ सरकारी, अग्निशमन, या घर-से-स्कूल परिवहन) को Medical Examiner's Certificate प्रदान करने की आवश्यकता नहीं होती, हालांकि नियोक्ता फिर भी परीक्षा की मांग कर सकते हैं। स्रोत: Nevada DMV CDL Self-Certification (dmv.nv.gov/cdlcertify.htm)."},"94":{"q":"किसी नेवादा CLP को जारी किए जाने से पहले, आवेदक को सबसे पहले कौन सी आवश्यकता पूरी करनी चाहिए?","options":["लाइसेंस वर्ग और एंडोर्समेंट के लिए सभी आवश्यक ज्ञान परीक्षण पास करें","सड़क पर कौशल परीक्षण पूरा करें","परमिट को 14 दिनों तक रखें","बुनियादी वाहन नियंत्रण परीक्षण पास करें"],"explanation":"CLP प्राप्त करने के लिए, आवेदक को लाइसेंस वर्ग और एंडोर्समेंट के लिए सभी आवश्यक ज्ञान परीक्षण पास करने आवश्यक हैं; कौशल परीक्षण बाद में आते हैं। स्रोत: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm)."},"95":{"q":"70 फीट से अधिक लंबाई वाले संयोजनों के लिए नेवादा संयोजन-वाहन (combination-vehicle) CDL प्रतिबंध किस आयु पर लागू होता है?","options":["ड्राइवरों की आयु कम से कम 25 वर्ष होनी चाहिए","ड्राइवरों की आयु कम से कम 18 वर्ष होनी चाहिए","ड्राइवरों की आयु कम से कम 21 वर्ष होनी चाहिए","लंबाई से जुड़ा कोई आयु प्रतिबंध नहीं है"],"explanation":"नेवादा 70 फीट से अधिक के वाहन संयोजनों को संचालित करने के लिए न्यूनतम आयु 25 वर्ष आवश्यक करता है। स्रोत: Nevada DMV Commercial Learner Permits page (dmv.nv.gov/clp.htm)."},"96":{"q":"यदि कोई नॉन-एक्सेप्टेड नेवादा CDL धारक फाइल पर नया इलेक्ट्रॉनिक MEC रखे बिना अपना मेडिकल प्रमाणन समाप्त (lapse) होने देता है, तो संभावित परिणाम क्या होता है?","options":["जब तक एक वैध MEC प्राप्त नहीं हो जाता, तब तक CDL को गैर-व्यावसायिक स्थिति में डाउनग्रेड कर दिया जाता है","CDL को स्थायी रूप से निरस्त कर दिया जाता है और बहाली का कोई रास्ता नहीं होता","8-वर्षीय नवीनीकरण तिथि तक कुछ नहीं होता","ड्राइवर को स्वचालित रूप से एक्सेप्टेड के रूप में पुनः वर्गीकृत कर दिया जाता है"],"explanation":"फाइल पर मौजूदा MEC के बिना, नेवादा CDL को स्वचालित रूप से गैर-व्यावसायिक स्थिति में डाउनग्रेड कर देता है जब तक कि एक वैध इलेक्ट्रॉनिक MEC प्राप्त न हो जाए। स्रोत: Nevada DMV news release 25013 (dmv.nv.gov)."},"97":{"q":"कौन सा कथन सबसे अच्छी तरह दर्शाता है कि किसी आवेदक को नेवादा CDL आवेदन शुल्क को कैसे समझना चाहिए?","options":["शुल्क DMV द्वारा निर्धारित किए जाते हैं और बदल सकते हैं, इसलिए आवेदकों को आवेदन करने से पहले DMV से वर्तमान राशि की पुष्टि कर लेनी चाहिए","शुल्क संघीय कानून द्वारा स्थायी रूप से तय हैं और कभी नहीं बदलते","नेवादा में CDL परीक्षण और लाइसेंसिंग हमेशा नि:शुल्क है","शुल्क सीधे FMCSA National Registry को भुगतान किए जाते हैं"],"explanation":"नेवादा CDL-संबंधित शुल्क DMV द्वारा प्रशासित होते हैं और परिवर्तन के अधीन हैं; आवेदकों को किसी निश्चित आंकड़े पर भरोसा करने के बजाय वर्तमान राशि सीधे DMV से सत्यापित करनी चाहिए। स्रोत: Nevada DMV CDL pages (dmv.nv.gov/cdl.htm)."}},"ar":{"0":{"q":"ما هو الحد الأقصى للارتفاع، بما في ذلك أي حمولة، الذي يُسمح بتشغيل مركبة به على طريق سريع في نيفادا؟","options":["13 قدمًا","13 قدمًا و6 بوصات","14 قدمًا","15 قدمًا"],"explanation":"يحدد قانون نيفادا الحد الأقصى لارتفاع المركبة، بما في ذلك الحمولة، بـ 14 قدمًا مقيسة من السطح الذي تقف عليه المركبة (NRS 484D.605)."},"1":{"q":"ما هو الحد الأقصى القانوني المعياري لعرض المركبة، أو مجموعة المركبات، أو الحمولة على طريق سريع في نيفادا؟","options":["96 بوصة","98 بوصة","102 بوصة","108 بوصات"],"explanation":"الحد الأقصى القانوني لعرض أي مركبة، أو مجموعة مركبات، أو معدات متنقلة خاصة، أو حمولة هو 102 بوصة (8 أقدام و6 بوصات) في نيفادا (NRS 484D.685)."},"2":{"q":"في نيفادا، ما هو الحد الأقصى المسموح به للوزن على أي محور مفرد لمركبة تُشغَّل على طريق عام؟","options":["18,000 رطل","20,000 رطل","22,000 رطل","34,000 رطل"],"explanation":"تحدد نيفادا الوزن على أي محور مفرد بـ 20,000 رطل (NRS 484D.635)."},"3":{"q":"ما هو الحد الأقصى المسموح به للوزن على أي محور مزدوج (تاندم) لمركبة على طريق عام في نيفادا؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تحدد نيفادا الوزن على أي محور مزدوج (تاندم) بـ 34,000 رطل (NRS 484D.635)."},"4":{"q":"على الجزء التابع لنيفادا من نظام الطرق السريعة بين الولايات والطرق الأخرى المدعومة فيدراليًا، ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به دون تصريح خاص؟","options":["73,280 رطل","80,000 رطل","88,000 رطل","105,500 رطل"],"explanation":"تطبق نيفادا الحد الأقصى الفيدرالي البالغ 80,000 رطل للوزن الإجمالي على أنظمة الطرق بين الولايات والطرق المدعومة فيدراليًا، لأن تخفيضه من شأنه أن يعرّض التمويل الفيدرالي للطرق السريعة للخطر (NRS 484D.660؛ 23 U.S.C. 127)."},"5":{"q":"ما هو الحد الأقصى لطول مجموعة من المركبات في نيفادا قبل أن يصبح التصريح الخاص مطلوبًا؟","options":["65 قدمًا","70 قدمًا","75 قدمًا","80 قدمًا"],"explanation":"لا يجوز لأي مجموعة من المركبات المقترنة معًا، بما في ذلك الملحقات، أن تتجاوز 70 قدمًا في نيفادا دون تصريح خاص من وزارة النقل (NRS 484D.615)."},"6":{"q":"ما هو الحد الأقصى لطول شاحنة آلية مفردة (شاحنة مستقيمة) على طريق سريع في نيفادا؟","options":["35 قدمًا","40 قدمًا","45 قدمًا","53 قدمًا"],"explanation":"لا يجوز أن يتجاوز طول الشاحنة الآلية المفردة 40 قدمًا في نيفادا (NRS 484D.615)."},"7":{"q":"ما هي الجهة في نيفادا التي تصدر تصاريح المركبات ذات الأبعاد الزائدة والأوزان الزائدة؟","options":["وزارة المركبات الآلية في نيفادا","وزارة النقل في نيفادا","دورية الطرق السريعة في نيفادا","شريف المقاطعة في كل مقاطعة"],"explanation":"تصدر وزارة النقل في نيفادا (NDOT) تصاريح الأبعاد الزائدة/الأوزان الزائدة، بما في ذلك من خلال نظام التصاريح الإلكتروني للأبعاد الزائدة الخاص بها (NRS 484D.625 و484D.685؛ NDOT)."},"8":{"q":"في مجموعة جرّار-نصف مقطورة على طريق سريع في نيفادا، ما هو الحد الأقصى للطول المسموح به لنصف المقطورة دون تصريح خاص؟","options":["48 قدمًا","53 قدمًا","57 قدمًا","60 قدمًا"],"explanation":"يُسمح بجرّار-شاحنة مع نصف مقطورة واحدة عندما لا يتجاوز طول نصف المقطورة 53 قدمًا (NRS 484D.615)."},"9":{"q":"بالنسبة لجرّار-شاحنة يسحب وحدتين مقطورتين (مقطورتان توأم) في نيفادا، ما هو الحد الأقصى لطول كل مقطورة دون تصريح خاص؟","options":["26 قدمًا","28 قدمًا و6 بوصات","30 قدمًا","33 قدمًا"],"explanation":"يُسمح بجرّار-شاحنة مع نصف مقطورة ومقطورة عندما لا يتجاوز طول كل من الوحدتين المقطورتين 28.5 قدمًا (NRS 484D.615)."},"10":{"q":"مركبة مزودة بإطارات هوائية. في نيفادا، ما هو الحد الأقصى للعرض الإجمالي المقيس من الجانب الخارجي لأحد الإطارات الخارجية إلى الجانب الخارجي للإطار الخارجي المقابل؟","options":["102 بوصة","104 بوصة","108 بوصات","120 بوصة"],"explanation":"بالنسبة للمركبات المزودة بإطارات هوائية، يمكن أن يصل العرض المقيس من إطار إلى إطار إلى 108 بوصات، ولكن الجسم أو الحمولة نفسها لا يجوز أن تتجاوز 102 بوصة (NRS 484D.685)."},"11":{"q":"بموجب قانون نيفادا، ما هو الحد الأقصى للوزن لكل بوصة من عرض الإطار المسموح به على محور التوجيه؟","options":["450 رطلاً لكل بوصة","500 رطل لكل بوصة","550 رطلاً لكل بوصة","600 رطل لكل بوصة"],"explanation":"تحدد نيفادا تحميل محور التوجيه بـ 600 رطل لكل بوصة من عرض الإطار (و500 رطل لكل بوصة لجميع المحاور الأخرى) (NRS 484D.635)."},"12":{"q":"بموجب قانون نيفادا، ما هو الحد الأقصى للوزن لكل بوصة من عرض الإطار المسموح به على المحاور غير محور التوجيه؟","options":["400 رطل لكل بوصة","500 رطل لكل بوصة","600 رطل لكل بوصة","650 رطلاً لكل بوصة"],"explanation":"بالنسبة لجميع المحاور غير محور التوجيه، تحدد نيفادا التحميل بـ 500 رطل لكل بوصة من عرض الإطار (يُسمح بـ 600 رطل لكل بوصة على محور التوجيه فقط) (NRS 484D.635)."},"13":{"q":"تطبق نيفادا الصيغة الفيدرالية للجسور لتحديد الحد الأقصى للوزن على مجموعة من المحاور المتتالية. يمكن أن تحمل مجموعتان متتاليتان من المحاور المزدوجة (تاندم) كل منهما 34,000 رطل إذا كانت المسافة بين المحور الأول والأخير للمجموعة لا تقل عن كم قدمًا؟","options":["30 قدمًا","33 قدمًا","36 قدمًا","40 قدمًا"],"explanation":"بموجب الصيغة الفيدرالية للجسور كما تُطبَّق في نيفادا، يمكن أن تحمل مجموعتان متتاليتان من المحاور المزدوجة (تاندم) كل منهما 34,000 رطل إذا كانت المسافة الإجمالية بين المحور الأول والأخير 36 قدمًا أو أكثر (NRS 484D.660؛ 23 U.S.C. 127، الصيغة الفيدرالية للجسور)."},"14":{"q":"يريد ناقل نقل حمولة بعرض 110 بوصات على طريق سريع في نيفادا. ما هو المطلوب؟","options":["لا شيء، لأنها ضمن العرض القانوني","تصريح أبعاد زائدة من وزارة النقل في نيفادا","فقط أضواء تحذيرية كهرمانية على كل زاوية","إعفاء من دورية الطرق السريعة في نيفادا"],"explanation":"الحمولة الأعرض من الحد القانوني البالغ 102 بوصة تُعدّ ذات أبعاد زائدة وتتطلب تصريح أبعاد زائدة من NDOT قبل أن يُسمح بنقلها (NRS 484D.685؛ NDOT)."},"15":{"q":"ما هو الغرض من الصيغة الفيدرالية للجسور التي تطبقها نيفادا على نظام الطرق بين الولايات؟","options":["تحدد السرعة القصوى للشاحنات الثقيلة","تحدّ من الوزن على مجموعة من المحاور بناءً على عدد المحاور والمسافة بينها","تحدد رسوم تسجيل المركبات التجارية","تحدد الحد الأقصى لطول المقطورة"],"explanation":"تضع الصيغة الفيدرالية للجسور حدًا أقصى للوزن الإجمالي الذي يمكن أن تحمله أي مجموعة من محورين متتاليين أو أكثر، بناءً على عدد المحاور والتباعد بين المحاور الخارجية للمجموعة، لحماية الجسور (NRS 484D.660؛ 23 U.S.C. 127، الصيغة الفيدرالية للجسور)."},"16":{"q":"تُمنح مركبة تنقل منتجات زراعية مكدسة بشكل غير محكم (غير مبلّطة) مثل التبن أو القش بكميات سائبة استثناءً في العرض في نيفادا. ما هو الحد الأقصى للعرض المسموح به لتلك الحمولة وحواملها المثبِّتة؟","options":["102 بوصة","108 بوصات","114 بوصة","120 بوصة"],"explanation":"تسمح نيفادا بأن تصل حمولة المنتجات الزراعية المكدسة بشكل غير محكم (غير المعبّأة في صناديق أو المبلّطة أو الموضوعة في علب أو أكياس) بالإضافة إلى أي حوامل مثبِّتة إلى عرض يصل إلى 120 بوصة، وهو استثناء من المعيار البالغ 102 بوصة (NRS 484D.705)."},"17":{"q":"تسمح نيفادا لحمولة من التبن المبلّط بتجاوز حد الارتفاع العادي البالغ 14 قدمًا. ما هو الحد الأقصى للارتفاع المسموح به لحمولة من التبن المبلّط؟","options":["14 قدمًا و6 بوصات","15 قدمًا","16 قدمًا","17 قدمًا"],"explanation":"في حين أن حد الارتفاع العام هو 14 قدمًا، تسمح نيفادا بحمل حمولة من التبن المبلّط حتى ارتفاع 15 قدمًا (NRS 484D.605)."},"18":{"q":"عندما تقرر NDOT أن المركبات التي تعمل بأقصى وزن قانوني من المرجح أن تسبب إجهادًا كبيرًا لطريق سريع أو جسر أو شارع معين، ماذا يمكن أن تفعل NDOT أو الهيئة الإدارية المحلية؟","options":["إغلاق الطريق نهائيًا أمام جميع حركة المرور التجارية","تخفيض حدود الوزن المسموح بها على ذلك الطريق السريع أو الطريق أو الشارع","مطالبة جميع الشاحنات بإضافة مقطورة ثالثة","زيادة حد المحور المفرد على مستوى الولاية للتعويض"],"explanation":"يجوز لـ NDOT والهيئات الإدارية المحلية تخفيض حدود الوزن على أي طريق سريع أو طريق أو شارع حيث يكون من المرجح أن تسبب المركبات ذات الوزن الأقصى المسموح به إجهادًا هيكليًا كبيرًا (NRS 484D.660)."},"19":{"q":"يحتاج ناقل آلي إلى تصريح وزن زائد سنوي للنقل الروتيني في نيفادا. وفقًا لإرشادات NDOT، قبل كم من الوقت يُنصح الناقل بتقديم الطلب عبر نظام تصاريح الأبعاد الزائدة؟","options":["قبل 24 ساعة على الأقل","قبل 7 أيام على الأقل","قبل 30 يومًا على الأقل","قبل 90 يومًا على الأقل"],"explanation":"تنصح NDOT حاملي التصاريح بالتخطيط قبل 30 يومًا على الأقل من الحركة المرغوبة أو قبل انتهاء صلاحية تصريح سنوي قائم؛ تُقدَّم الطلبات من خلال نظام التصاريح الإلكتروني للأبعاد الزائدة التابع لـ NDOT (NDOT؛ NRS 484D.625)."},"20":{"q":"في نيفادا، أي فئة من رخصة القيادة التجارية (CDL) مطلوبة لتشغيل مجموعة من المركبات بتصنيف وزن إجمالي مجمّع يتجاوز 26,000 رطل عندما يكون للوحدة المسحوبة تصنيف وزن إجمالي للمركبة (GVWR) يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تشترط نيفادا رخصة CDL من الفئة A للمركبات المجمّعة التي تتجاوز 26,000 رطل حيث تتجاوز المقطورة/الوحدة المسحوبة 10,000 رطل من GVWR. المصدر: Nevada DMV CDL-051 'Commercial Driver License Information' و dmv.nv.gov/cdlcertify.htm (فئات الرخص)."},"21":{"q":"أي فئة من رخصة CDL في نيفادا تشمل أي مركبة مفردة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر، مثل حافلة كبيرة أو شاحنة مستقيمة، تسحب وحدة لا تتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تشمل رخصة CDL من الفئة B في نيفادا المركبات المفردة التي تبلغ 26,001 رطل أو أكثر (الحافلات، الشاحنات الكبيرة) والتي تسحب وحدة أقل من 10,001 رطل. المصدر: Nevada DMV cdlcertify.htm و CDL-051."},"22":{"q":"بموجب قواعد نيفادا، المركبة التي لا تستوفي حدود حجم الفئة A أو B ولكنها مصممة لنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو التي تنقل مواد خطرة تتطلب لوحات تحذيرية، تتطلب أي فئة من CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة P"],"explanation":"رخصة CDL من الفئة C في نيفادا مخصصة للمركبات الواقعة تحت حدود الوزن للفئتين A/B التي تنقل 16 راكبًا أو أكثر (بما في ذلك السائق) أو التي تتطلب لوحة تحذيرية للمواد الخطرة. المصدر: Nevada DMV cdlcertify.htm و CDL-051."},"23":{"q":"ما هو الحد الأدنى للسن لإصدار رخصة CDL في نيفادا لتشغيل مركبة آلية تجارية في التجارة بين الولايات؟","options":["18 عامًا","19 عامًا","21 عامًا","25 عامًا"],"explanation":"تشترط نيفادا أن يكون المتقدمون في سن 21 على الأقل لتشغيل مركبة آلية تجارية في التجارة بين الولايات. المصدر: Nevada DMV CDL-051 'Minimum Age'."},"24":{"q":"في نيفادا، يمكن منح المتقدم الذي تتراوح أعماره بين 18 و20 عامًا رخصة CDL فقط لأي نوع من التشغيل؟","options":["التجارة بين الولايات فقط","التجارة داخل الولاية فقط","طرق الحكومة الفيدرالية فقط","نقل الركاب فقط"],"explanation":"تسمح نيفادا للذين تتراوح أعمارهم بين 18 و20 عامًا برخصة CDL للتجارة داخل الولاية فقط؛ ولا يمكنهم نقل الركاب مقابل أجر أو نقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: Nevada DMV CDL-051 'Minimum Age'."},"25":{"q":"ما هو الحد الأدنى للسن في نيفادا للحصول على التظهير المطلوب لقيادة مركبة مجمّعة زائدة الطول (70 قدمًا)؟","options":["21 عامًا","23 عامًا","25 عامًا","26 عامًا"],"explanation":"تشترط نيفادا أن يكون السائقون في سن 25 على الأقل لقيادة مركبة مجمّعة زائدة الطول تبلغ 70 قدمًا. المصدر: Nevada DMV CDL-051 'Minimum Age'؛ انظر أيضًا NRS 484D.615 (قيود الطول)."},"26":{"q":"كم تبلغ مدة صلاحية تصريح المتعلم التجاري (CLP) في نيفادا من تاريخ إصداره؟","options":["60 يومًا","90 يومًا","180 يومًا","سنة واحدة"],"explanation":"تصريح CLP في نيفادا صالح لمدة 180 يومًا من الإصدار (قد يتطلب التجديد إعادة الاختبار). المصدر: Nevada DMV dmv.nv.gov/clp.htm و CDL-051 'CLP Conditions'."},"27":{"q":"بموجب القواعد الفيدرالية وقواعد نيفادا، كم من الوقت يجب الاحتفاظ بتصريح المتعلم التجاري قبل أن يتمكن حامله من إجراء اختبار مهارات CDL؟","options":["7 أيام على الأقل","14 يومًا على الأقل","21 يومًا على الأقل","30 يومًا على الأقل"],"explanation":"يجب الاحتفاظ بتصريح CLP في نيفادا لمدة 14 يومًا على الأقل قبل اختبار المهارات، بما يتوافق مع المتطلب الفيدرالي. المصدر: Nevada DMV clp.htm و CDL-051 'CLP Conditions'."},"28":{"q":"قبل إصدار تصريح CLP أو رخصة CDL، كم عدد إثباتات الإقامة في نيفادا التي تطلبها Nevada DMV من المتقدم لتقديمها؟","options":["إثبات واحد","إثباتان","ثلاثة إثباتات","لا يلزم إثبات"],"explanation":"تشترط نيفادا إثباتين للإقامة يُظهران اسم المتقدم وعنوان إقامته في نيفادا. المصدر: Nevada DMV CDL-051 'Proof of residency'."},"29":{"q":"أي وثيقة مقبولة لدى Nevada DMV كإثبات لرقم الضمان الاجتماعي للمتقدم للحصول على CDL؟","options":["بطاقة تسجيل ناخب","بطاقة الضمان الاجتماعي، أو نموذج W-2، أو كعب راتب يُظهر الرقم بالكامل","تسجيل مركبة في نيفادا","إقرار شخصي موقّع"],"explanation":"تقبل نيفادا بطاقة الضمان الاجتماعي، أو نموذج W-2، أو نموذج 1099، أو كعب راتب يدرج رقم الضمان الاجتماعي بالكامل كإثبات لرقم الضمان الاجتماعي. المصدر: Nevada DMV CDL-051 'Proof of Your Social Security Number'."},"30":{"q":"بالنسبة لمتقدم CDL مولود في الولايات المتحدة، أي وثيقة تقبلها Nevada DMV كإثبات إضافي للهوية؟","options":["شهادة ميلاد مصدّقة أو جواز سفر أمريكي","شهادة دبلوم من المدرسة الثانوية","بطاقة مكتبة","كشف حساب بطاقة ائتمان"],"explanation":"تقبل نيفادا شهادة ميلاد مصدّقة (أو ملخصًا لها) أو جواز سفر أمريكي كإثبات إضافي للهوية للمتقدمين المولودين في الولايات المتحدة؛ ويجب أن تكون الوثائق أصلية. المصدر: Nevada DMV CDL-051 'Additional Proof of Identity'."},"31":{"q":"يجب على متقدم CDL المولود خارج الولايات المتحدة أن يقدم أيًا مما يلي إلى Nevada DMV لإثبات الوجود القانوني؟","options":["رخصة قيادة أجنبية","جواز سفر أجنبي ساري المفعول وغير منتهي الصلاحية مع ختم I-94، أو بطاقة الإقامة الدائمة، أو شهادة التجنّس","بطاقة عمل قنصلية","بطاقة هوية طالب من أي بلد"],"explanation":"تشترط نيفادا على المتقدمين المولودين في الخارج إظهار جواز سفر أجنبي ساري المفعول وغير منتهي الصلاحية (مع ختم I-94)، أو بطاقة الإقامة الدائمة، أو شهادة التجنّس. المصدر: Nevada DMV CDL-051 'Additional Proof of Identity'."},"32":{"q":"أي تظهير CDL في نيفادا مطلوب لنقل المواد الخطرة بكميات تتطلب لوحات تحذيرية؟","options":["تظهير N","تظهير T","تظهير H","تظهير P"],"explanation":"تظهير H (المواد الخطرة) مطلوب لنقل المواد الخطرة التي تتطلب لوحات تحذيرية في نيفادا. المصدر: Nevada DMV CDL-051 'Endorsements' و dmv.nv.gov/cdl.htm."},"33":{"q":"بالإضافة إلى حمل رخصة CDL وهوية صالحة، ما الذي يجب على المتقدم في نيفادا إكماله قبل أن يمكن إصدار تظهير المواد الخطرة (H)؟","options":["دورة قيادة دفاعية","فحص خلفية قائم على البصمات","اختبار مهارات طريق ثانٍ","تظهير طول 70 قدمًا"],"explanation":"تشترط نيفادا على المتقدم اجتياز فحص خلفية قائم على البصمات (TSA)؛ ولا يجوز إجراء اختبار معرفة المواد الخطرة حتى يكتمل فحص الخلفية. المصدر: Nevada DMV CDL-051 'Hazmat Endorsement'."},"34":{"q":"أي تظهير CDL في نيفادا مطلوب لتشغيل مركبة صهريج تنقل مواد سائلة أو غازية في صهريج سائب مثبّت بشكل دائم؟","options":["تظهير T","تظهير N","تظهير S","تظهير X"],"explanation":"تظهير N (مركبة الصهريج) مطلوب لتشغيل مركبات الصهاريج في نيفادا. المصدر: Nevada DMV CDL-051 'Endorsements'."},"35":{"q":"على رخصة تجارية في نيفادا، ماذا يدل عليه تظهير X؟","options":["صلاحية المقطورات المزدوجة/الثلاثية","تظهير مشترك للمواد الخطرة والصهاريج (صهريج مواد خطرة)","تظهير حافلة مدرسية","تظهير مركبة زائدة الطول"],"explanation":"تدرج نيفادا X باعتباره تظهير صهريج المواد الخطرة (يجمع بين متطلبات H وN). المصدر: Nevada DMV CDL-051 'Endorsements'."},"36":{"q":"أي تظهير تشترطه نيفادا على السائق لسحب مقطورات مزدوجة أو ثلاثية؟","options":["تظهير P","تظهير S","تظهير T","تظهير N"],"explanation":"تظهير T (المقطورات المزدوجة/الثلاثية) مطلوب لسحب المقطورات المزدوجة أو الثلاثية في نيفادا. المصدر: Nevada DMV CDL-051 'Endorsements'."},"37":{"q":"السائق الذي يرغب في قيادة حافلة مدرسية عامة في نيفادا يجب أن يحمل أي مجموعة من التظهيرات؟","options":["تظهيرا P وS","تظهيرا N وT","تظهيرا H وX","تظهير S فقط"],"explanation":"يجب على سائق الحافلة المدرسية في نيفادا أن يحمل كلًا من تظهير الركاب (P) وتظهير الحافلة المدرسية (S)، ويتطلب كل منهما اختبار معرفة ومهارات إضافيًا. المصدر: مواد CDL الخاصة بـ Nevada DMV؛ دليل تدريب سائقي الحافلات المدرسية في نيفادا (ELDT لـ P وS)."},"38":{"q":"أين يجب على السائق التجاري المبتدئ في نيفادا إكمال تدريب السائق المبتدئ المطلوب (ELDT)؟","options":["أي نشاط تجاري مرخّص في نيفادا","مزوّد مدرج في السجل الفيدرالي لمزوّدي التدريب","مكتب شريف المقاطعة","دورة عبر الإنترنت من اختيار السائق"],"explanation":"تشترط نيفادا على السائقين التجاريين المبتدئين إكمال ELDT من مزوّد مدرج في السجل الفيدرالي لمزوّدي التدريب التابع لـ FMCSA. المصدر: Nevada DMV CDL-051 'Entry Level Driver Training (ELDT)'؛ 49 CFR Part 380."},"39":{"q":"عند التصديق الذاتي لدى Nevada DMV، أي فئة تنطبق على حامل CDL الذي يقود فقط داخل نيفادا ويخضع لمعايير التأهيل البدني للولاية (وليس الفيدرالية Part 391)؟","options":["غير مُعفى بين الولايات","مُعفى بين الولايات","غير مُعفى داخل الولاية","مُعفى بين الولايات-مُعفى"],"explanation":"تنطبق فئة 'غير مُعفى داخل الولاية' على السائقين الذين يعملون فقط داخل نيفادا ويخضعون لمعايير تأهيل السائق الخاصة بالولاية. المصدر: Nevada DMV dmv.nv.gov/cdlcertify.htm (فئات التصديق الذاتي)؛ 49 CFR 383.71."},"40":{"q":"أثناء تشغيل مركبة آلية تجارية (CMV) في نيفادا، يُعتبر سائق CDL مخمورًا قانونيًا ويرتكب مخالفة كبرى عند أي تركيز للكحول في الدم (BAC)؟","options":["0.04 بالمئة أو أعلى","0.08 بالمئة أو أعلى","0.02 بالمئة أو أعلى","0.10 بالمئة أو أعلى"],"explanation":"تطبق نيفادا المعيار الفيدرالي لـ CMV: تُعدّ مخالفة كبرى موجبة لسحب الأهلية تشغيل CMV بتركيز كحول في الدم BAC يبلغ 0.04 بالمئة أو أكثر (لا يزال الحد العام لسائق غير حامل CDL البالغ 0.08 بالمئة ينطبق في أي مركبة). المصدر: Nevada Commercial Driver Handbook (سحب الأهلية) و 49 CFR 383.51."},"41":{"q":"بموجب قانون الموافقة الضمنية في نيفادا، ماذا يحدث إذا رفض سائق CDL الخضوع لفحص كيميائي للدم أو النَفَس أو البول عند طلبه بشكل قانوني؟","options":["تُلغى رخصة السائق تلقائيًا، ويُعدّ الرفض نفسه مخالفة كبرى موجبة لسحب الأهلية","لا يحدث شيء ما لم يُدَن السائق لاحقًا بالقيادة تحت تأثير الكحول في المحكمة","يُصدر تحذير كتابي فقط عن أول رفض","يدفع السائق غرامة مدنية قدرها $250 دون أي إجراء على الرخصة"],"explanation":"بقيادته في نيفادا، يمنح حامل CDL موافقة ضمنية على الفحص؛ ويؤدي الرفض إلى إلغاء تلقائي للرخصة من قبل DMV ويُحتسب مخالفة كبرى تسحب أهلية CDL حتى لو تمت تبرئة السائق لاحقًا. المصدر: قوانين الموافقة الضمنية في نيفادا (NRS Chapter 484C) و Nevada Commercial Driver Handbook."},"42":{"q":"بالنسبة لأول مخالفة كبرى (مثل القيادة تحت تأثير الكحول أو رفض الفحص) ارتُكبت أثناء عدم نقل مواد خطرة تتطلب لوحات تحذيرية، كم تبلغ مدة سحب أهلية CDL في نيفادا؟","options":["سنة واحدة","60 يومًا","3 سنوات","6 أشهر"],"explanation":"تسحب أول مخالفة كبرى أهلية CDL لمدة لا تقل عن سنة واحدة. المصدر: Nevada Commercial Driver Handbook (سحب الأهلية) و 49 CFR 383.51."},"43":{"q":"إذا ارتُكبت أول مخالفة كبرى (مثل القيادة تحت تأثير الكحول) أثناء تشغيل السائق لـ CMV تنقل مواد خطرة تتطلب لوحات تحذيرية، فإن مدة سحب أهلية CDL في نيفادا تزداد إلى:","options":["3 سنوات","سنة واحدة","5 سنوات","مدى الحياة"],"explanation":"تحمل أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة تتطلب لوحات تحذيرية سحبًا للأهلية لمدة 3 سنوات بدلاً من السنة الواحدة المعيارية. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"44":{"q":"ما هي مدة سحب أهلية CDL في نيفادا لمخالفة كبرى ثانية (على سبيل المثال، إدانة ثانية بالقيادة تحت تأثير الكحول في CMV)؟","options":["سحب الأهلية مدى الحياة","10 سنوات","3 سنوات","5 سنوات"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى سحب أهلية CDL مدى الحياة (قد تتوفر إعادة محدودة بعد 10 سنوات على الأقل فقط بموجب شروط محددة). المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"45":{"q":"يُدان سائق CDL في نيفادا بمخالفتين مروريتين خطيرتين في حادثتين منفصلتين خلال فترة 3 سنوات. تُسحب أهلية CDL لمدة:","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات (في حادثتين منفصلتين) إلى سحب أهلية CDL لمدة 60 يومًا. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"46":{"q":"يُدان سائق CDL في نيفادا بثلاث مخالفات مرورية خطيرة في حوادث منفصلة خلال فترة 3 سنوات. تُسحب أهلية CDL لمدة:","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات (في حوادث منفصلة) إلى سحب أهلية CDL لمدة 120 يومًا، تُنفَّذ بالإضافة إلى أي سحب أهلية سابق لمدة 60 يومًا. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"47":{"q":"أي مما يلي يُحتسب مخالفة مرورية خطيرة لأغراض سحب أهلية CDL في نيفادا؟","options":["تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المعلن","تجاوز السرعة بمقدار 5 أميال في الساعة فوق الحد المعلن","مخالفة وقوف غير متحركة","القيادة بتسجيل مركبة منتهي الصلاحية"],"explanation":"تجاوز السرعة المفرط، المُعرّف بأنه 15 ميلاً في الساعة أو أكثر فوق الحد المعلن، هو مخالفة مرورية خطيرة مدرجة. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"48":{"q":"أي مجموعة من المخالفات تُصنّف جميعها كمخالفات مرورية خطيرة بموجب قواعد CDL في نيفادا؟","options":["القيادة المتهورة، والاقتراب الشديد من المركبة الأمامية، وتغيير المسار بشكل غير سليم أو غير منتظم","القيادة تحت تأثير الكحول، ومغادرة مكان الحادث، واستخدام CMV في جناية","رفض الفحص الكيميائي، وقيادة ثانية تحت تأثير الكحول، والهروب من حادث مميت","مخالفة تصريح الوزن الزائد، وبطاقة طبية منتهية الصلاحية، ورسوم مرور غير مدفوعة"],"explanation":"القيادة المتهورة، والاقتراب الشديد من المركبة الأمامية، وتغيير المسار بشكل غير سليم أو غير منتظم هي جميعها مخالفات مرورية خطيرة. أما المخالفات الأخرى المدرجة فهي مخالفات كبرى أو ليست جزءًا من قائمة المخالفات الخطيرة. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"49":{"q":"قيادة CMV في نيفادا دون الفئة الصحيحة من رخصة CDL أو تصريح المتعلم التجاري، أو دون حملها بحوزتك، تُصنّف على أنها:","options":["مخالفة مرورية خطيرة","مخالفة كبرى","مخالفة أمر إيقاف عن الخدمة","خطأ ورقي غير موجب لسحب الأهلية"],"explanation":"تشغيل CMV دون رخصة CDL/تصريح CLP الصحيح، أو دون حملها بحوزتك، هو مخالفة مرورية خطيرة تُحتسب ضمن سحب الأهلية لمدة 60 يومًا/120 يومًا. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"50":{"q":"بالنسبة لأول إدانة بمخالفة معبر سكة حديد-طريق سريع في CMV، تُسحب أهلية CDL في نيفادا لمدة لا تقل عن:","options":["60 يومًا","30 يومًا","120 يومًا","سنة واحدة"],"explanation":"تسحب أول مخالفة لمعبر سكة حديد-طريق سريع أهلية CDL لمدة لا تقل عن 60 يومًا. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"51":{"q":"مخالفة ثانية لمعبر سكة حديد-طريق سريع خلال فترة 3 سنوات تسحب أهلية CDL في نيفادا لمدة لا تقل عن:","options":["120 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"تسحب مخالفة ثانية لمعبر سكة حديد خلال أي فترة 3 سنوات أهلية CDL لمدة لا تقل عن 120 يومًا. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"52":{"q":"مخالفة ثالثة لمعبر سكة حديد-طريق سريع خلال فترة 3 سنوات تسحب أهلية CDL في نيفادا لمدة لا تقل عن:","options":["سنة واحدة","120 يومًا","180 يومًا","60 يومًا"],"explanation":"تسحب مخالفة ثالثة لمعبر سكة حديد خلال أي فترة 3 سنوات أهلية CDL لمدة لا تقل عن سنة واحدة. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"53":{"q":"إذا خالف السائق أمر إيقاف عن الخدمة أثناء نقل مواد خطرة تتطلب لوحات تحذيرية أو تشغيل مركبة مصممة لـ 16 راكبًا أو أكثر، فإن سحب الأهلية للمخالفة الأولى يكون:","options":["لا يقل عن 180 يومًا ولا يزيد عن سنتين","لا يقل عن 90 يومًا ولا يزيد عن سنة واحدة","لا يقل عن سنة واحدة ولا يزيد عن 5 سنوات","120 يومًا بالضبط"],"explanation":"تسحب أول مخالفة لأمر إيقاف عن الخدمة أثناء نقل مواد خطرة تتطلب لوحات تحذيرية أو نقل 16 راكبًا أو أكثر أهلية CDL لمدة لا تقل عن 180 يومًا ولا تزيد عن سنتين. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"54":{"q":"بالإضافة إلى سحب الأهلية، يواجه السائق المُدان بمخالفة أمر إيقاف عن الخدمة في نيفادا غرامة مدنية فيدرالية لا تقل عن:","options":["$1,000","$250","$500","$2,750"],"explanation":"يخضع السائق الذي يخالف أمر إيقاف عن الخدمة لغرامة مدنية لا تقل عن $1,000 (وتصل إلى $2,500)، منفصلة عن سحب الأهلية. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51."},"55":{"q":"بموجب قانون نيفادا (NRS 484B.165)، يحمل استخدام هاتف محمول يدوي أو إرسال الرسائل النصية أثناء القيادة أي غرامة مدنية للمخالفة الأولى؟","options":["$50","$100","$250","$500"],"explanation":"يحدد قانون نيفادا للأجهزة اليدوية/الرسائل النصية (NRS 484B.165) غرامة مدنية قدرها $50 للمخالفة الأولى، و$100 للثانية، و$250 للثالثة خلال 7 سنوات؛ ولا تُعامَل المخالفة الأولى كمخالفة متحركة. المصدر: NRS 484B.165."},"56":{"q":"بالنسبة لحامل CDL، كيف يؤثر استخدام هاتف يدوي أو إرسال الرسائل النصية أثناء تشغيل CMV على الرخصة التجارية بموجب قواعد نيفادا/الفيدرالية؟","options":["إنها مخالفة مرورية خطيرة يمكن أن تؤدي إلى سحب الأهلية لمدة 60 أو 120 يومًا في حال تكرارها","إنها مخالفة كبرى تسبب سحب الأهلية لمدة سنة واحدة عند المخالفة الأولى","تؤدي فقط إلى غرامة قدرها $50 دون أي تأثير على CDL","إنها مخالفة إيقاف عن الخدمة تحمل سحب الأهلية لمدة 90 يومًا"],"explanation":"إرسال الرسائل النصية أو استخدام هاتف محمول يدوي أثناء قيادة CMV هو مخالفة مرورية خطيرة؛ تسحب مخالفتان خلال 3 سنوات أهلية CDL لمدة 60 يومًا وثلاث خلال 3 سنوات لمدة 120 يومًا. المصدر: Nevada Commercial Driver Handbook و 49 CFR 383.51 / 392.80-392.82."},"57":{"q":"تحدد نيفادا سقفًا للغرامة على مخالفة تجاوز السرعة بموجب قانون القاعدة الأساسية (NRS 484B.600) بأي مبلغ لكل ميل في الساعة فوق الحد؟","options":["$20 عن كل ميل في الساعة فوق الحد","$25 عن كل ميل في الساعة فوق الحد","$10 عن كل ميل في الساعة فوق الحد","$50 عن كل ميل في الساعة فوق الحد"],"explanation":"تحدد نيفادا سقفًا لغرامة تجاوز السرعة بـ $20 عن كل ميل في الساعة يقطعه السائق فوق الحد المعلن؛ وبالنسبة لحامل CDL، يبقى تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر مخالفة مرورية خطيرة بغض النظر عن مبلغ الغرامة. المصدر: NRS 484B.600 و Nevada Commercial Driver Handbook."},"58":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في نيفادا، عندما تقترب من مركبة طوارئ متوقفة، أو شاحنة قطر، أو مركبة تابعة لـ NDOT تعرض أضواءً وامضة على طريق سريع، ماذا يجب عليك أن تفعل؟","options":["أن تخفّض السرعة إلى معدّل معقول، وتتابع السير بحذر، وإذا أمكن تنتقل إلى مسار غير مجاور للمركبة المتوقفة","أن تتوقف توقفاً تاماً حتى يتم إطفاء أضواء مركبة الطوارئ","أن تحافظ على حدّ السرعة المعلن لكن تطلق منبّه السيارة أثناء التجاوز","أن تنتقل إلى الكتف الأيمن وتنتظر ضابطاً يشير لك بالمرور"],"explanation":"يقتضي قانون \"أفسح الطريق\" في نيفادا (NRS 484B.607) أن يخفّض السائقون السرعة إلى معدّل معقول وسليم، وأن يتابعوا السير بحذر، وأن يكونوا مستعدين للتوقف، وإذا أمكن أن ينتقلوا إلى مسار غير مجاور مباشرةً للمركبة المتوقفة. وينطبق ذلك على مركبات الطوارئ المرخّصة وعلى المركبات التي تعرض أضواءً عنبرية وامضة أو أضواءً زرقاء غير وامضة، بما في ذلك مركبات NDOT. المصدر: NRS 484B.607."},"59":{"q":"على طريق سريع مقسوم في نيفادا يفصله حاجز مادي أو قسم فاصل، توقفت حافلة مدرسية في الطريق الآخر وهي تعرض أضواءً حمراء وامضة لإركاب الأطفال. ماذا يجب على سائق يسير في اتجاهك أن يفعل؟","options":["أن يتوقف حتى تتوقف الأضواء الحمراء عن الوميض، تماماً كما على طريق غير مقسوم","ليس ملزماً بالتوقف، لأن الحافلة موجودة في الطريق الآخر من طريق سريع مقسوم","أن يخفّض السرعة إلى 15 mph ويتجاوز بحذر في المسار البعيد","أن يتوقف فقط إذا كان الأطفال يعبرون الجزيرة الوسطى على نحو ظاهر"],"explanation":"بموجب NRS 484B.353، فإن سائق المركبة على طريق سريع مقسوم ليس ملزماً بالتوقف عند مقابلته أو تجاوزه حافلة مدرسية موجودة في الطريق الآخر. وتعرّف نيفادا الطريق السريع المقسوم بأنه طريق يفصله حاجز مادي أو قسم فاصل، لذا يتطلب هذا الاستثناء طريقاً مقسوماً حقيقياً، وليس مجرد خط أوسط أو مسار انعطاف. المصدر: NRS 484B.353."},"60":{"q":"عندما تقترب حافلة مدرسية في نيفادا تقل أطفالاً، أو حافلة تقل ركاباً، أو مركبة تحمل مواد خطرة موسومة بلافتات من تقاطع سكة حديد على مستوى الطريق يجب التوقف عنده، ضمن أي مسافة من أقرب قضيب يجب أن تتوقف؟","options":["ما لا يقل عن 5 feet ولا يزيد عن 25 feet من أقرب قضيب","ما لا يقل عن 25 feet ولا يزيد عن 75 feet من أقرب قضيب","ما لا يقل عن 15 feet ولا يزيد عن 50 feet من أقرب قضيب","ما لا يقل عن 50 feet ولا يزيد عن 100 feet من أقرب قضيب"],"explanation":"يقتضي NRS 484B.560 أن تتوقف الحافلة التي تقل ركاباً، أو الحافلة المدرسية التي تقل أطفالاً، أو المركبة التي تحمل مواد خطرة موسومة بلافتات، ضمن 50 feet لكن ليس أقل من 15 feet من أقرب قضيب قبل العبور على مستوى الطريق. المصدر: NRS 484B.560."},"61":{"q":"في نيفادا، إن المركبة التجارية المحرّكة التي لا يُطلب منها التوقف الكامل عند تقاطع سكة حديد على مستوى الطريق يقع عليها مع ذلك واجب محدّد قبل العبور. ما هو؟","options":["أن تحافظ على سرعة الطريق السريع لتجتاز التقاطع بأسرع ما يمكن","أن تتوقف، وتشغّل فرامل الانتظار، وتنزل النافذة للإصغاء","أن تطلق المنبّه مرتين وتتابع السير دون إبطاء","أن تخفّض السرعة وتتأكد من خلوّ القضبان من أي قطار مقترب"],"explanation":"ينص NRS 484B.560 على أن المركبة التجارية المحرّكة (كما هي معرّفة في 49 C.F.R. 383.5) التي لا يُطلب منها التوقف بخلاف ذلك يجب، قبل العبور على مستوى الطريق، أن تخفّض سرعتها وتتأكد من خلوّ القضبان من أي قطار مقترب أو معدات على القضبان. المصدر: NRS 484B.560."},"62":{"q":"ما هو أقصى حدّ سرعة يمكن أن يُعلن على أي طريق سريع في نيفادا؟","options":["65 miles per hour","80 miles per hour","75 miles per hour","85 miles per hour"],"explanation":"بموجب NRS 484B.613، يجوز لـ NDOT تحديد حدود سرعة لا تتجاوز 80 miles per hour على طرق الولاية السريعة، و80 mph هو أعلى حدّ معلن موجود في نيفادا (على مقاطع محدّدة من الطرق السريعة بين الولايات في المناطق الريفية). المصدر: NRS 484B.613؛ NRS 484B.617."},"63":{"q":"هل يحدّد قانون نيفادا حدّاً أقصى واحداً للسرعة على مستوى الولاية للشاحنات يكون أدنى من الحدّ المخصّص لسيارات الركاب؟","options":["نعم، تقتصر سرعة الشاحنات على 55 mph في كل أنحاء الولاية","نعم، تقتصر سرعة الشاحنات على 60 mph على جميع الطرق بين الولايات","لا يوجد حدّ أدنى واحد للشاحنات على مستوى الولاية؛ يجوز لـ NDOT تحديد حدّ أدنى للشاحنات حيث يكون معلناً","نعم، يجب أن تسير الشاحنات دائماً بسرعة تقلّ بالضبط 10 mph عن الحدّ المعلن للسيارات"],"explanation":"بخلاف بعض الولايات، لا تفرض نيفادا حدّاً أدنى شاملاً لسرعة الشاحنات على مستوى الولاية. يخوّل NRS 484B.613 لـ NDOT تحديد حدّ سرعة أدنى للشاحنات والمركبات ذات الأبعاد الزائدة والحافلات حيث تبرّر الدراسات ذلك، معلناً بلافتة؛ وإلا فإن الشاحنات تتبع الحدّ المعلن. المصدر: NRS 484B.613."},"64":{"q":"على طريق سريع محدود الدخول في نيفادا، متى يُطلب من السائق الخروج من المسار الأيسر الأقصى؟","options":["فقط عندما تحظر لافتة بشكل محدّد على الشاحنات استخدام المسار الأيسر","كلما كانت أي مركبة على بُعد 500 feet خلفه، بغض النظر عن السرعة","فقط خلال ساعات الظلام الليلية","عندما يسير بسرعة أبطأ من حدّ السرعة المعلن ويجري تجاوزه من مركبة أسرع من الخلف"],"explanation":"يقتضي NRS 484B.208 أن ينتقل السائق في المسار الأيسر الأقصى من طريق سريع محدود الدخول خارج ذلك المسار عندما يسير بسرعة أدنى من حدّ السرعة المعلن ويجري تجاوزه من مركبة أسرع. وتشمل الاستثناءات التجاوز، والتحضير للانعطاف يساراً، وأعمال إنشاء الطرق، واستخدام مسار HOV، والسير داخل مدينة أو بلدة. المصدر: NRS 484B.208."},"65":{"q":"بعد إيقاف مركبة تجارية على كتف طريق سريع في نيفادا ذي مسارين واتجاهين، خلال كم دقيقة يجب أن تضع أجهزة التحذير من الطوارئ؟","options":["خلال 10 minutes","خلال 5 minutes","خلال 15 minutes","خلال 30 minutes"],"explanation":"تقتضي القاعدة الفيدرالية 49 C.F.R. 392.22، التي تطبّقها نيفادا على المركبات التجارية المحرّكة، وضع مثلثات عاكسة (أو أجهزة معتمدة أخرى) خلال 10 minutes من التوقف على الجزء المخصّص للسير أو على كتف الطريق السريع. المصدر: 49 C.F.R. 392.22؛ دليل السائق التجاري في نيفادا."},"66":{"q":"على طريق في نيفادا ذي مسارين واتجاهين، أين تضع مثلثات التحذير الثلاثة من الطوارئ لمركبة تجارية محرّكة متوقفة (ليست قرب تلّة أو منعطف)؟","options":["10 feet، و50 feet، و100 feet، جميعها خلف المركبة","25 feet، و75 feet، و150 feet خلف المركبة","10 feet خلف المركبة، و100 feet خلفها، و100 feet أمام المركبة","50 feet أماماً، و50 feet خلفاً، وواحد على سقف المركبة"],"explanation":"وفقاً لـ 49 C.F.R. 392.22، على طريق ذي مسارين واتجاهين تضع مثلثاً واحداً على بُعد نحو 10 feet من المركبة باتجاه حركة المرور المقتربة، وواحداً على بُعد نحو 100 feet إلى الخلف، وواحداً على بُعد نحو 100 feet إلى الأمام، بحيث تُحذّر حركة المرور من كلا الاتجاهين. المصدر: 49 C.F.R. 392.22؛ دليل السائق التجاري في نيفادا."},"67":{"q":"ما هو أقصى عرض قانوني لمركبة تجارية أو حمولتها على طريق سريع في نيفادا قبل أن يُطلب تصريح للأبعاد الزائدة؟","options":["96 inches (8 feet)","114 inches (9 feet 6 inches)","120 inches (10 feet)","102 inches (8 feet 6 inches)"],"explanation":"يحدّد NRS 484D.685 أقصى عرض قانوني لمركبة أو تركيبة أو حمولة بـ 102 inches (8 feet 6 inches)، باستثناء بعض أجهزة السلامة. وأي عرض أكبر من ذلك يتطلب تصريحاً للأبعاد الزائدة. المصدر: NRS 484D.685."},"68":{"q":"ما هو أقصى ارتفاع قانوني، شاملاً الحمولة، لمركبة على طريق سريع في نيفادا؟","options":["14 feet","13 feet 6 inches","15 feet","16 feet"],"explanation":"يحظر NRS 484D.605 تشغيل مركبة على طريق سريع في نيفادا إذا تجاوز ارتفاعها، شاملاً أي حمولة، 14 feet. (يسمح استثناء ضيّق بالقشّ المكبوس حتى 15 feet.) المصدر: NRS 484D.605."},"69":{"q":"على طريق سريع مقسوم أو شارع باتجاه واحد في نيفادا، أين يوضع مثلث التحذير من الطوارئ الأبعد خلف مركبة تجارية محرّكة متوقفة؟","options":["على بُعد نحو 100 feet باتجاه حركة المرور المقتربة","على بُعد نحو 200 feet باتجاه حركة المرور المقتربة","على بُعد نحو 50 feet باتجاه حركة المرور المقتربة","على بُعد نحو 500 feet باتجاه حركة المرور المقتربة"],"explanation":"بموجب 49 C.F.R. 392.22، على طريق باتجاه واحد أو طريق مقسوم توضع المثلثات على بُعد نحو 10 و100 و200 feet باتجاه حركة المرور المقتربة خلف المركبة. المصدر: 49 C.F.R. 392.22؛ دليل السائق التجاري في نيفادا."},"70":{"q":"أي مركبة يقتضي قانون نيفادا أن تتوقف عند كل تقاطع سكة حديد على مستوى الطريق (في غياب استثناء)؟","options":["شاحنة مسطّحة فارغة بلا لافتات","شاحنة توصيل وزنها أقل من 10,000 pounds","سيارة ركاب تقطر مقطورة صغيرة","حافلة مدرسية تقل أطفالاً"],"explanation":"يقتضي NRS 484B.560 أن تتوقف الحافلات التي تقل ركاباً، والحافلات المدرسية التي تقل أطفالاً، والمركبات التي تحمل مواد خطرة موسومة بلافتات، عند جميع تقاطعات سكك الحديد على مستوى الطريق. أما الشاحنة المسطّحة الفارغة غير الموسومة بلافتات، أو الشاحنة الخفيفة، أو السيارة، فليست ضمن فئة التوقف الإلزامي. المصدر: NRS 484B.560."},"71":{"q":"عندما تتوقف حافلة أو مركبة موسومة بلافتات في نيفادا عند تقاطع سكة حديد وتستعد للعبور، ما قاعدة نقل السرعة (الترس) التي تنطبق؟","options":["العبور بترس لا يتطلب أي تبديل أثناء وجودها على التقاطع","خفض الترس إلى أدنى ترس في منتصف التقاطع","النقل إلى الترس المحايد والانزلاق عبر القضبان","استخدام أعلى ترس متاح لاجتياز القضبان بأسرع ما يمكن"],"explanation":"يوجّه NRS 484B.560 بأنه بعد التوقف، يجب على السائق أن يعبر فقط بترس لا يتطلب تبديل التروس أثناء اجتياز التقاطع، وألا يبدّل التروس على القضبان. المصدر: NRS 484B.560."},"72":{"q":"أي حالة تُعدّ استثناءً يعفي حافلة أو مركبة موسومة بلافتات في نيفادا من التوقف الإلزامي عند تقاطع سكة الحديد؟","options":["كون السائق متأخراً عن جدوله الزمني","وجود ضابط شرطة أو موجّه إشارات ينظّم حركة المرور عند التقاطع","احتواء التقاطع على بوابات أوتوماتيكية مرفوعة","تجاوز مدى الرؤية على امتداد القضبان 400 feet"],"explanation":"يعدّد NRS 484B.560 استثناءات تشمل التقاطعات التي ينظّمها ضابط شرطة أو موجّه إشارات، والقضبان المهجورة أو الموسومة بأنها معفاة، وبعض عمليات المناورة الصناعية في منطقة تجارية. أما الرؤية الصافية أو التأخر فليس استثناءً. المصدر: NRS 484B.560."},"73":{"q":"ما هو أقصى وزن إجمالي قانوني للمركبة على طريق سريع في نيفادا قبل أن يُطلب تصريح للوزن الزائد؟","options":["73,280 pounds","90,000 pounds","80,000 pounds","100,000 pounds"],"explanation":"تتبع نيفادا الحدّ الفيدرالي: الوزن الإجمالي الأقصى هو 80,000 pounds، مع 20,000 pounds على المحور الواحد و34,000 pounds على المحور المزدوج، رهناً بصيغة الجسر (bridge formula). وتحتاج الأحمال الأثقل إلى تصريح NDOT للوزن الزائد. المصدر: NRS Chapter 484D (الحجم/الوزن)؛ تصاريح NDOT للأبعاد الزائدة."},"74":{"q":"يخالف سائق قانون \"أفسح الطريق\" في نيفادا لأول مرة على طريق سريع عادي (ليس منطقة عمل). كيف تُصنّف المخالفة عموماً؟","options":["جنحة تحمل غرامة (نحو $395) ونقاطاً سلبية","مخالفة غير متحركة بلا نقاط وبلا غرامة","جناية تستوجب إلغاء الرخصة إلزامياً","مجرد تحذير، بلا عقوبة عن المخالفة الأولى"],"explanation":"تُعدّ مخالفة NRS 484B.607 جنحة؛ وعادةً ما تحمل المخالفة الأولى غرامة في حدود نحو $395 (وتصل إلى نحو $790 في منطقة عمل) إضافةً إلى نقاط سلبية. المصدر: NRS 484B.607."},"75":{"q":"بالنسبة لجرّار شاحنة يسحب نصف مقطورة واحدة في نيفادا، ما هو أقصى طول قانوني لنصف المقطورة (دون تصريح خاص)؟","options":["48 feet","57 feet","60 feet","53 feet"],"explanation":"يسمح NRS 484D.615 بتركيبة جرّار شاحنة ونصف مقطورة لا يتجاوز فيها طول نصف المقطورة 53 feet، كاستثناء من الحدّ العام للتركيبة الكلّي البالغ 70-foot. المصدر: NRS 484D.615."},"76":{"q":"أثناء التوقف عند تقاطع سكة حديد في حافلة مدرسية في نيفادا، إضافةً إلى التوقف على المسافة الصحيحة، ماذا يجب على السائق أن يفعل قبل المتابعة؟","options":["أن يراقب فقط أضواء إشارة التقاطع والبوابات","أن يُصغي وينظر في كلا الاتجاهين على امتداد القضبان بحثاً عن قطار مقترب","أن يطلب من راكب النزول ليوجّه الحافلة عبر التقاطع","أن يعتمد على منبّه القطار وحده كإشارة إلى أن العبور آمن"],"explanation":"يقتضي NRS 484B.560 أن يُصغي السائق، أثناء التوقف، وينظر في كلا الاتجاهين على امتداد القضبان بحثاً عن أي قطار مقترب وعن إشارات تدل على اقتراب قطار قبل العبور. ويُعلَّم السائقون ألا يعتمدوا على الإشارات وحدها. المصدر: NRS 484B.560؛ دليل السائق التجاري في نيفادا."},"77":{"q":"متى يجب عموماً أن تتوقف عن الحركة في نيفادا مركبةٌ تحمل حمولة ذات أبعاد زائدة تسير بموجب تصريح من NDOT؟","options":["فقط بين الظهر والساعة 1:00 p.m. كل يوم","كلما تجاوز حدّ السرعة المعلن 65 mph","أثناء ساعات الظلام، ما لم يأذن التصريح أو التعليمات الخاصة بالسير الليلي","فقط داخل حدود المدينة المسجّلة في أي ساعة"],"explanation":"تحظر شروط تصاريح NDOT للأبعاد الزائدة في نيفادا عموماً السير أثناء ساعات الظلام، وقد تقيّد الحركة في عطلة نهاية الأسبوع والعطل ما لم يأذن التصريح أو التعليمات الخاصة بذلك تحديداً. المصدر: أحكام تصريح NDOT للمركبات ذات الأبعاد الزائدة."},"78":{"q":"أي جهة تُصدر رخص القيادة التجارية (CDLs) في نيفادا؟","options":["إدارة المركبات الآلية في نيفادا (DMV)","الإدارة الفيدرالية لسلامة الناقلات الآلية (FMCSA)","إدارة النقل في نيفادا (NDOT)","دورية الطرق السريعة في نيفادا"],"explanation":"في نيفادا تُصدر إدارة المركبات الآلية (DMV) رخص CDL وتصاريح CLP؛ وتضع FMCSA المعايير الفيدرالية لكنها لا تُصدر الرخصة. المصدر: ترخيص السائق التجاري لدى Nevada DMV (dmv.nv.gov/cdl.htm)."},"79":{"q":"ما مدة صلاحية تصريح المتعلّم التجاري (CLP) في نيفادا؟","options":["180 days","30 days","60 days","1 year"],"explanation":"تُصدر نيفادا تصاريح CLP صالحة لمدة 180 days. المصدر: صفحة تصاريح المتعلّم التجاري لدى Nevada DMV (dmv.nv.gov/clp.htm)."},"80":{"q":"في نيفادا، ما هو الحدّ الأدنى من الوقت الذي يجب أن تحتفظ فيه بتصريح CLP قبل أن يتسنى لك إجراء أي اختبار مهارات لـ CDL؟","options":["14 days","7 days","30 days","60 days"],"explanation":"تشترط نيفادا أن تحتفظ بتصريح CLP لمدة 14 days على الأقل قبل أي اختبار مهارات، تماشياً مع القاعدة الفيدرالية الخاصة بـ CLP. المصدر: صفحة تصاريح المتعلّم التجاري لدى Nevada DMV (dmv.nv.gov/clp.htm)."},"81":{"q":"يتألف اختبار مهارات CDL في نيفادا من ثلاثة أجزاء. أي مجموعة تسردها بشكل صحيح؟","options":["فحص المركبة (ما قبل الرحلة)، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة العامة، والفرامل الهوائية، والمركبات المركّبة","الاختبار التحريري، وفحص النظر، والقيادة على الطريق","فحص ما قبل الرحلة، والمواد الخطرة، والقيادة الليلية"],"explanation":"يتألف اختبار المهارات ذو الأجزاء الثلاثة في نيفادا من فحص المركبة (ما قبل الرحلة)، ومهارات التحكم الأساسية، واختبار القيادة على الطريق. المصدر: ترخيص السائق التجاري لدى Nevada DMV (dmv.nv.gov/cdl.htm)."},"82":{"q":"قبل أن يتسنى لمتقدّم لأول مرة للحصول على CDL في نيفادا إجراء اختبار المهارات، ما التدريب الذي يجب إتمامه؟","options":["تدريب السائق المبتدئ (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب الفيدرالي","دورة قيادة دفاعية معتمَدة من المحاكم","دورة معرفة عامة عبر الإنترنت فقط","دورة شهادة إسعافات أولية وإنعاش قلبي رئوي (CPR)"],"explanation":"تنطبق قواعد ELDT الفيدرالية في نيفادا: يجب على المتقدّمين إتمام التدريب من مزوّد مدرَج في سجل مزوّدي التدريب الفيدرالي قبل إجراء اختبار المهارات. المصدر: Nevada DMV (dmv.nv.gov/cdl.htm)؛ 49 CFR Part 380."},"83":{"q":"من بين كم فئة من فئات التصديق الذاتي يجب أن يختار السائق التجاري في نيفادا عند التقدّم للحصول على CLP أو CDL؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للتصديق الذاتي: بين الولايات غير معفاة، وبين الولايات معفاة، وداخل الولاية غير معفاة، وداخل الولاية معفاة. المصدر: التصديق الذاتي لـ CDL لدى Nevada DMV (dmv.nv.gov/cdlcertify.htm)."},"84":{"q":"أي فئة من فئات التصديق الذاتي تتطلب عموماً من السائق تقديم شهادة فاحص طبي معتمَد من DOT؟","options":["بين الولايات غير معفاة","بين الولايات معفاة","داخل الولاية معفاة","موظف حكومي معفى"],"explanation":"يخضع السائقون بين الولايات غير المعفَون لقواعد التأهيل البدني في 49 CFR Part 391 ويجب أن يحملوا/يقدّموا شهادة فاحص طبي؛ أما الفئات المعفاة فغير مطالَبة بذلك. المصدر: التصديق الذاتي لـ CDL لدى Nevada DMV (dmv.nv.gov/cdlcertify.htm)."},"85":{"q":"أي نموذج لشهادة الفاحص الطبي تقبله Nevada DMV للتصديق الطبي الخاص بـ CDL؟","options":["شهادة الفاحص الطبي MCSA-5876","نموذج DOT رقم HS-2","إعفاء نيفادا الصحي CDL-9","أي خطاب موقّع من طبيب"],"explanation":"تقبل Nevada DMV حصراً شهادة الفاحص الطبي MCSA-5876. المصدر: صفحات التصديق الطبي لـ CDL لدى Nevada DMV (dmv.nv.gov/cdlmedical.htm)."},"86":{"q":"اعتباراً من الإجراء المحدّث في نيفادا، كيف تصل شهادة طبية لسائق غير معفى إلى DMV عادةً؟","options":["يرفعها الفاحص الطبي المعتمَد إلكترونياً إلى السجل الوطني لدى FMCSA، الذي يحيلها إلى DMV","يرسل السائق نسخة ورقية موثّقة بالبريد إلى Carson City","يرسل رب عمل السائق نسخة منها بالفاكس إلى مكتب DMV المحلي","يمسح السائق نسخة منها ضوئياً ويرسلها بالبريد الإلكتروني إلى DMV مباشرةً"],"explanation":"اعتباراً من 16 June 2025، انتقلت نيفادا إلى نظام بلا ورق: يرفع الفاحص شهادة الفحص الطبي (MEC) إلكترونياً إلى FMCSA، التي تحيلها إلى DMV، فلم يعد على السائقين تسليم بطاقات ورقية. المصدر: بيان صحفي لـ Nevada DMV رقم 25013 (dmv.nv.gov)."},"87":{"q":"من المسموح له بإجراء الفحص الطبي لـ DOT الذي يدعم التصديق الذاتي لسائق CDL غير معفى في نيفادا؟","options":["مزوّد مدرَج في السجل الوطني للفاحصين الطبيين المعتمَدين","أي ممرّض ممارس مرخّص في الولاية","طبيب العائلة المعتاد للمتقدّم، بغض النظر عن وضعه في السجل","فنّي تابع لـ Nevada DMV في موقع الاختبار"],"explanation":"يجب أن يُجري الفحصَ مزوّدٌ مدرَج في السجل الوطني للفاحصين الطبيين المعتمَدين؛ ولن تقبل DMV نتائج من مزوّدين غير مدرَجين. المصدر: صفحات CDL الطبية لدى Nevada DMV (dmv.nv.gov/cdlmedical.htm)."},"88":{"q":"ما مدة صلاحية رخصة CDL القياسية في نيفادا قبل أن يجب تجديدها (لسائق دون 65)؟","options":["8 years","4 years","5 years","10 years"],"explanation":"تنتهي صلاحية رخصة CDL في نيفادا في الذكرى الثامنة للإصدار أو التجديد للسائقين دون 65. المصدر: قانون نيفادا الإداري NAC 483.832."},"89":{"q":"بالنسبة لحامل رخصة CDL في نيفادا بعمر 65 عاماً أو أكثر، ما مدة صلاحية رخصة CDL؟","options":["4 years","8 years","2 years","6 years"],"explanation":"تنتهي صلاحية رخصة CDL الصادرة لحامل رخصة بعمر 65 أو أكثر في الذكرى الرابعة لعيد ميلاد حامل الرخصة، بدلاً من 8 years القياسية. المصدر: قانون نيفادا الإداري NAC 483.832."},"90":{"q":"ما هو الحدّ الأدنى للعمر للحصول على رخصة CDL في نيفادا للقيادة داخل الولاية (ضمن نيفادا)؟","options":["18 years old","16 years old","19 years old","21 years old"],"explanation":"يجب أن يكون عمرك 18 على الأقل للحصول على رخصة CDL في نيفادا للتشغيل داخل الولاية. المصدر: صفحات تصاريح المتعلّم التجاري/CDL لدى Nevada DMV (dmv.nv.gov/clp.htm، dmv.nv.gov/cdl.htm)."},"91":{"q":"ما هو الحدّ الأدنى للعمر المطلوب للقيادة في التجارة بين الولايات أو لحمل تظهيرات الركاب أو المواد الخطرة (HazMat) في نيفادا؟","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"تتطلب التجارة بين الولايات وتظهيرات الركاب/المواد الخطرة (hazmat) حدّاً أدنى للعمر يبلغ 21 في نيفادا. المصدر: صفحة CLP لدى Nevada DMV (dmv.nv.gov/clp.htm)."},"92":{"q":"أي اختبار معرفة يجب أن يجتازه متقدّم في نيفادا فقط إذا كانت المركبة التي سيقودها مزوّدة بفرامل هوائية؟","options":["اختبار معرفة الفرامل الهوائية","اختبار المعرفة العامة","اختبار المركبات المركّبة","اختبار المواد الخطرة"],"explanation":"ينطبق اختبار معرفة الفرامل الهوائية عندما تكون المركبة مزوّدة بفرامل هوائية؛ والرسوب فيه أو تخطّيه يؤدي إلى قيد خاص بالفرامل الهوائية. المصدر: ترخيص CDL لدى Nevada DMV (dmv.nv.gov/cdl.htm)."},"93":{"q":"إن المتقدّم في نيفادا الذي يصدّق على نفسه بأنه 'معفى داخل الولاية' لا يُطلب منه عموماً القيام بأي مما يلي؟","options":["تقديم شهادة فاحص طبي معتمَد من DOT","اجتياز اختبار المعرفة العامة","الاحتفاظ بتصريح CLP قبل الاختبار","تقديم إثبات الهوية والإقامة"],"explanation":"السائقون المعفَون (مثل بعض موظفي الحكومة، أو مكافحة الحرائق، أو نقل من المنزل إلى المدرسة) غير مطالَبين بتقديم شهادة فاحص طبي، وإن كان أرباب العمل قد يشترطون مع ذلك إجراء فحص. المصدر: التصديق الذاتي لـ CDL لدى Nevada DMV (dmv.nv.gov/cdlcertify.htm)."},"94":{"q":"قبل أن يتسنى إصدار تصريح CLP في نيفادا، أي شرط يجب أن يستوفيه المتقدّم أولاً؟","options":["اجتياز جميع اختبارات المعرفة المطلوبة لفئة الرخصة والتظهيرات","إتمام اختبار المهارات على الطريق","الاحتفاظ بالتصريح لمدة 14 days","اجتياز اختبار التحكم الأساسي بالمركبة"],"explanation":"للحصول على تصريح CLP، يجب على المتقدّم اجتياز جميع اختبارات المعرفة المطلوبة لفئة الرخصة والتظهيرات؛ أما اختبارات المهارات فتأتي لاحقاً. المصدر: صفحة تصاريح المتعلّم التجاري لدى Nevada DMV (dmv.nv.gov/clp.htm)."},"95":{"q":"في أي عمر ينطبق قيد رخصة CDL للمركبات المركّبة في نيفادا على التركيبات التي يتجاوز طولها 70 قدماً (70 feet)؟","options":["يجب أن يكون عمر السائقين 25 عاماً على الأقل","يجب أن يكون عمر السائقين 18 عاماً على الأقل","يجب أن يكون عمر السائقين 21 عاماً على الأقل","لا يوجد قيد عمري مرتبط بالطول"],"explanation":"تشترط نيفادا حدّاً أدنى للعمر يبلغ 25 لتشغيل تركيبات مركبات يتجاوز طولها 70 feet. المصدر: صفحة تصاريح المتعلّم التجاري لدى Nevada DMV (dmv.nv.gov/clp.htm)."},"96":{"q":"إذا سمح حامل رخصة CDL غير معفى في نيفادا بانتهاء تصديقه الطبي دون وجود شهادة فحص طبي إلكترونية (MEC) جديدة في الملف، ما النتيجة المرجّحة؟","options":["يُخفَّض تصنيف رخصة CDL إلى وضع غير تجاري حتى يتم استلام شهادة فحص طبي (MEC) صالحة","تُلغى رخصة CDL نهائياً دون أي سبيل للاستعادة","لا يحدث شيء حتى موعد التجديد بعد 8 years","يُعاد تصنيف السائق تلقائياً بوصفه معفى"],"explanation":"دون وجود شهادة فحص طبي (MEC) سارية في الملف، تخفّض نيفادا تلقائياً تصنيف رخصة CDL إلى وضع غير تجاري حتى يتم استلام شهادة فحص طبي إلكترونية صالحة. المصدر: بيان صحفي لـ Nevada DMV رقم 25013 (dmv.nv.gov)."},"97":{"q":"أي عبارة تعكس على نحو أفضل كيف ينبغي للمتقدّم أن يتعامل مع رسوم طلب CDL في نيفادا؟","options":["تحدّد DMV الرسوم وقد تتغيّر، لذا ينبغي للمتقدّمين التأكد من المبالغ الحالية لدى DMV قبل التقدّم","تحدَّد الرسوم بشكل دائم بموجب القانون الفيدرالي ولا تتغيّر أبداً","اختبار وترخيص CDL مجاني دائماً في نيفادا","تُدفع الرسوم مباشرةً إلى السجل الوطني لدى FMCSA"],"explanation":"تُدار الرسوم المتعلقة بـ CDL في نيفادا من قِبل DMV وهي عرضة للتغيير؛ وينبغي للمتقدّمين التحقق من المبالغ الحالية مباشرةً لدى DMV بدلاً من الاعتماد على رقم ثابت. المصدر: صفحات CDL لدى Nevada DMV (dmv.nv.gov/cdl.htm)."}}};
